def build_planning_matchs_reel():
    """BRIQUE 1
    Construit le planning des matchs de saison sur un calendrier réel.

    - 4 matchs par semaine : mardi 20h, mercredi 20h, vendredi 21h, dimanche 19h (GMT+1).
    - Départ à SAISON_START_DATETIME_STR.
    - Publie/retourne une liste de dicts :
        [{"journee": 1, "datetime": <datetime>}, ...]
    - Ne modifie pas le reste de la logique : on garde len(historique_matchs)
      et total_matchs_saison comme aujourd'hui.
    """
    try:
        import datetime as _dt
    except Exception:
        globals()['planning_matchs_reel'] = []
        return []

    try:
        nb = int(globals().get('total_matchs_saison', 22) or 0)
    except Exception:
        nb = 22
    if nb <= 0:
        globals()['planning_matchs_reel'] = []
        return []

        # Parse la date de départ configurable
    txt = str(globals().get('SAISON_START_DATETIME_STR', SAISON_START_DATETIME_STR) or SAISON_START_DATETIME_STR)
    start = None
    for fmt in ("%Y-%m-%d %H:%M", "%Y/%m/%d %H:%M"):
        try:
            start = _dt.datetime.strptime(txt, fmt)
            break
        except Exception:
            start = None

    # Fallback : si la date n'est pas parseable, on calcule automatiquement
    # le prochain créneau mardi/mercredi/vendredi/dimanche suivant "maintenant".
    if start is None:
        try:
            now = _dt.datetime.now()

            # weekday Python : lundi=0, mardi=1, ..., dimanche=6
            CRENEAUX = (
                (1, 20, 0),  # mardi 20h
                (2, 20, 0),  # mercredi 20h
                (4, 21, 0),  # vendredi 21h
                (6, 19, 0),  # dimanche 19h
            )

            candidats = []
            for wd, hh, mm in CRENEAUX:
                # décalage en jours jusqu'à ce weekday
                delta_j = (wd - now.weekday()) % 7
                candidat = now + _dt.timedelta(days=delta_j)
                candidat = candidat.replace(hour=hh, minute=mm, second=0, microsecond=0)

                # si on est déjà après ce créneau aujourd'hui, on prend la semaine suivante
                if candidat <= now:
                    candidat = candidat + _dt.timedelta(days=7)

                candidats.append(candidat)

            if candidats:
                start = min(candidats)
            else:
                # garde-fou : on retombe sur "aujourd'hui 19h" comme avant
                start = now.replace(hour=19, minute=0, second=0, microsecond=0)
        except Exception:
            globals()['planning_matchs_reel'] = []
            return []


    planning = []
    current = start

    # mardi 20h → mercredi 20h → vendredi 21h → dimanche 19h → mardi 20h (semaine suivante) → ...
    # Encodée comme des deltas (jours, heures) appliqués en boucle.
    pattern_deltas = (
        (1, 0),   # +1 jour (mardi → mercredi, même heure)
        (2, 1),   # +2 jours, +1h (mercredi 20h → vendredi 21h)
        (2, -2),  # +2 jours, -2h (vendredi 21h → dimanche 19h)
        (2, 1),   # +2 jours, +1h (dimanche 19h → mardi 20h suivant)
    )
    pi = 0

    for j in range(1, nb + 1):
        planning.append({
            "journee": j,
            "datetime": current,
        })
        if j < nb:
            try:
                d_days, d_hours = pattern_deltas[pi]
                current = current + _dt.timedelta(days=d_days, hours=d_hours)
            except Exception:
                break
            pi = (pi + 1) % len(pattern_deltas)

    globals()['planning_matchs_reel'] = planning
    return planning



def get_planning_matchs_reel():
    """Renvoie le planning temps réel des matchs de saison.

    Reconstruit si nécessaire (ex : changement de total_matchs_saison ou première utilisation).
    Ne lance aucun match et ne touche pas à historique_matchs.
    """
    plan = globals().get('planning_matchs_reel', None)
    try:
        nb_attendu = int(globals().get('total_matchs_saison', 22) or 22)
    except Exception:
        nb_attendu = 22

    if not isinstance(plan, list) or len(plan) != nb_attendu:
        plan = build_planning_matchs_reel()
    return plan or []


def _now_local():
    """Petite helper isolée pour récupérer l'heure locale.

    Isolée ici pour faciliter d'éventuels tests / surcharges plus tard.
    """
    try:
        import datetime as _dt
        return _dt.datetime.now()
    except Exception:
        return None


def get_match_real_time_state(journee, now=None):
    """BRIQUE 2
    Pour une journée donnée (1..N), calcule un petit état temps réel :

    - etat : "AVANT"   → trop tôt (hors fenêtre)
             "FENETRE" → fenêtre ouverte autour de l'horaire réel
             "APRES"    → match considéré comme passé
    - datetime       : horaire théorique du match
    - delta_minutes  : (now - datetime) en minutes (peut être négatif)
    - fenetre_start / fenetre_end : bornes de la fenêtre.

    ⚠️ Cette fonction ne déclenche rien : elle décrit juste la situation.
    """
    try:
        j = int(journee)
    except Exception:
        return {"etat": "INCONNU"}

    if j <= 0:
        return {"etat": "INCONNU", "journee": j}

    plan = get_planning_matchs_reel()
    if not plan or j > len(plan):
        return {"etat": "INCONNU", "journee": j}

    dt = plan[j - 1].get("datetime", None)
    if now is None:
        now = _now_local()
    if dt is None or now is None:
        return {"etat": "INCONNU", "journee": j}

    try:
        import datetime as _dt
        before_min = int(globals().get('MATCHS_FENETRE_BEFORE_MIN', MATCHS_FENETRE_BEFORE_MIN))
        duree_min  = int(globals().get('MATCHS_DUREE_REEL_MIN', MATCHS_DUREE_REEL_MIN))

        fen_start = dt - _dt.timedelta(minutes=before_min)
        fen_end   = dt + _dt.timedelta(minutes=duree_min)
        delta     = now - dt
        delta_min = int(delta.total_seconds() // 60)
    except Exception:
        return {"etat": "INCONNU", "journee": j}

    if now < fen_start:
        etat = "AVANT"
    elif fen_start <= now <= fen_end:
        etat = "FENETRE"
    else:
        etat = "APRES"

    return {
        "etat": etat,
        "journee": j,
        "datetime": dt,
        "delta_minutes": delta_min,
        "fenetre_start": fen_start,
        "fenetre_end": fen_end,
    }


def get_etat_match_prochain_temps_reel():
    """Helper pratique pour l'UI :

    - Utilise journee_courante si défini (>0),
      sinon déduit la prochaine journée depuis le nombre de matchs de saison joués.
    - Renvoie le même dict que get_match_real_time_state().
    """
    try:
        j = int(globals().get('journee_courante', 0) or 0)
    except Exception:
        j = 0

    if j <= 0:
        # Fallback : prochaine journée = matchs de saison déjà joués + 1
        try:
            h = globals().get('historique_matchs', []) or []
            # On ne compte que les matchs "saison" structurés (home/away), comme _nb_matchs_saison_joues()
            from collections.abc import Iterable as _Iterable
            if isinstance(h, list):
                total = 0
                for m in h:
                    if not isinstance(m, dict):
                        continue
                    if not any(k in m for k in ('domicile', 'home', 'exterieur', 'away', 'equipe_a', 'equipe_b')):
                        continue
                    total += 1
                j = total + 1
            else:
                j = 1
        except Exception:
            j = 1

    return get_match_real_time_state(j)

