# --- [BRIQUE 3] Helper lecture seule pour le bouton MATCH en temps réel ---
def can_lancer_match_temps_reel():
    """
    Renvoie True si le prochain match de SAISON est dans la fenêtre temps réel
    (état 'FENETRE' renvoyé par get_etat_match_prochain_temps_reel()).
    False si on est 'AVANT', 'APRES' ou si la saison est terminée.
    N'écrit jamais dans l'état global.
    """
    # 1) Saison déjà terminée → pas de match à lancer
    try:
        total = int(globals().get('total_matchs_saison', 22))
        _matchs_saison = [
            m for m in globals().get('historique_matchs', [])
            if isinstance(m, dict) and not (m.get("type") == "tournoi" or "frais_inscription" in m)
        ]
        if len(_matchs_saison) >= total:
            return False
    except Exception:
        # en cas de problème de lecture, on ne bloque pas
        pass

    # 2) Lecture de l'état temps réel (lecture seule)
    try:
        info = get_etat_match_prochain_temps_reel()
    except Exception:
        # fail-safe : si la Brique 1+2 plante, on ne casse pas le jeu
        return True

    etat_tr = str(info.get("etat", "")).upper()
    return etat_tr == "FENETRE"


def _draw_compte_a_rebours_match(surface=None):
    """
    Compte à rebours temps réel jusqu'au prochain match de SAISON.

    - AVANT la fenêtre :
        Ligne 1 : "Prochain match dans"
        Ligne 2 : "JJ jours : HH heures : MM minutes : SS secondes"
    - Pendant la FENETRE :
        Ligne 1 : "Match disponible maintenant !"
        (pas de 2ᵉ ligne)
    - Rien si match passé ou saison terminée.

    Lecture seule (n'écrit pas dans l'état global).
    """
    try:
        import pygame
        import datetime as _dt
    except Exception:
        return

    if surface is None:
        surface = globals().get("FENETRE")
    if surface is None:
        return

    # Infos temps réel du prochain match
    try:
        info = get_etat_match_prochain_temps_reel()
    except Exception:
        return

    etat = str(info.get("etat", "")).upper()
    dt   = info.get("datetime")
    if not dt:
        return

    now = _now_local() or _dt.datetime.now()

    ligne1 = None
    ligne2 = None

    if etat == "AVANT":
        delta = dt - now
        total = int(delta.total_seconds())
        if total < 0:
            total = 0

        jours   = total // 86400
        reste   = total % 86400
        heures  = reste // 3600
        reste   = reste % 3600
        minutes = reste // 60
        secondes = reste % 60

        ligne1 = "Prochain match dans"
        ligne2 = f"{jours:02d}:{heures:02d}:{minutes:02d}:{secondes:02d}"
    elif etat == "FENETRE":
        ligne1 = "Match disponible maintenant !"
        ligne2 = None
    else:
        # APRES / saison terminée → on n'affiche rien
        return

    if not ligne1:
        return

    # Polices un peu plus grandes
    font1 = (globals().get('POLICE_TITRE')
             or globals().get('POLICE_GRANDE')
             or globals().get('FONT')
             or None)
    font2 = (globals().get('POLICE_GRANDE')
             or globals().get('FONT')
             or font1)

    if not font1:
        return

    try:
        couleur = ORANGE_FONCE
    except NameError:
        try:
            couleur = ORANGE
        except NameError:
            couleur = (200, 100, 0)

    try:
        surf1 = font1.render(ligne1, True, couleur)
    except Exception:
        return

    surf2 = None
    if ligne2 and font2:
        try:
            surf2 = font2.render(ligne2, True, couleur)
        except Exception:
            surf2 = None

    L = int(globals().get("LARGEUR", surface.get_width()))
    H = int(globals().get("HAUTEUR", surface.get_height()))

    line_gap = 12
    h1 = surf1.get_height()
    h2 = surf2.get_height() if surf2 else 0

    total_h = h1 + (line_gap + h2 if surf2 else 0)

    y_start = H // 2 - total_h // 2

    # Ligne 1 centrée
    x1 = L // 2 - surf1.get_width() // 2
    y1 = y_start
    surface.blit(surf1, (x1, y1))

    # Ligne 2 juste en dessous, centrée aussi
    if surf2:
        x2 = L // 2 - surf2.get_width() // 2
        y2 = y1 + h1 + line_gap
        surface.blit(surf2, (x2, y2))


