import os

def load_image_or_placeholder(rel_path, size=(220, 140), bg=(230, 230, 230), border=(120,120,120), label=None):
    """
    Tente de charger une image par chemin relatif au script.
    En cas d’échec, retourne une Surface placeholder grisée avec un cadre et un label.
    """
    try:
        base_dir = os.path.dirname(__file__)
    except NameError:
        base_dir = os.getcwd()
    abs_path = os.path.join(base_dir, rel_path)

    try:
        img = pygame.image.load(abs_path)
        # PNG avec alpha → convert_alpha, sinon convert
        try:
            return img.convert_alpha()
        except Exception:
            return img.convert()
    except Exception:
        w, h = size
        surf = pygame.Surface((w, h), pygame.SRCALPHA)
        surf.fill(bg)
        pygame.draw.rect(surf, border, surf.get_rect(), 2)
        text = (label or os.path.basename(rel_path) or "image").split("/")[-1]
        f = pygame.font.SysFont("comicsansms", 16, bold=True)
        txt = f.render(text, True, (80,80,80))
        surf.blit(txt, txt.get_rect(center=surf.get_rect().center))
        return surf


