def enregistrer_message_popup_once(key, subject, texte_long):
    """
    Ajoute en boîte de réception un message issu d'un popup (Object + corps),
    mais UNE SEULE FOIS par `key`.
    - key: identifiant unique (ex: "popup_capacite_limitee")
    - subject: la ligne "Object:    ...", telle qu'affichée par le popup
    - texte_long: corps du popup (multi-lignes)
    """
    try:
        deja = globals().get('_messages_popup_deja_enregistres')
        if not isinstance(deja, set):
            deja = set()

        # si déjà enregistré, on ne fait rien
        if key in deja:
            return

        sujet = (subject or "").strip()
        corps = (texte_long or "").strip()
        if sujet and corps:
            msg = sujet + "\n" + corps
        else:
            msg = sujet or corps
        if not msg:
            return

        boite = globals().get('messages_recus')
        if not isinstance(boite, list):
            boite = []
        if msg not in boite:
            boite.append(msg)
            globals()['messages_recus'] = boite

        deja.add(key)
        globals()['_messages_popup_deja_enregistres'] = deja
    except Exception:
        pass



