if 'stade_prochain_palier' not in globals():
    def stade_prochain_palier():
        # trouve le prochain (ng, ns) existant dans capacite_stade_niveaux
        ng = int(globals().get('niveau_global_jeu',1))
        ns = int(globals().get('niveau_stade',1))
        caps = globals().get('capacite_stade_niveaux', {})
        # même niveau_global d'abord
        niveaux_ns = sorted(caps.get(ng, {}).keys())
        suivants = [x for x in niveaux_ns if x > ns]
        if suivants:
            return (ng, suivants[0])
        # sinon, passe au prochain niveau_global si dispo
        niveaux_ng = sorted(caps.keys())
        suivants_ng = [g for g in niveaux_ng if g > ng]
        if not suivants_ng:
            return None
        g2 = suivants_ng[0]
        ns2 = min(caps.get(g2, {}).keys()) if caps.get(g2) else None
        return (g2, ns2) if ns2 else None

if 'stade_cout_pour' not in globals():
    def stade_cout_pour(ng2, ns2):
        # d'abord table fine (cout_niveau_stade), sinon table par global (cout_evolution_stade)
        fine = globals().get('cout_niveau_stade', {})
        val = fine.get((ng2, ns2))
        if val: return int(val)
        coarse = globals().get('cout_evolution_stade', {}).get(ng2, {})
        return int(coarse.get(ns2, 0))

