def _load_sound_safe(filename, vol=0.3):
    # chemin principal
    path = os.path.join(SFX_DIR, filename)
    if not os.path.exists(path):
        # fallback si tu exécutes depuis un autre cwd
        alt = os.path.join(os.getcwd(), "sfx", filename)
        if os.path.exists(alt):
            path = alt
        else:
            print(f"[SFX] Introuvable: {path}")
            return None
    try:
        snd = pygame.mixer.Sound(path)
        snd.set_volume(vol)
        return snd
    except Exception as e:
        print(f"[SFX] Échec chargement {path}: {e}")
        return None

