def get_coach_factor(club_level=None):
    """
    Renvoie un coefficient d'impact du coach en fonction du niveau du club.
    LV 1–2 : 2.0
    LV 3–4 : 1.5
    LV 5+  : 1.0
    """
    try:
        if club_level is None:
            club_level = int(globals().get('CLUB_LEVEL', 1))
        else:
            club_level = int(club_level)
    except Exception:
        club_level = 1

    if club_level <= 2:
        return 2.0
    elif club_level <= 4:
        return 1.5
    else:
        return 1.0


