# === PSEUDOS COMMUNAUTÉ (intégration désactivée par défaut) ==================
import os, json, random, re

# Toggle global : laisser False pour garder le comportement actuel
COMMUNITY_NAMES_ENABLED = False

# Cache mémoire des pseudos communautaires disponibles (dédupliqués)
COMMUNITY_PSEUDOS = []

def _normalize_pseudo(s: str) -> str:
    s = (s or "").strip()
    # borne la longueur, supprime les espaces multiples
    s = re.sub(r"\s+", " ", s)
    return s[:32]

def _is_valid_pseudo(s: str) -> bool:
    # soft check: lettres/chiffres/espace/._-'/éèàç… ; ajustable si besoin
    return bool(re.match(r"^[\w .'\-éèàùêâîôçÉÈÀÙÂÊÎÔÇ]{2,32}$", s))

def _load_community_pseudos(path="data/noms_communaute.json"):
    global COMMUNITY_PSEUDOS
    COMMUNITY_PSEUDOS = []
    try:
        if not os.path.isfile(path):
            return
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        raw = []
        if isinstance(data, dict):
            # accepte {"pseudos": ["Nom1", "Nom2", ...]}
            raw = data.get("pseudos") or []
        elif isinstance(data, list):
            # accepte ["Nom1", "Nom2", ...] OU [{"pseudo":"Nom"}, {"name":"Nom"}]
            for it in data:
                if isinstance(it, str):
                    raw.append(it)
                elif isinstance(it, dict):
                    raw.append(it.get("pseudo") or it.get("name") or it.get("nom"))
        # normalise, filtre, déduplique
        clean = []
        seen = set()
        for s in raw:
            s = _normalize_pseudo(str(s))
            if not s or not _is_valid_pseudo(s):
                continue
            if s.lower() in seen:
                continue
            seen.add(s.lower())
            clean.append(s)
        random.shuffle(clean)
        COMMUNITY_PSEUDOS = clean
    except Exception:
        COMMUNITY_PSEUDOS = []

def _pop_community_pseudo():
    # renvoie un pseudo unique jusqu’à épuisement, sinon None
    if COMMUNITY_PSEUDOS:
        return COMMUNITY_PSEUDOS.pop()
    return None

def _generated_name_fallback():
    """
    Fallback gradué :
    1) Si tu ajoutes un jour PRENOMS/NOMS_FAMILLE globalement, on les utilisera.
    2) Sinon on garde le comportement actuel: Joueur_####.
    """
    PRENOMS = globals().get("PRENOMS")
    NOMS_FAMILLE = globals().get("NOMS_FAMILLE")
    if isinstance(PRENOMS, (list, tuple)) and isinstance(NOMS_FAMILLE, (list, tuple)) \
       and PRENOMS and NOMS_FAMILLE:
        return f"{random.choice(PRENOMS)} {random.choice(NOMS_FAMILLE)}"
    return f"Joueur_{random.randint(1000, 9999)}"

def generate_player_name():
    """
    Source des noms (dans l’ordre):
    1) Pseudos communauté (si COMMUNITY_NAMES_ENABLED==True et fichier non vide)
    2) Pools PRENOMS/NOMS_FAMILLE si présents dans globals()
    3) Fallback historique: Joueur_#### (actuel)
    """
    try:
        if COMMUNITY_NAMES_ENABLED and not COMMUNITY_PSEUDOS:
            _load_community_pseudos()
        if COMMUNITY_NAMES_ENABLED:
            p = _pop_community_pseudo()
            if p:
                return p
    except Exception:
        pass
    return _generated_name_fallback()
