def _draw_finance_scroll_arrows():
    if FIN_SCROLL_MAX <= 0:
        return

    # Gauche puis droite — dessin proportionnel à la taille du Rect
    for rect, direction in ((fleche_fin_gauche, -1), (fleche_fin_droite, +1)):
        # fond
        pygame.draw.rect(FENETRE, (0, 0, 0, 50), rect, border_radius=6)

        w, h = rect.size
        cx, cy = rect.center

        # chevron proportionnel (pas de constantes magiques)
        dx = max(6, w // 4)
        dy = max(6, h // 3)

        if direction < 0:  # ←
            pts = [(cx + dx, cy - dy), (cx - dx, cy), (cx + dx, cy + dy)]
        else:               # →
            pts = [(cx - dx, cy - dy), (cx + dx, cy), (cx - dx, cy + dy)]

        pygame.draw.polygon(FENETRE, BLANC, pts)





