def _trophy_bg_surface():
    mode = _trophy_layout_mode()
    if mode not in _TROPHY_BG_CACHE:
        path = _TROPHY_LAYOUTS[mode]["bg"]
        try:
            img = pygame.image.load(path).convert()
            img = pygame.transform.scale(img, (LARGEUR, HAUTEUR))
        except Exception:
            # secours : fond uni orangé si l'image n’est pas trouvée
            img = pygame.Surface((LARGEUR, HAUTEUR))
            img.fill((240, 140, 60))
        _TROPHY_BG_CACHE[mode] = img
    return _TROPHY_BG_CACHE[mode]


def _trophy_blit(surface, img, x, y, kind="medal"):
    """Blit d’un trophée avec offset + scale selon le mode (v1/v2)."""
    layout = _TROPHY_LAYOUTS[_trophy_layout_mode()]

    # 1) offsets globaux (communs aux deux versions)
    dx, dy = layout.get("offset", (0, 0))

    # 2) offsets spécifiques par type (actifs seulement si définis, i.e. en v2)
    if kind == "medal":
        kdx, kdy = layout.get("medal_offset", (0, 0))
        sc = layout.get("medal_scale", 1.0)
    else:  # "cup"
        kdx, kdy = layout.get("cup_offset", (0, 0))
        sc = layout.get("cup_scale", 1.0)

    # 3) scale si nécessaire
    if sc != 1.0:
        w, h = img.get_width(), img.get_height()
        img = pygame.transform.smoothscale(img, (int(w * sc), int(h * sc)))

    # 4) blit avec tous les offsets cumulés
    surface.blit(img, (x + dx + kdx, y + dy + kdy))


def _draw_trophy_scroll_arrows():
    # Ne rien dessiner si pas de scroll nécessaire
    if SCROLL_X_MAX <= 0:
        return

    y_mid = HAUTEUR // 2
    w, h = 42, 64  # tailles
    # positions (centrées verticalement)
    global fleche_scroll_gauche, fleche_scroll_droite
    fleche_scroll_gauche = pygame.Rect(24, y_mid - h//2, w, h)
    fleche_scroll_droite = pygame.Rect(LARGEUR - 24 - w, y_mid - h//2, w, h)

    # fond semi-transparent discret
    s = pygame.Surface((w, h), pygame.SRCALPHA)
    s.fill((0, 0, 0, 70))
    FENETRE.blit(s, fleche_scroll_gauche.topleft)
    FENETRE.blit(s, fleche_scroll_droite.topleft)

    # chevrons
    pygame.draw.polygon(FENETRE, (255,255,255), [
        (fleche_scroll_gauche.centerx + 8, fleche_scroll_gauche.centery - 16),
        (fleche_scroll_gauche.centerx - 8, fleche_scroll_gauche.centery),
        (fleche_scroll_gauche.centerx + 8, fleche_scroll_gauche.centery + 16),
    ], 0)
    pygame.draw.polygon(FENETRE, (255,255,255), [
        (fleche_scroll_droite.centerx - 8, fleche_scroll_droite.centery - 16),
        (fleche_scroll_droite.centerx + 8, fleche_scroll_droite.centery),
        (fleche_scroll_droite.centerx - 8, fleche_scroll_droite.centery + 16),
    ], 0)




