def _get_sponsor_bonus_table_for_level():
    """
    Retourne la table de bonus sponsor pour le niveau courant, sinon la table par défaut.
    Accepte un niveau entier (ex. 3) ou décimal (ex. 3.0). Fallback robuste.
    """
    lvl = globals().get('niveau_global_jeu', 1)
    try:
        lvl_key = f"{float(lvl):.1f}"   # ex. 3  -> "3.0",  2.5 -> "2.5"
    except Exception:
        lvl_key = str(lvl)
    levels = globals().get('SPONSOR_BONUS_PO_LEVELS', {}) or {}
    return levels.get(lvl_key, globals().get('SPONSOR_BONUS_PO', {}))



def stade_niveau_est_debloque(ng, ns):
    """Retourne True si la fiche (ng,ns) doit apparaître comme débloquée (cliquable)."""
    cur_ng = int(globals().get('niveau_global_jeu', 1))
    cur_ns = int(globals().get('niveau_stade', 1))

    # Règle de base : tout ce qui est <= au niveau courant est débloqué
    if (ng, ns) <= (cur_ng, cur_ns):
        return True

    # 🆕 Règle demandée : dès que 2-1 est atteint, 2-2 et 2-3 sont aussi débloqués
    if (cur_ng, cur_ns) >= (2, 1) and ng == 2:
        return True

    return False





