def _caf_fill_missing(dct: dict) -> dict:
    """Complète le dict 'dct' avec les clés du template manquantes (valeur 0)."""
    for _k in _CAF_STOCK_TEMPLATE.keys():
        dct.setdefault(_k, 0)
    return dct

def _caf_keys_union_refresh():
    """(Optionnel) Si tu ajoutes un produit globalement, refresh le template et normalise."""
    global _CAF_STOCK_TEMPLATE, stock_cafe_par_niveau, stock_cafe
    # recalcul template
    _all = set()
    for _v in CAFETERIA_STOCK_PAR_NIVEAU.values():
        _all.update(_v.keys())
    if not _all:
        _all = {"Hotdog", "Soda"}
    _CAF_STOCK_TEMPLATE = {k: 0 for k in sorted(_all)}
    # normalise les niveaux en mémoire
    if 'stock_cafe_par_niveau' in globals():
        for _k, _v in stock_cafe_par_niveau.items():
            stock_cafe_par_niveau[_k] = _caf_fill_missing(dict(_v))
    if 'stock_cafe' in globals():
        stock_cafe = _caf_fill_missing(dict(stock_cafe))


# 2) Copie profonde des stocks par niveau (source de vérité)
if 'stock_cafe_par_niveau' not in globals():
    stock_cafe_par_niveau = {k: _caf_fill_missing(dict(v)) for k, v in CAFETERIA_STOCK_PAR_NIVEAU.items()}

# 3) Stock courant = copie du stock du niveau actuel (ou gabarit si manquant), normalisé
if 'stock_cafe' not in globals():
    ng0 = int(globals().get('niveau_global_jeu', 1))
    ns0 = int(globals().get('niveau_stade', 1))
    base = stock_cafe_par_niveau.get((ng0, ns0), dict(_CAF_STOCK_TEMPLATE))
    stock_cafe = _caf_fill_missing(dict(base))

# 4) Binder simple à appeler quand le niveau change
def _stock_cafe_bind():
    ng = int(globals().get('niveau_global_jeu', 1))
    ns = int(globals().get('niveau_stade', 1))
    base = stock_cafe_par_niveau.get((ng, ns), dict(_CAF_STOCK_TEMPLATE))
    globals()['stock_cafe'] = _caf_fill_missing(dict(base))

def caf_set_stock(level_tuple, **stocks):
    """
    Modifie les stocks d'un niveau donné.
    Exemple:
        caf_set_stock((2,2), Cafe=1300, Bonbons=950)
    """
    lvl = tuple(level_tuple)
    base = dict(stock_cafe_par_niveau.get(lvl, dict(_CAF_STOCK_TEMPLATE)))
    for k, v in stocks.items():
        base[k] = int(v)
    stock_cafe_par_niveau[lvl] = _caf_fill_missing(base)

    # si on est actuellement à ce niveau, refléter immédiatement
    ng = int(globals().get('niveau_global_jeu', 1))
    ns = int(globals().get('niveau_stade', 1))
    if (ng, ns) == lvl:
        globals()['stock_cafe'] = _caf_fill_missing(dict(base))




