def _coach_cost_tokens(label: str, tier: int) -> int:
    """Renvoie le coût en tokens depuis le catalogue ; fallback sur barème si non trouvé."""
    try:
        for (lib, t, cost, _lvl_req) in COACHS_CATALOG:
            if str(lib) == str(label) and int(t) == int(tier):
                return int(cost)
    except Exception:
        pass
    flat = globals().get('COACH_TOKENS_COST_FLAT', None)
    if flat is not None:
        return int(flat)
    cmap = globals().get('COACH_TOKENS_COST_BY_TIER', {1:0, 2:18, 3:35})
    return int(cmap.get(int(tier), 80))

