def make_parking_option(label, *, places_pct, cout_euros, duree_matchs, stade_palier):
    """
    label: str (ex. 'Parking 2-1')
    places_pct: pourcentage (int) de places par rapport à la capacité du stade-pivot
    cout_euros: coût en €
    duree_matchs: durée des travaux en nombre de matchs
    stade_palier: tuple (niveau_global, niveau_stade) pivot de capacité (ex. (2,1), (2,2), (2,3))
    """
    return {
        "label": label,
        "places_pct": int(places_pct),
        "cout": int(cout_euros),
        "duree": int(duree_matchs),
        "pivot": tuple(stade_palier),
    }

