# Multiplicateurs globaux optionnels (ex. événement “double tokens”)
TOKENS_GLOBAL_MULT = 1.0   # passe à 2.0 pour double tokens
# ============================================================================

def _token_level_key():
    lvl = globals().get('niveau_global_jeu', 1)
    try:
        return f"{float(lvl):.1f}"
    except Exception:
        return str(lvl)

def _get_tokens_table_for_level():
    levels = globals().get('TOKENS_RULES_LEVELS', {}) or {}
    return levels.get(_token_level_key(), globals().get('TOKENS_RULES_DEFAULT', {}))


def grant_tokens(event: str, outcome: str, reason_prefix: str = "") -> int:
    """
    event: "PO" | "TOURNOI" | autre clé du config
    outcome: "finaliste" | "champion" | "vainqueur" | etc.
    Retourne le nombre de tokens crédités.
    """
    table = _get_tokens_table_for_level()
    base = int(((table.get(event, {}) or {}).get(outcome, 0)) or 0)
    mult = float(globals().get('TOKENS_GLOBAL_MULT', 1.0) or 1.0)
    amount = int(round(base * mult))
    if amount > 0:
        rp = f"{reason_prefix}:{event}:{outcome}" if reason_prefix else f"{event}:{outcome}"
        try:
            add_tokens(amount, rp)
        except Exception:
            pass
    return amount


# === TOKENS (MVP) ============================================================
# Solde + journal minimal
if 'TOKENS' not in globals(): TOKENS = 0
if 'TOKENS_LOG' not in globals(): TOKENS_LOG = []  # [(+/-int, "raison")]

def add_tokens(amount: int, reason: str = ""):
    """Crédite des tokens (>=0) et journalise."""
    try:
        amt = int(amount)
    except Exception:
        return
    if amt <= 0: 
        return
    globals()['TOKENS'] = int(globals().get('TOKENS', 0)) + amt
    globals()['TOKENS_LOG'].append((+amt, reason))

def spend_tokens(amount: int, reason: str = "") -> bool:
    """Débite si solde suffisant. Retourne True si ok."""
    try:
        amt = int(amount)
    except Exception:
        return False
    cur = int(globals().get('TOKENS', 0))
    if amt <= 0 or cur < amt:
        return False
    globals()['TOKENS'] = cur - amt
    globals()['TOKENS_LOG'].append((-amt, reason))
    return True

# === POPUP CONFIRMATION TOKENS (générique) ==============================
def token_popup_open(amount:int, reason:str, action_key:str, payload:dict=None):
    """[LEGACY WRAPPER] redirige vers l’API moderne."""
    token_popup_open_modern(
        amount,
        title="Confirmer le paiement",
        subtitle=str(reason or ""),
        on_ok=str(action_key or ""),
        payload=dict(payload or {})
    )
    try:
        # redirige vers l’API moderne (celle définie plus bas)
        _modern = globals().get('token_popup_open')  # pointe vers la dernière déf. (moderne)
        # Si ce wrapper est le dernier à être défini, on cherche la moderne par un autre nom :
        if _modern is token_popup_open:
            _modern = globals().get('token_popup_open_modern', None)
        if callable(_modern):
            _modern(
                amount,
                title="Confirmer le paiement",           # ancien 'reason' va en sous-titre
                subtitle=str(reason or ""),
                on_ok=str(action_key or ""),
                payload=dict(payload or {})
            )
            return
    except Exception:
        pass

    # Fallback (au pire, on pose les champs "modernes")
    globals()['TOK_POPUP_ACTIVE'] = True
    globals()['TOK_POPUP_AMOUNT'] = int(amount or 0)
    globals()['TOK_POPUP_TITLE']  = "Confirmer le paiement"
    globals()['TOK_POPUP_SUB']    = str(reason or "")
    globals()['TOK_POPUP_ON_OK']  = str(action_key or "")
    globals()['TOK_POPUP_DATA']   = dict(payload or {})


