def token_popup_draw_legacy(surface):
    """Popup LEGACY (Evolution Stade / Parking) — rendu d'avant Missions.
    - N'impacte pas Missions (le popup Missions utilise draw_token_reminder_popup).
    - Utilise uniquement les variables legacy posées par token_popup_open/token_popup_close :
        TOK_POPUP_ACTIVE, TOK_POPUP_AMOUNT, TOK_POPUP_TITLE, TOK_POPUP_SUB,
        TOK_POPUP_ON_OK, TOK_POPUP_DATA
      et publie des hitboxes legacy :
        TOK_POPUP_BTN_OK, TOK_POPUP_BTN_NO
    """
    import pygame

    # Afficher uniquement si le legacy est armé
    if not bool(globals().get('TOK_POPUP_ACTIVE', False)):
        return

    # Couleurs/Fonts avec fallback aux globaux existants
    NOIR  = globals().get('NOIR',  (30, 30, 30))
    BLANC = globals().get('BLANC', (245, 245, 245))
    GRIS  = globals().get('GRIS',  (120, 120, 120))
    ORANGE = globals().get('ORANGE', (245,170,70))

    FONT     = (globals().get('POLICE_MOYENNE') or pygame.font.SysFont("arial", 18))
    FONT_B   = (globals().get('POLICE_MOYENNE_BOLD') or pygame.font.SysFont("arial", 18, bold=True))
    FONT_S   = (globals().get('POLICE_PETITE') or pygame.font.SysFont("arial", 16))

    LARGEUR = int(globals().get('LARGEUR', surface.get_width()))
    HAUTEUR = int(globals().get('HAUTEUR', surface.get_height()))

    # Données legacy
    amount  = int(globals().get('TOK_POPUP_AMOUNT', 0) or 0)
    title   = str(globals().get('TOK_POPUP_TITLE',  "Confirmer le paiement") or "Confirmer le paiement")
    sub     = str(globals().get('TOK_POPUP_SUB',    "") or "")
    # on_ok / payload sont stockés mais cliqués ailleurs (handler événements)
    # on publie seulement les rects OK/NO ici
    # on_ok = str(globals().get('TOK_POPUP_ON_OK', "") or "")
    # data  = dict(globals().get('TOK_POPUP_DATA', {}) or {})

    # Dimensions popup
    W, H = 620, 260
    rect = pygame.Rect(0, 0, W, H)
    rect.center = (LARGEUR // 2, HAUTEUR // 2)

    # Ombre
    shadow = pygame.Surface((W, H), pygame.SRCALPHA)
    pygame.draw.rect(shadow, (0, 0, 0, 90), shadow.get_rect(), border_radius=16)
    surface.blit(shadow, (rect.x + 8, rect.y + 10))

    # Fond
    back = pygame.Surface((W, H), pygame.SRCALPHA)
    back.fill((255, 255, 255, 238))
    pygame.draw.rect(back, NOIR, back.get_rect(), 2, border_radius=16)
    surface.blit(back, rect.topleft)

    # Titre
    t = FONT_B.render(title, True, NOIR)
    surface.blit(t, (rect.x + 20, rect.y + 16))

    # Sous-titre (si présent)
    if sub.strip():
        s = FONT.render(sub, True, GRIS)
        surface.blit(s, (rect.x + 20, rect.y + 16 + t.get_height() + 6))

    # Ligne centrale : icône token + "X tokens"
    try:
        tok = (globals().get('img_token') or globals().get('token_img') or globals().get('icon_token'))
    except Exception:
        tok = None
    num = FONT_B.render(f"{amount}", True, NOIR)
    tail = FONT.render("tokens", True, NOIR)

    # mise en page centrée
    tok_w = tok.get_width() if tok else 0
    tok_h = tok.get_height() if tok else 0
    target_h = num.get_height()
    if tok and tok_h:
        scale_w = int(tok_w * target_h / tok_h)
        tok_s = pygame.transform.smoothscale(tok, (scale_w, target_h))
    else:
        tok_s = None
        scale_w = 0

    total_w = num.get_width() + (6 if tok_s else 0) + scale_w + (8 if tok_s else 0) + tail.get_width()
    cx = rect.centerx - total_w // 2
    cy = rect.y + 110

    surface.blit(num, (cx, cy))
    x = cx + num.get_width()
    if tok_s:
        surface.blit(tok_s, (x + 6, cy))
        x += 6 + scale_w
    surface.blit(tail, (x + (8 if tok_s else 0), cy + (num.get_height() - tail.get_height()) // 2))

    # Boutons (Annuler à gauche, Payer à droite)
    btn_h = 44
    btn_w = 180
    gap   = 16
    yb    = rect.bottom - 24 - btn_h

    btn_no = pygame.Rect(rect.x + 20,           yb, btn_w, btn_h)
    btn_ok = pygame.Rect(rect.right - 20 - btn_w, yb, btn_w, btn_h)

    # Annuler
    pygame.draw.rect(surface, (235,235,235), btn_no, border_radius=10)
    pygame.draw.rect(surface, NOIR, btn_no, 2, border_radius=10)
    no_lbl = FONT_S.render("Annuler", True, NOIR)
    surface.blit(no_lbl, (btn_no.centerx - no_lbl.get_width() // 2,
                          btn_no.centery - no_lbl.get_height() // 2))

    # Payer (style accent + bord)
    pygame.draw.rect(surface, ORANGE, btn_ok, border_radius=10)
    pygame.draw.rect(surface, NOIR,   btn_ok, 2, border_radius=10)
    ok_lbl = FONT_S.render("Payer", True, NOIR)
    surface.blit(ok_lbl, (btn_ok.centerx - ok_lbl.get_width() // 2,
                          btn_ok.centery - ok_lbl.get_height() // 2))

    # Croix fermeture (haut droit)
    btn_close = pygame.Rect(0, 0, 24, 24)
    btn_close.center = (rect.right - 14, rect.y + 14)
    pygame.draw.circle(surface, (220, 70, 70), btn_close.center, 12)
    pygame.draw.circle(surface, (120, 35, 35), btn_close.center, 12, 2)
    pygame.draw.line(surface, BLANC,
                     (btn_close.centerx - 5, btn_close.centery - 5),
                     (btn_close.centerx + 5, btn_close.centery + 5), 2)
    pygame.draw.line(surface, BLANC,
                     (btn_close.centerx + 5, btn_close.centery - 5),
                     (btn_close.centerx - 5, btn_close.centery + 5), 2)

    # Publier les hitboxes legacy (utilisées par tes handlers Evolution Stade / Parking)
    globals()['TOK_POPUP_BTN_OK'] = btn_ok
    globals()['TOK_POPUP_BTN_NO'] = btn_no
    globals()['TOK_BTN_OK']       = btn_ok      # alias au besoin
    globals()['TOK_BTN_NO']       = btn_no
    globals()['TOK_BTN_CLOSE']    = btn_close   # tu peux l’utiliser pour fermer


    # --- [LEGACY ALIASES pour handlers existants] ---
    try:
        # suppose que tu as des variables locales btn_ok / btn_no / btn_close
        globals()['TOK_POPUP_OK_RECT']     = globals()['TOK_POPUP_BTN_OK']   = btn_ok
        globals()['TOK_POPUP_CANCEL_RECT'] = globals()['TOK_POPUP_BTN_NO']   = btn_no
        globals()['TOK_POPUP_CLOSE_RECT']  = globals()['TOK_POPUP_BTN_CLOSE'] = btn_close
    except Exception:
        pass



