def get_match_xp(resultat: str, club_level: int = None) -> int:
    """Renvoie le nombre de points d'XP club à attribuer après un match.

    Version actuelle : barème fixe (identique à l'existant)
    - Victoire   : 30 XP
    - Match Nul  : 10 XP
    - Défaite    : 4 XP

    Le paramètre club_level est prévu pour de futures évolutions
    (ajuster les gains en fonction du niveau du club).
    """
    try:
        res = str(resultat or "")
    except Exception:
        res = ""

    # Barème actuel strictement identique à l'ancien comportement
    if res == "Victoire":
        base = 30
    elif res == "Match Nul":
        base = 10
    else:
        # Par défaut on considère le cas "défaite"
        base = 4

    # On garde club_level dans la signature pour l'avenir,
    # mais il n'influence pas encore le calcul.
    try:
        if club_level is None:
            club_level = int(globals().get("CLUB_LEVEL", 1))
        else:
            club_level = int(club_level)
    except Exception:
        club_level = 1

    return int(base)


def _apply_xp(delta:int, reason:str=""):
    try:
        dv = int(delta)
    except Exception:
        return
    if dv <= 0: 
        return

    # 1) ajoute l'XP
    globals()['CLUB_XP'] = int(globals().get('CLUB_XP',0)) + dv
    globals().setdefault('CLUB_XP_LOG', []).append((dv, reason))
    globals()['CLUB_XP_SAISON'] = int(globals().get('CLUB_XP_SAISON',0)) + dv

    # 2) level-up tant que le seuil est franchi
    lvl = int(globals().get('CLUB_LEVEL', 1))
    xp  = int(globals().get('CLUB_XP', 0))
    thr = globals().get('LEVEL_THRESHOLDS', [0, 350, 800, 1350, 2000, 2750, 3600])

    while lvl < len(thr) and xp >= thr[lvl]:
        lvl += 1
        globals()['CLUB_LEVEL'] = lvl
        # (optionnel) récompense level-up :
        tok = int(globals().get('LEVELUP_TOKENS', {}).get(lvl, 0))
        if tok > 0:
            add_tokens(tok, f"LEVEL:{lvl}")
    

def _complete_mission_immediately(mid: str):
    import pygame
    prog = globals().get('MISSIONS_PROGRESS', {"done": set(), "in_progress": set(), "selected": None})
    prog["done"].add(mid)
    prog["in_progress"].discard(mid)
    if prog.get("selected") == mid:
        prog["selected"] = None
    globals()['MISSIONS_PROGRESS'] = prog

    missions = globals().get('MISSIONS_POOL', globals().get('MISSIONS_ROADMAP', []))
    m = next((mm for mm in missions if mm.get('id') == mid), None) or {}
    rw = (m.get("reward") or {})
    eur_reward    = int(m.get("reward_eur")    or rw.get("eur")    or 0)
    tokens_reward = int(m.get("reward_tokens") or rw.get("tokens") or 0)
    if eur_reward:
        globals()['tresorerie'] = int(globals().get('tresorerie', 0)) + eur_reward
    if tokens_reward:
        globals()['TOKENS'] = int(globals().get('TOKENS', 0)) + tokens_reward
    # toast avec icône
    label  = m.get("label") or m.get("titre") or mid
    suffix = f"  +{tokens_reward} [TOK]" if tokens_reward > 0 else ""
    globals()['ui_flash_msg']   = f"Mission réussie : {label}{suffix}"

    # Option : appliquer aussi le tuning club (XP/LV) pour cette mission
    try:
        missions_apply_tuning(m)
    except Exception:
        pass



def coach_pick_best8(joueurs:list, tier:int=1):
    """
    Retourne les 8 meilleurs joueurs selon des critères paramétrés par le palier de coach.
    Clés attendues dans chaque joueur: 'note', 'forme', 'fatigue', 'poste' (fallbacks si absents).
    """
    # — Applique la config du palier —
    cfg = (globals().get('COACH_BEHAVIOR') or {}).get(int(tier or 0), {
        'w_note': 1.0, 'w_forme': 1.0, 'fatigue_k': 0.20, 'pos_bias': 0.0, 'rnd': 0.15
    })
    w_note    = float(cfg.get('w_note', 1.0))
    w_forme   = float(cfg.get('w_forme', 1.0))
    fatigue_k = float(cfg.get('fatigue_k', 0.20))
    pos_bias  = float(cfg.get('pos_bias', 0.0))
    rnd_amp   = float(cfg.get('rnd', 0.0))

    # poids de base modulés par le coach
    a = 0.5 * w_note   # poids de la note intrinsèque
    b = 0.5 * w_forme  # poids de la forme actuelle

    pool = []
    for j in joueurs:
        note    = float(j.get("note", 50))
        forme   = float(j.get("forme", 50))
        fatigue = float(j.get("fatigue", 0))
        poste   = str(j.get("poste", j.get("position", "")) or "")

        # score brut
        score = note * a + forme * b

        # pénalité de fatigue (0..100 -> 0..1)
        score -= (fatigue / 100.0) * fatigue_k

        # petit biais si un poste est renseigné (affinable)
        if poste:
            score += pos_bias * 0.05

        # bruit aléatoire (moins avec un coach meilleur)
        if rnd_amp > 0:
            import random
            score += random.uniform(-rnd_amp, rnd_amp)

        pool.append((score, j))

    pool.sort(key=lambda x: x[0], reverse=True)
    return [j for _, j in pool[:8]]



def draw_staff_portrait(surface, role, anchor_rect, *, size=96):
    """
    Affiche un portrait rond (avatar si dispo, sinon icône du rôle).
    - role: "coach" | "kine" | "prepa" | ...
    - anchor_rect: zone du bandeau ; le portrait sera centré verticalement à gauche.
    """
    import pygame
    # 1) charger (ou récupérer) l'image
    key_avatar = f"avatar_{role}"
    key_icon   = f"icon_{role}"
    img = globals().get(key_avatar) or globals().get(key_icon)

    # 2) fallback discret si rien
    if not img:
        return None

    # 3) scale carré
    img = pygame.transform.smoothscale(img, (size, size))

    # 4) masque rond + bord
    surf = pygame.Surface((size, size), pygame.SRCALPHA)
    pygame.draw.circle(surf, (255,255,255), (size//2, size//2), size//2)
    surf.blit(img, (0,0), special_flags=pygame.BLEND_RGBA_MIN)  # simple “masque”
    pygame.draw.circle(surf, (25,25,25), (size//2, size//2), size//2, 2)

    # 5) position: à gauche du bandeau, centré verticalement
    x = anchor_rect.x - size - 12   # marge 12px avant le texte/bandeau
    y = anchor_rect.centery - size//2
    surface.blit(surf, (x, y))
    return pygame.Rect(x, y, size, size)




