# ==== AVATARS DYNAMIQUES (recolorisation par masques) ====
import os, hashlib, pygame

AVATAR_LAYER_CACHE = {}
AVATAR_SURF_CACHE  = {}

def _load_layer(name, set_name=None):
    """
    Charge un calque. Si set_name est fourni (ex 'M_base', 'F_base', 'F_bun'),
    on cherche d'abord dans layers/{set_name}/, sinon fallback vers layers/.
    """
    import os, pygame
    key = f"layer::{set_name or 'base'}::{name}"
    if key in AVATAR_LAYER_CACHE:
        return AVATAR_LAYER_CACHE[key]

    base_dir = os.path.join("images", "avatars", "layers")
    tried = []

    if set_name:
        p = os.path.join(base_dir, set_name, f"{name}.png")
        tried.append(p)
        if os.path.isfile(p):
            surf = pygame.image.load(p).convert_alpha()
            AVATAR_LAYER_CACHE[key] = surf
            return surf

    # fallback: répertoire racine
    p = os.path.join(base_dir, f"{name}.png")
    tried.append(p)
    try:
        surf = pygame.image.load(p).convert_alpha()
    except Exception:
        # calque vide si manquant
        surf = pygame.Surface((256,256), pygame.SRCALPHA)

    AVATAR_LAYER_CACHE[key] = surf
    return surf

def _tint_from_mask(mask_surf, color):
    """
    Colorise un masque en ignorant son RGB (qui peut être gris/noir) :
    on force d'abord le RGB à blanc là où il y a de l'alpha, puis on multiplie par la couleur.
    L'alpha per-pixel du masque est conservé.
    """
    s = mask_surf.copy()
    s.fill((255, 255, 255, 0), special_flags=pygame.BLEND_RGBA_ADD)
    s.fill((*color, 0), special_flags=pygame.BLEND_RGBA_MULT)
    return s


