def _get_preset_index_for_player(joueur):
    """Retourne l'index de preset à utiliser pour ce joueur."""
    # Si override global actif, on l'utilise pour tout le monde
    if GLOBAL_AVATAR_PRESET_OVERRIDE is not None:
        return int(GLOBAL_AVATAR_PRESET_OVERRIDE) % max(1, len(PRESET_AVATARS))

    # Sinon, on choisit de façon déterministe (stable) en fonction de l'id/nom
    seed = str(joueur.get('id') or joueur.get('nom') or joueur.get('name') or repr(joueur))
    h = _hash_int(seed)
    return h % max(1, len(PRESET_AVATARS))

def _spec_from_preset(joueur):
    idx = int(joueur.get("avatar_preset_index", 0)) % max(1, len(PRESET_AVATARS))
    p = PRESET_AVATARS[idx]
    return {
        "skin": p.get("skin", (224,172,105)),
        "hair": p.get("hair", (24,24,24)),
        "jersey": p.get("jersey", (245,130,30)),
        "accessory": p.get("accessory", (0,0,0)),
        "acc_on": bool(p.get("acc_on", False)),
        "stubble_alpha": int(p.get("stubble_alpha", 0)),
        "layer_set": p.get("layer_set"),
        "gender": p.get("gender", "U"),
    }



def _hash_int(s):
    return int(hashlib.sha1(s.encode("utf-8")).hexdigest(), 16)


def get_avatar_surface(joueur, size=64):
    """
    Compose un avatar en recolorant les masques + outline.
    Cache par clé (id + size) pour perf.
    """
    
    ak_for_key = joueur.get("avatar_key") or ""
    key = f"{joueur.get('id') or joueur.get('nom') or joueur.get('name') or ak_for_key or id(joueur)}_{size}"
    if key in AVATAR_SURF_CACHE:
        return AVATAR_SURF_CACHE[key]

    ak = joueur.get("avatar_key")
    if ak:
        import os
        if not os.path.isfile(ak):
            # Placeholder ROUGE pour bien voir l’erreur (au lieu de retomber sur les masques)
            ph = pygame.Surface((size, size), pygame.SRCALPHA)
            ph.fill((255, 0, 0, 255))
            AVATAR_SURF_CACHE[key] = ph
            return ph

        try:
            surf = pygame.image.load(ak).convert_alpha()
        except Exception as e:
            print(f"[AVATAR][FAILLOAD] Échec de chargement {ak} -> {e}")
            # Placeholder ROUGE: pareil, surtout pas de fallback silencieux
            ph = pygame.Surface((size, size), pygame.SRCALPHA)
            ph.fill((255, 0, 0, 255))
            AVATAR_SURF_CACHE[key] = ph
            return ph

        # OK: on a un PNG → on l’utilise, point.
        if surf.get_size() != (size, size):
            surf = pygame.transform.smoothscale(surf, (size, size))
        AVATAR_SURF_CACHE[key] = surf
        return surf

    # --- sentinelle temporaire : si pas de PNG, affiche un placeholder magenta ---
    if not ak:
        # => on a PAS d'avatar PNG assigné à ce joueur (étrange si c'est un des 12)
        print(f"[AVATAR][WARN] Pas d'avatar_key pour {joueur.get('nom') or joueur.get('name')}")
        ph = pygame.Surface((size, size), pygame.SRCALPHA)
        ph.fill((255, 0, 255, 255))  # magenta visible
        AVATAR_SURF_CACHE[key] = ph
        return ph
    
    # --- Overrides PNG multi-tailles : charge un PNG si dispo, sinon fabrication par calques ---
    OVERRIDE = {
        28:  "images/avatars/avatar_popup_28.png",
        64:  "images/avatars/avatar_popup_64.png",
        72:  "images/avatars/avatar_popup_72.png",
        84:  "images/avatars/avatar_select_84.png",
        96:  "images/avatars/avatar_select_96.png",
        128: "images/avatars/avatar_card_128.png",
        # 26:  "images/avatars/avatar_list_26.png",
        # 32:  "images/avatars/avatar_list_32.png",
    }

    global _AVATAR_OVERRIDE_SURF_CACHE
    if '_AVATAR_OVERRIDE_SURF_CACHE' not in globals():
        _AVATAR_OVERRIDE_SURF_CACHE = {}

    def _load_override(sz):
        path = OVERRIDE.get(sz)
        if not path:
            return None
        key_ovr = f"ovr::{sz}::{path}"
        surf = _AVATAR_OVERRIDE_SURF_CACHE.get(key_ovr)
        if surf is None:
            try:
                surf = pygame.image.load(path).convert_alpha()
                _AVATAR_OVERRIDE_SURF_CACHE[key_ovr] = surf
            except Exception:
                return None
        return surf

    # 1) exact match
    surf = _load_override(size)
    if surf:
        if surf.get_size() != (size, size):
            surf = pygame.transform.smoothscale(surf, (size, size))
        AVATAR_SURF_CACHE[key] = surf
        return surf

    # 2) plus proche dispo (lissé)
    if OVERRIDE:
        nearest = min(OVERRIDE.keys(), key=lambda s: abs(s - size))
        surf = _load_override(nearest)
        if surf:
            if surf.get_size() != (size, size):
                surf = pygame.transform.smoothscale(surf, (size, size))
            AVATAR_SURF_CACHE[key] = surf
            return surf

    spec = _spec_from_preset(joueur)
    layer_set = spec.get("layer_set")  # peut être None -> fallback racine

    outline = _load_layer("outline",   layer_set)
    skin_m  = _load_layer("skin_mask", layer_set)
    hair_m  = _load_layer("hair_mask", layer_set)
    jersey_m= _load_layer("jersey_mask",layer_set)
    acc_m   = _load_layer("accessory_mask", layer_set)

    # Compose 256x256 puis on scale
    base = pygame.Surface(outline.get_size(), pygame.SRCALPHA)
    # ordre: peau -> cheveux -> maillot -> accessoire -> outline au-dessus
    base.blit(_tint_from_mask(skin_m,   spec["skin"]), (0,0))
    base.blit(_tint_from_mask(hair_m,   spec["hair"]), (0,0))
    base.blit(_tint_from_mask(jersey_m, spec["jersey"]), (0,0))
    if spec["acc_on"]:
        base.blit(_tint_from_mask(acc_m, spec["accessory"]), (0,0))

    base.blit(outline, (0,0))

    # --- Barbe de 3 jours (stubble) si demandé par le preset ---
    stubble_a = int(spec.get("stubble_alpha", 0) or 0)
    if stubble_a > 0:
        # On réutilise skin_mask comme base: un bruit doux limité au bas du visage
        _noise = pygame.Surface(base.get_size(), pygame.SRCALPHA)
        import random
        px = pygame.PixelArray(_noise)
        w, h = base.get_size()
        for y in range(int(h*0.55), int(h*0.80)):  # zone du bas du visage (bouche/menton/cou)
            for x in range(int(w*0.30), int(w*0.70)):
                if random.random() < 0.10:
                    px[x, y] = (20 << 24) | (20 << 16) | (20 << 8) | 255  # gris très foncé
        del px
        _noise.set_alpha(min(255, stubble_a))
        # masque par la peau pour rester dans la zone visage
        base.blit(_noise, (0,0), special_flags=pygame.BLEND_RGBA_MULT)


    if size != base.get_width():
        base = pygame.transform.smoothscale(base, (size, size))

    AVATAR_SURF_CACHE[key] = base
    return base



# ==== Avatar API simple & scalable ===========================================
import os, pygame

_AVATAR_MEMO = {}  # cache RAM: {(player_id, size): Surface}

AVATAR_SIZES = {
    "popup": 64,
    "select": 96,
    "list": 32,
    "card": 128,
}

def _player_id(joueur):
    return str(joueur.get('id') or joueur.get('nom') or joueur.get('name') or repr(joueur))

def _player_avatar_path(pid, size):
    root = os.path.join("images", "avatars", "players", pid)
    return root, os.path.join(root, f"{size}.png")

def _ensure_dir(p):
    d = os.path.dirname(p)
    if not os.path.isdir(d):
        os.makedirs(d, exist_ok=True)

def _load_or_build_avatar_png(pid, size):
    """1) cherche {size}.png ; 2) sinon resize master.png ; 3) sinon None."""
    root, p_size = _player_avatar_path(pid, size)

    # 1) PNG exact ?
    if os.path.isfile(p_size):
        try:
            return pygame.image.load(p_size).convert_alpha()
        except Exception:
            pass

    # 2) master.png -> resize -> save -> return
    p_master = os.path.join(root, "master.png")
    if os.path.isfile(p_master):
        try:
            surf = pygame.image.load(p_master).convert_alpha()
            if surf.get_size() != (size, size):
                surf = pygame.transform.smoothscale(surf, (size, size))
            _ensure_dir(p_size)
            try:
                pygame.image.save(surf, p_size)  # persiste pour les prochains lancements
            except Exception:
                pass
            return surf
        except Exception:
            return None

    # 3) rien trouvé
    return None

def avatar_for(joueur, context="select"):
    """Retourne l'avatar du joueur pour un contexte ('popup','select','list','card')."""
    size = AVATAR_SIZES.get(context, 64)
    pid  = _player_id(joueur)
    key  = (pid, size)

    # Cache RAM
    if key in _AVATAR_MEMO:
        return _AVATAR_MEMO[key]

    # 1) PNGs par joueur (size ou master->resize)
    surf = _load_or_build_avatar_png(pid, size)
    if surf:
        _AVATAR_MEMO[key] = surf
        return surf

    # 2) fallback : fabrique historique (masques/presets + tes overrides multi-tailles)
    surf = get_avatar_surface(joueur, size)
    _AVATAR_MEMO[key] = surf
    return surf

import os, pygame

def ensure_persistent_avatar(joueur):
    """
    Garantit qu'un joueur a un avatar figé:
    - si master.png existe déjà => ne rien faire (avatar déjà figé)
    - sinon: fabrique un 512x512 depuis les masques et l'enregistre comme master.png
    """
    pid = str(joueur.get('id') or joueur.get('nom') or joueur.get('name') or repr(joueur))
    root = os.path.join("images", "avatars", "players", pid)
    p_master = os.path.join(root, "master.png")

    if os.path.isfile(p_master):
        return  # déjà figé

    # fabrique un visuel net "maître" (512) depuis ta pipeline actuelle
    surf = get_avatar_surface(joueur, 512)

    # crée le dossier si besoin et sauvegarde
    os.makedirs(root, exist_ok=True)
    try:
        pygame.image.save(surf, p_master)
    except Exception as e:
        # si écriture échoue, on laisse la pipeline dynamique (non figé)
        print("WARN: save master avatar failed for", pid, e)


# --- Cache de redimensionnement (path,size) -> Surface ---
_AVA_RESIZE_CACHE = {}

def load_avatar_scaled(path, size):
    """Charge un master PNG, smoothscale à size×size, avec cache."""
    key = (path, size)
    surf = _AVA_RESIZE_CACHE.get(key)
    if surf:
        return surf
    import pygame, os
    try:
        src = pygame.image.load(path).convert_alpha()
        if src.get_size() != (size, size):
            src = pygame.transform.smoothscale(src, (size, size))
        _AVA_RESIZE_CACHE[key] = src
        return src
    except Exception:
        return None


