# === TOKEN ICON (global, utilisé partout où on affiche des tokens) ===
TOKEN_IMG_PATH = "/mnt/data/A_2D_digital_illustration_features_a_gold_coin_wit.png"

TOKEN_IMG_PATHS = ["images/token.png", "/mnt/data/A_2D_digital_illustration_features_a_gold_coin_wit.png"]

def load_token_icon_any(size=24):
    import pygame
    # a) essaie une liste de chemins
    for p in TOKEN_IMG_PATHS:
        try:
            img = pygame.image.load(p).convert_alpha()
            w, h = img.get_size()
            sc = size / max(w, h)
            return pygame.transform.smoothscale(img, (int(w*sc), int(h*sc)))
        except Exception:
            pass
    # b) fallback: rescale le token_img chargé plus haut si dispo
    base = globals().get("token_img")
    if base:
        w, h = base.get_size()
        sc = size / max(w, h)
        return pygame.transform.smoothscale(base, (int(w*sc), int(h*sc)))
    return None

TOKEN_ICON_20 = load_token_icon_any(20)
TOKEN_ICON_24 = load_token_icon_any(24)
TOKEN_ICON_28 = load_token_icon_any(28)

TOKEN_ICON = TOKEN_ICON_24


def draw_tokens(surface, x, y, amount, font, align="left", pad=6):
    """
    Dessine l'icône de token + le nombre.
    Retourne le rect total utile (pour clics).
    """
    col = (255, 255, 255)
    icon = _get_token_icon()
    if icon:
        icon_rect = icon.get_rect(topleft=(x, y))
        surface.blit(icon, icon_rect)
        txt = font.render(str(int(amount)), True, col)
        txt_rect = txt.get_rect()
        txt_rect.midleft = (icon_rect.right + pad, icon_rect.centery)
        surface.blit(txt, txt_rect)
        total = icon_rect.union(txt_rect)
    else:
        # fallback emoji si aucune icône
        txt = font.render(f"🪙 {int(amount)}", True, col)
        total = txt.get_rect(topleft=(x, y))
        surface.blit(txt, total)

    if align == "right":
        dx = x - total.right
        total.move_ip(dx, 0)
    return total



