# =============== CARTE TOKEN STANDARD ===============
def draw_token_card(surface, rect, amount, title="Débloquer", subtitle=None,
                    theme="green", font_title=None, font_sub=None,
                    token_font=None, corner=12, key=None, enabled=True):
    """
    Dessine une petite carte d'achat (token + montant) dans 'rect'.
    Retourne le rect dessiné. Publie un rect cliquable dans TOKEN_CARD_RECTS[key].
    - key: identifiant unique (ex: "unlock_kine", "coach_Danton", etc.)
    - enabled=False => style grisé + clic ignoré
    """
    import pygame
    NOIR  = globals().get("NOIR", (0,0,0))
    BLANC = globals().get("BLANC", (255,255,255))
    GRISF = (245,245,245)

    # thèmes simples
    if theme == "green":
        col_bg, col_bd = (40,150,60), (20,80,35)
    elif theme == "blue":
        col_bg, col_bd = (0,70,150), (0,0,0)
    else:  # grey
        col_bg, col_bd = (180,180,180), (110,110,110)

    if not enabled:
        col_bg = (170,170,170); col_bd = (120,120,120)

    # Fond
    pygame.draw.rect(surface, GRISF, rect, border_radius=corner)
    pygame.draw.rect(surface, NOIR,  rect, 2, border_radius=corner)

    # Titre
    f1 = font_title or globals().get("POLICE_MOYENNE") or pygame.font.SysFont(None, 22, bold=True)
    title_s = f1.render(title, True, (60,20,60))
    surface.blit(title_s, (rect.x+12, rect.y+10))

    # Capsule bouton (en bas)
    bw, bh = rect.w - 24, 36
    pill = pygame.Rect(rect.x+12, rect.bottom - bh - 12, bw, bh)
    pygame.draw.rect(surface, col_bg, pill, border_radius=10)
    pygame.draw.rect(surface, col_bd, pill, 2, border_radius=10)

    # Icône token + nombre (centré dans la capsule)
    f_tok = token_font or globals().get("POLICE_MOYENNE") or pygame.font.SysFont(None, 20, bold=True)
    # centrer horizontalement
    # on dessine via draw_tokens mais on mesure d'abord le texte
    txt_tmp = f_tok.render(str(amount), True, BLANC)
    total_w = (globals().get("TOKEN_ICON_24").get_width() if globals().get("TOKEN_ICON_24") else 16) + 6 + txt_tmp.get_width()
    start_x = pill.centerx - total_w // 2
    # icône + texte
    from pygame import Surface
    draw_tokens(surface, start_x, pill.y + (pill.h - (globals().get("TOKEN_ICON_24").get_height() if globals().get("TOKEN_ICON_24") else txt_tmp.get_height()))//2,
                amount, f_tok)

    # Sous-texte optionnel
    if subtitle:
        f2 = font_sub or pygame.font.SysFont(None, 18)
        sub_s = f2.render(subtitle, True, (50,50,70))
        surface.blit(sub_s, (rect.x+12, rect.y + 10 + title_s.get_height() + 4))

    # Publier le rect cliquable
    if key:
        cards = globals().setdefault("TOKEN_CARD_RECTS", {})
        cards[key] = pill if enabled else None

    return rect


def _get_token_icon():
    """Retourne une Surface icône token (ou None)."""
    return (globals().get("TOKEN_ICON")
            or globals().get("TOKEN_ICON_24")
            or globals().get("TOKEN_ICON_20")
            or globals().get("token_img"))

# Palette unique des pastilles (bg, text) — DOIT matcher draw_token_pill
TOKEN_PILL_THEMES = {
    "orange": ((240, 140, 40), (25, 25, 25)),  # Accélération
    "green":  ((80, 200, 120), (25, 25, 25)),  # Déblocage
    "blue":   ((120, 180, 255), (25, 25, 25)),
    "grey":   ((80, 80, 80),    (240, 240, 240)),
}


def draw_token_pill(surface, amount, anchor_rect, *,
                    theme="orange", font=None):
    """
    Pastille token uniforme (format Coach) : hauteur fixe, largeur mini, padding cohérent,
    texte à gauche puis icône à droite. Retourne le pygame.Rect affiché.
    """
    import pygame

    # === STYLE GLOBAL UNIQUE (identique Coach) ===
    PILL_FONT_NAME  = globals().get("TOKEN_PILL_FONT_NAME", "comicsansms")
    PILL_FONT_SIZE  = int(globals().get("TOKEN_PILL_FONT_SIZE", 18))
    PILL_FONT_BOLD  = True
    PILL_PAD_X      = int(globals().get("TOKEN_PILL_PAD_X", 10))
    PILL_PAD_Y      = int(globals().get("TOKEN_PILL_PAD_Y", 6))
    PILL_GAP_ICON   = int(globals().get("TOKEN_PILL_GAP_ICON", 6))
    PILL_MIN_W      = int(globals().get("TOKEN_PILL_MIN_W", 90))
    PILL_H_FIXED    = int(globals().get("TOKEN_PILL_H_FIXED", 36))

    # Thèmes centralisés (bg, text) — même palette que Coach
    themes = {
        "orange": ((240, 140, 40), (25, 25, 25)),  # Accélération
        "green":  ((80, 200, 120), (25, 25, 25)),  # Déblocage
        "blue":   ((120, 180, 255), (25, 25, 25)),
        "grey":   ((80, 80, 80),    (240, 240, 240)),
    }
    bg_color, text_color = themes.get(theme, themes["orange"])

    # Police verrouillée
    if font is None:
        font = pygame.font.SysFont(PILL_FONT_NAME, PILL_FONT_SIZE, bold=PILL_FONT_BOLD)

    # Contenu : texte (montant) + icône (à droite)
    txt = font.render(str(int(amount)), True, text_color)

    icon = _get_token_icon()
    if icon:
        # Normalise l’icône à ~24 px de haut (sans dépasser la pastille)
        target_h = min(PILL_H_FIXED - 2*PILL_PAD_Y, 24)
        if icon.get_height() != target_h:
            scale = target_h / max(1, icon.get_height())
            icon = pygame.transform.smoothscale(
                icon,
                (max(1, int(icon.get_width() * scale)), target_h)
            )
        iw, ih = icon.get_width(), icon.get_height()
    else:
        iw, ih = 0, txt.get_height()

    tw, th = txt.get_width(), txt.get_height()

    # Dimensions internes
    w = PILL_PAD_X + tw + (PILL_GAP_ICON if icon else 0) + iw + PILL_PAD_X
    w = max(w, PILL_MIN_W)
    h = PILL_H_FIXED

    # marge égale droite/bas (réglable globalement)
    M = int(globals().get("TOKEN_PILL_MARGIN", 8))  # ← change 12 pour avancer/reculer
    pill = pygame.Rect(anchor_rect.right - w - M, anchor_rect.bottom - h - M, w, h)

    # Dessin
    pygame.draw.rect(surface, bg_color, pill, border_radius=12)
    pygame.draw.rect(surface, (0, 0, 0), pill, 2, border_radius=12)

    # Placement interne (texte → icône)
    cur_x = pill.x + PILL_PAD_X
    ty = pill.y + (pill.h - th) // 2
    surface.blit(txt, (cur_x, ty))
    cur_x += tw + (PILL_GAP_ICON if icon else 0)
    if icon:
        iy = pill.y + (pill.h - ih) // 2
        surface.blit(icon, (cur_x, iy))

    return pill






# === Helpers libellé de pastille (général) ===
def draw_pill_caption(surface, text, pill_rect, *, font=None, color=(40,40,40), pos="left", gap=6, bold=False):
    """
    Dessine un petit libellé près de la pastille tokens.
    pos="left"   -> à gauche, centré verticalement
    pos="above"  -> au-dessus, aligné à droite
    Retourne le rect du libellé.
    """
    import pygame
    base_font = font or pygame.font.SysFont("comicsansms", 18)

    # activer le gras temporairement si supporté
    prev_bold = None
    try:
        if hasattr(base_font, "get_bold"):
            prev_bold = base_font.get_bold()
        if hasattr(base_font, "set_bold"):
            base_font.set_bold(bold)
    except Exception:
        prev_bold = None

    surf = base_font.render(str(text), True, color)

    # positionnement
    if pos == "above":
        x = pill_rect.left
        y = pill_rect.top - surf.get_height() - gap
    else:  # "left"
        x = pill_rect.left - surf.get_width() - gap
        y = pill_rect.top + (pill_rect.height - surf.get_height()) // 2

    out = surface.blit(surf, (x, y))

    # restaurer l'état bold de la police
    try:
        if prev_bold is not None and hasattr(base_font, "set_bold"):
            base_font.set_bold(prev_bold)
    except Exception:
        pass

    return out


def blit_text_with_stroke(surface, font, text, pos, *,
                          fill=(0,0,0),           # noir
                          stroke=(255,140,0),     # orange
                          stroke_width=2):
    """Blitte du texte avec un contour en 'stroke' autour du 'fill'."""
    x, y = pos
    # Pré-rendu
    txt_fill = font.render(text, True, fill)
    txt_stk  = font.render(text, True, stroke)
    # Contour (anneau de pixels autour)
    w = max(1, int(stroke_width))
    for dx in range(-w, w+1):
        for dy in range(-w, w+1):
            if dx == 0 and dy == 0: 
                continue
            surface.blit(txt_stk, (x+dx, y+dy))
    # Remplissage
    surface.blit(txt_fill, (x, y))



