def _mission_unlock_cost(m: dict) -> int:
    """
    Coût de tokens affiché/consommé pour cette mission.
    Priorité : 'unlock_cost_tokens' > 'token_cost' > fallback global (TOKENS_ACCEL_MISSION ou 4).
    """
    try:
        return int(
            (m or {}).get('unlock_cost_tokens')
            or (m or {}).get('token_cost')
            or globals().get('TOKENS_ACCEL_MISSION', 4)
        )
    except Exception:
        return int(globals().get('TOKENS_ACCEL_MISSION', 4))



