def start_token_reward(amount:int):
    """Démarre l’overlay de récompense tokens (compteur animé)."""
    try:
        import pygame
        now = pygame.time.get_ticks()
    except Exception:
        now = 0
    amount = int(max(0, amount))
    if amount <= 0:
        return
    globals()['TOKEN_REWARD_ACTIVE'] = True
    globals()['TOKEN_REWARD_TARGET'] = amount
    globals()['TOKEN_REWARD_CURRENT'] = 0.0
    globals()['TOKEN_REWARD_START_MS'] = now
    globals()['TOKEN_REWARD_LAST_CHIME_STEP'] = -1
    globals()['TOKEN_REWARD_READY_TO_CLOSE'] = False

def _token_reward_play_chime(step:int, final:bool=False):
    """Ping léger à chaque palier de 5, son différent à la fin (silencieux si mixer absent)."""
    try:
        import pygame
        if not pygame.mixer.get_init():
            return
        s = None
        if final:
            s = globals().get('sfx_token_final')  # charge-le ailleurs si tu as des assets
        else:
            s = globals().get('sfx_token_ping')
        if s:
            s.play()
    except Exception:
        pass

def dessiner_overlay_tokens(surface):
    """Voile blanc semi-transparent + texte doré géant + compteur animé + hint 'Clique pour continuer…'."""
    import pygame
    if not (globals().get('TOKEN_REWARD_ACTIVE', False) or
            globals().get('TOKEN_REWARD_READY_TO_CLOSE', False)):
        return
    
    try:
        w, h = surface.get_width(), surface.get_height()
    except Exception:
        w = int(globals().get('LARGEUR', 800))
        h = int(globals().get('HAUTEUR', 600))

    # 1) Avancement
    try:
        now = pygame.time.get_ticks()
    except Exception:
        now = 0
    start = int(globals().get('TOKEN_REWARD_START_MS', now))
    elapsed_s = max(0.0, (now - start) / 1000.0)
    speed = float(globals().get('RECOMPENSE_TOKENS_PAR_SECONDE', 60))
    speed *= 0.5  # ⇦ diminue ce facteur (0.3, 0.2, …) pour ralentir davantage
    target = int(globals().get('TOKEN_REWARD_TARGET', 0))
    cur = float(globals().get('TOKEN_REWARD_CURRENT', 0.0))

    # --- nouveau : delta-time réel ---
    last = int(globals().get('TOKEN_REWARD_LAST_MS', 0))
    if last == 0:
        globals()['TOKEN_REWARD_LAST_MS'] = now
        dt = 0.0
    else:
        dt = max(0.0, (now - last) / 1000.0)
        globals()['TOKEN_REWARD_LAST_MS'] = now

    # incrémente (vitesse * secondes réelles)
    next_val = min(target, cur + speed * dt)
    globals()['TOKEN_REWARD_CURRENT'] = next_val


    # 2) (voile retiré)
    try:
        w, h = surface.get_width(), surface.get_height()
    except Exception:
        w = int(globals().get('LARGEUR', 800))
        h = int(globals().get('HAUTEUR', 600))
        

    # 3) Texte principal (doré + ombre)
    try:
        big = globals().get('POLICE_TITRE_BIG', POLICE_TITRE)
    except Exception:
        big = pygame.font.SysFont("comicsansms", int(globals().get('TOKEN_REWARD_FONT_PX', 72)), bold=True)

    # Texte sans le mot "TOKENS"
    value_txt = f"+ {int(next_val)}"
    txt_shadow = big.render(value_txt, True, (160, 120, 0))
    txt_main   = big.render(value_txt, True, (255, 215, 0))
    SCALE_TXT = float(globals().get('TOKEN_REWARD_TEXT_SCALE', 1.3))  # ex. 1.15, 1.3, 1.5…
    if SCALE_TXT > 1.001:
        new_w = max(1, int(txt_main.get_width()  * SCALE_TXT))
        new_h = max(1, int(txt_main.get_height() * SCALE_TXT))
        txt_main   = pygame.transform.smoothscale(txt_main,   (new_w, new_h))
        txt_shadow = pygame.transform.smoothscale(txt_shadow, (new_w, new_h))
    rect = txt_main.get_rect(center=(w//2, h//2 - 20))

    # --- Voile circulaire semi-transparent (paramétrable) ---
    alpha  = int(globals().get('TOKEN_OVERLAY_CIRCLE_ALPHA', 225))  # 160 conseillé (250 ≈ quasi opaque)
    radius = int(globals().get('TOKEN_OVERLAY_CIRCLE_RADIUS', max(140, int(min(w, h) * 0.20))))
    GAP = int(globals().get('TOKEN_REWARD_ICON_GAP', 12))
    cx  = rect.right + GAP // 2
    cy  = rect.centery

    ORANGE = tuple(globals().get('TOKEN_OVERLAY_CIRCLE_RGB', (255, 140, 0)))

    ring = pygame.Surface((radius * 2, radius * 2), pygame.SRCALPHA)
    pygame.draw.circle(ring, (ORANGE[0], ORANGE[1], ORANGE[2], alpha), (radius, radius), radius)
    # halo plus doux (optionnel) :
    # pygame.draw.circle(ring, (0, 0, 0, alpha // 2), (radius, radius), int(radius * 0.75))

    surface.blit(ring, (cx - radius, cy - radius))

    # blits du texte APRÈS le voile
    surface.blit(txt_shadow, rect.move(2, 3))
    surface.blit(txt_main, rect)


    # Icône tokens à droite du texte (réutilise images/token.png)
    try:
        ic = globals().get('IMG_TOKEN_ICON_BIG')
        if ic is None:
            import pygame
            ic = pygame.image.load("images/token.png").convert_alpha()
            ic = pygame.transform.smoothscale(ic, (64, 64))
            globals()['IMG_TOKEN_ICON_BIG'] = ic
    except Exception:
        ic = pygame.Surface((48, 48), pygame.SRCALPHA)
        pygame.draw.circle(ic, (255,200,80), (32,32), 32)
        pygame.draw.circle(ic, (120,90,20), (32,32), 32, 3)
        globals()['IMG_TOKEN_ICON_BIG'] = ic
        ic = globals()['IMG_TOKEN_ICON_BIG']

    # --- Animation "rotation horizontale" (coin flip) + étincelles ---
    import math, random
    now_ms = pygame.time.get_ticks()
    spin = globals().setdefault('TOKEN_SPIN', {'t_prev': 0, 'angle': 0.0, 'spark_accum': 0.0})
    dt = 0.0
    if spin['t_prev']:
        dt = max(0.0, (now_ms - spin['t_prev']) / 1000.0)
    spin['t_prev'] = now_ms

    # Vitesse de spin (~1.5 tours/seconde)
    spin['angle'] = (spin['angle'] + (3.0 * math.pi) * dt) % (2 * math.pi)

    # Échelle horizontale 0.35↔1.0 selon cos(angle) → illusion de rotation 3D
    sx = 0.35 + 0.65 * abs(math.cos(spin['angle']))
    w = max(6, int(64 * sx))
    h = 64
    ico_scaled = pygame.transform.smoothscale(ic, (w, h))

    # Position (ancrage midleft), centrée verticalement (+1 px pour compenser l'ombre du texte)
    GAP = int(globals().get('TOKEN_REWARD_ICON_GAP', 12))
    anchor = (rect.right + GAP, rect.centery + 1)
    ico_rect = ico_scaled.get_rect(midleft=anchor)
    surface.blit(ico_scaled, ico_rect)

    # --- Étincelles : petites particules dorées autour de l'icône pendant le compteur ---
    sparks = globals().setdefault('TOKEN_SPARKS', [])
    # Génération à cadence fixe (12/s)
    spin['spark_accum'] += dt
    while spin['spark_accum'] >= 1.0/12.0:
        spin['spark_accum'] -= 1.0/12.0
        # Naissance autour du centre de l'icône
        cx, cy = ico_rect.center
        ang = random.random() * 2 * math.pi
        r0  = random.uniform(6, 12)
        x0  = cx + math.cos(ang) * r0
        y0  = cy + math.sin(ang) * r0
        # Vitesse radiale légère
        v   = random.uniform(40, 80)  # px/s
        vx  = math.cos(ang) * v
        vy  = math.sin(ang) * v
        life = random.uniform(0.25, 0.45)
        sparks.append({'x': x0, 'y': y0, 'vx': vx, 'vy': vy, 'life': life, 'max': life})

    # Mise à jour + rendu
    for p in list(sparks):
        p['life'] -= dt
        if p['life'] <= 0:
            sparks.remove(p)
            continue
        # déplacement
        p['x'] += p['vx'] * dt
        p['y'] += p['vy'] * dt
        # alpha décroissant
        a = max(0, min(255, int(255 * (p['life'] / p['max']))))
        # rendu simple : halo + cœur
        pygame.draw.circle(surface, (255, 220, 80, a), (int(p['x']), int(p['y'])), 3)
        pygame.draw.circle(surface, (255, 255, 255, a), (int(p['x']), int(p['y'])), 1)

    SPIN_MAX_S = 1.5  # "quelques secondes" ; ajuste 2.5–3.0 si tu veux
    if 't0' not in spin or not spin['t0']:
        spin['t0'] = now_ms
    elapsed = (now_ms - spin['t0']) / 1000.0

    if elapsed < SPIN_MAX_S:
        # vitesse ~1.5 tours/s : 3π rad/s
        spin['angle'] = (spin['angle'] + (3.0 * math.pi) * dt) % (2 * math.pi)
    else:
        spin['angle'] = 0.0

    # Échelle horizontale (illusion 3D) — 0.35↔1.0 pendant la fenêtre, puis 1.0
    if elapsed < SPIN_MAX_S:
        sx = 0.35 + 0.65 * abs(math.cos(spin['angle']))
    else:
        sx = 1.0

    w_scaled = max(6, int(64 * sx))
    ico_scaled = pygame.transform.smoothscale(ic, (w_scaled, 64))
    anchor = (rect.right + 12, rect.centery + 1)
    ico_rect = ico_scaled.get_rect(midleft=anchor)
    surface.blit(ico_scaled, ico_rect)

    # Étincelles seulement pendant la fenêtre de spin
    if elapsed < SPIN_MAX_S:
        pass
        
    # [OVERLAY-HINT-CLICK-TO-CONTINUE]
    if globals().get('TOKEN_REWARD_READY_TO_CLOSE', False):
        try:
            try:
                w, h = surface.get_width(), surface.get_height()
            except Exception:
                w = int(globals().get('LARGEUR', 800))
                h = int(globals().get('HAUTEUR', 600))
            # Police (une fois)
            small = pygame.font.SysFont(None, int(globals().get('TOKEN_HINT_FONT_PX', 28)))

            # 1) Première apparition → on calcule et on fige
            if 'TOKEN_HINT_SURF' not in globals() or globals().get('TOKEN_HINT_SURF') is None:
                hint = small.render("Clic pour continuer…", True, (235, 235, 235))
                # Y : sous le +X et l’icône (comme avant)
                base_y = (max(rect.bottom, ico_rect.bottom) + 18) if 'ico_rect' in locals() else (rect.bottom + 18)
                # X : centre sur le cercle si dispo, sinon milieu de l’espace texte↔icône
                try:
                    cx_hint = int(cx)
                except Exception:
                    GAP = int(globals().get('TOKEN_REWARD_ICON_GAP', 12))
                    cx_hint = int(rect.right + GAP // 2)
                dst = hint.get_rect(midtop=(cx_hint, int(base_y)))
                # ➜ on fige surface + position
                globals()['TOKEN_HINT_SURF'] = hint
                globals()['TOKEN_HINT_POS']  = (dst.x, dst.y)
            else:
                # 2) Frames suivantes → on réutilise sans recalcul
                hint = globals()['TOKEN_HINT_SURF']
                pos  = globals()['TOKEN_HINT_POS']
                dst  = hint.get_rect(topleft=pos)

            # Blit unique, sans “recharge”
            surface.blit(hint, dst)
        except Exception:
            pass


    # 4) Paliers de 5 → chime
    step = int(next_val // 5)
    last = int(globals().get('TOKEN_REWARD_LAST_CHIME_STEP', -1))
    if step > last and int(next_val) < target:
        _token_reward_play_chime(step, final=False)
        globals()['TOKEN_REWARD_LAST_CHIME_STEP'] = step

    # 5) Fin : son final + hint
    if int(next_val) >= target and not globals().get('TOKEN_REWARD_READY_TO_CLOSE', False):
        _token_reward_play_chime(step, final=True)
        globals()['TOKEN_REWARD_READY_TO_CLOSE'] = True


def anchor_bottom_right(container_rect, size=None, mr=None, mb=None):
    """Retourne un Rect ancré en bas-droite du conteneur, avec marges constantes."""
    PW, PH = size or globals().get('PILL_SIZE', (120, 36))
    MR = int(globals().get('PILL_MARGIN_RIGHT', 16) if mr is None else mr)
    MB = int(globals().get('PILL_MARGIN_BOTTOM', 16) if mb is None else mb)
    return pygame.Rect(container_rect.right - MR - PW,
                       container_rect.bottom - MB - PH,
                       PW, PH)



def draw_token_reminder_popup(surface):
    """Dessine le POPUP MODERNE tokens (pastille + bouton classique)."""
    import pygame
    import textwrap

    # 0) Affiché seulement si demandé
    if not globals().get('afficher_popup_tokens', False):
        # Nettoyage doux (optionnel)
        globals()['popup_tokens_btn_unlock'] = None
        globals()['popup_tokens_btn_classic'] = None
        globals()['popup_tokens_close'] = None
        globals()['popup_btn_ok'] = None
        globals()['popup_btn_cancel'] = None
        globals()['popup_btn_close'] = None
        return

    # Dimensions & couleurs (fallbacks robustes)
    LARGEUR = int(globals().get('LARGEUR', surface.get_width()))
    HAUTEUR = int(globals().get('HAUTEUR', surface.get_height()))
    NOIR  = globals().get('NOIR',  (30,30,30))
    BLANC = globals().get('BLANC', (245,245,245))
    GRIS  = globals().get('GRIS',  (110,110,110))
    ROUGE = globals().get('ROUGE', (210,60,60))
    FONT_M = globals().get("POLICE_MOYENNE") or globals().get("FONT")
    FONT_B = globals().get("POLICE_MOYENNE_BOLD") or FONT_M
    FONT_S = globals().get("POLICE_PETITE") or FONT_M

    # Popup rect centré
    W, H = 640, 260
    rect = pygame.Rect(0, 0, W, H)
    rect.center = (LARGEUR // 2, HAUTEUR // 2)

    # Ombre + panneau
    shadow = pygame.Surface((W, H), pygame.SRCALPHA)
    pygame.draw.rect(shadow, (0, 0, 0, 90), shadow.get_rect(), border_radius=16)
    surface.blit(shadow, (rect.x + 8, rect.y + 10))

    back = pygame.Surface((W, H), pygame.SRCALPHA)
    back.fill((255, 255, 255, 235))
    pygame.draw.rect(back, NOIR, back.get_rect(), 2, border_radius=16)
    surface.blit(back, rect.topleft)

    pygame.draw.line(surface, (255, 255, 255, 140),
                     (rect.left + 10, rect.top + 10),
                     (rect.right - 10, rect.top + 10), 2)

    # Contexte (priorité aux valeurs du contexte parking)
    ctx    = globals().get('popup_tokens_ctx', {}) or {}
    title  = globals().get("popup_tokens_title", "Tu peux utiliser des tokens")
    mode   = str(globals().get("popup_tokens_mode") or "accel").lower()
    area   = str(ctx.get('area') or '').lower()

    # ➜ montant pastille = priorité contexte, sinon global
    try:
        amount = int(ctx.get('amount'))
    except Exception:
        amount = int(globals().get("popup_tokens_amount") or 0)

    # ➜ Titre spécifique Missions (déblocage immédiat)
    if area == 'missions_unlock':
        mid = str(ctx.get('mission_id') or "")
        _ms = (globals().get('MISSIONS_ROADMAP') or []) + (globals().get('MISSIONS_POOL') or [])
        try:
            num = next((i+1 for i, mm in enumerate(_ms) if str(mm.get('id')) == mid), None)
        except Exception:
            num = None
        # si trouvé → numéro, sinon on garde l'ID (au pire)
        title = f"Activer Déblocage Immédiat pour Mission {num if num is not None else mid}"
    
    # ➜ montant pastille = priorité contexte, sinon global
    try:
        amount = int(ctx.get('amount'))
    except Exception:
        amount = int(globals().get("popup_tokens_amount") or 0)


    # ➜ Harmonisation du titre selon l'AREA (priorité à 'parking')
    try:
        if area == 'parking':
            # “Parking — Capacité X”
            cap = ctx.get('cap')
            if cap is None:
                try:
                    idx  = int(ctx.get('card_index'))
                    opts = (globals().get('PARKING_CHOIX') or globals().get('PARKING_OPTIONS') or [])
                    if isinstance(opts, list) and 0 <= idx < len(opts):
                        o = opts[idx]
                        cap = (o.get('cap') or o.get('capacite') or o.get('capacity') or o.get('places'))
                except Exception:
                    cap = None
            title = (f"Parking — Capacité {cap}" if cap is not None else "Parking — Amélioration")
        elif area == 'stade_upgrade':
            cand = globals().get('stade_candidat')
            if isinstance(cand, (list, tuple)) and len(cand) >= 2:
                ng, ns = int(cand[0]), int(cand[1])
                title = f"Améliorer le stade — Niveau {ng}-{ns}"
    except Exception:
        pass


    # Titre (missions_unlock : le "titre" devient le libellé mission en FONT_B, avec ballons)
    try:
        if FONT_B:
            if area == 'missions_unlock':
                mid_ctx = str(ctx.get('mission_id') or "")
                missions_all = (globals().get('MISSIONS_ROADMAP') or []) + (globals().get('MISSIONS_POOL') or [])
                m = next((mm for mm in missions_all if str(mm.get('id')) == mid_ctx), None)
                mission_label = str((m or {}).get('titre') or (m or {}).get('label') or mid_ctx or "Mission")

                # même police/format/position que l'ancien titre, mais avec le libellé mission
                t_surf = FONT_B.render(mission_label, True, NOIR)
                title_rect = t_surf.get_rect(midtop=(rect.centerx, rect.y + 16))
                surface.blit(t_surf, title_rect)

                # Ballons gauche/droite (réutilise 'ballon_img' si dispo), sinon ronds orange
                ball_w = ball_h = 18
                ball_dx = 6
                try:
                    _ball_src = globals().get('ballon_img')
                except Exception:
                    _ball_src = None
                if _ball_src:
                    try:
                        _ball_small = pygame.transform.smoothscale(_ball_src, (ball_w, ball_h))
                    except Exception:
                        _ball_small = None
                else:
                    _ball_small = None

                # Gauche
                if _ball_small:
                    surface.blit(_ball_small, (title_rect.left - ball_dx - ball_w,
                                               title_rect.top + (title_rect.height - ball_h)//2))
                else:
                    pygame.draw.circle(surface, (255, 140, 0),
                                       (title_rect.left - ball_dx - ball_w//2, title_rect.centery), ball_w//2)
                # Droite
                if _ball_small:
                    surface.blit(_ball_small, (title_rect.right + ball_dx,
                                               title_rect.top + (title_rect.height - ball_h)//2))
                else:
                    pygame.draw.circle(surface, (255, 140, 0),
                                       (title_rect.right + ball_dx + ball_w//2, title_rect.centery), ball_w//2)

                # --- [APRÈS le ballon de droite] Ligne Récompense centrée avec icône token ---
                try:
                    rw = (m or {}).get("reward") or {}
                    tokens_reward = int((m or {}).get("reward_tokens", 0) or rw.get("tokens", 0) or 0)
                except Exception:
                    tokens_reward = 0

                _fsub = (FONT_M or FONT_S or FONT)
                reward_text = f"Récompense : {tokens_reward}"
                rew_surf = _fsub.render(reward_text, True, NOIR)

                # Icône token : même logique que le survol (token_img / icon_token)
                tok_h = rew_surf.get_height()
                tok_w = tok_h
                tok_gap = 8
                token_src = (globals().get('token_img') or
                             globals().get('icon_token') or
                             globals().get('IMG_TOKEN_ICON'))
                if token_src:
                    try:
                        token_small = pygame.transform.smoothscale(token_src, (tok_w, tok_h))
                    except Exception:
                        token_small = None
                else:
                    token_small = None

                total_w = rew_surf.get_width() + (tok_gap + tok_w if token_small else 0)
                start_x = rect.centerx - total_w // 2
                start_y = title_rect.bottom + 8

                surface.blit(rew_surf, (start_x, start_y))
                if token_small:
                    surface.blit(token_small, (start_x + rew_surf.get_width() + tok_gap, start_y))

            else:
                # 🔹 Titre standard pour Parking, Stade, etc.
                t_surf = FONT_B.render(title, True, NOIR)
                surface.blit(t_surf, t_surf.get_rect(midtop=(rect.centerx, rect.y + 16)))
    except Exception:
        pass


    # Texte descriptif
    if mode == "unlock":
        # 🔹 Déblocage immédiat Coach / Kiné : texte contextualisé
        if area == "coach_unlock":
            label = ctx.get("label") or "ce coach"
            try:
                amt = int(amount or 0)
            except Exception:
                amt = 0
            texte = (
                f"Débloque immédiatement {label}.\n"
                "Le contrat démarre dès maintenant."
            )
        elif area == "kine_unlock":
            label = ctx.get("label") or "ce kiné"
            try:
                amt = int(amount or 0)
            except Exception:
                amt = 0
            texte = (
                f"Débloque immédiatement {label}.\n"
                "Le contrat démarre dès maintenant."
            )
        else:
            # 🔹 Autres cas (missions, parking, stade…) : texte global existant
            texte = globals().get("popup_tokens_text_unlock") or ""
    else:
        texte = globals().get("popup_tokens_text_accel") or ""

    if isinstance(texte, str) and texte.strip():
        for i, line in enumerate(texte.splitlines()):
            surface.blit(FONT_M.render(line, True, NOIR), (rect.x + 18, rect.y + 56 + i*22))

    # Ligne "TOKENS disponibles" centrée
    try:
        tok_dispo = int(globals().get('TOKENS', 0))
    except Exception:
        tok_dispo = 0
    num_s  = FONT_M.render(str(tok_dispo), True, (30,30,30))
    tail_s = FONT_M.render("disponibles", True, (60,60,60))
    icon = (globals().get('img_token') or globals().get('token_img') or globals().get('icon_token'))
    icon_s, iw, ih = None, 0, 0
    if icon:
        ih = num_s.get_height()
        iw = int(icon.get_width() * ih / max(1, icon.get_height()))
        try:
            icon_s = pygame.transform.smoothscale(icon, (iw, ih))
        except Exception:
            icon_s, iw, ih = None, 0, 0
    gap_num_icon  = 6  if icon_s else 0
    gap_icon_tail = 8  if icon_s else 0
    total_w = num_s.get_width() + gap_num_icon + iw + gap_icon_tail + tail_s.get_width()
    line_h = max(num_s.get_height(), ih, tail_s.get_height())
    y_mid  = rect.centery - line_h // 2
    x_mid  = rect.centerx - total_w // 2
    surface.blit(num_s, (x_mid, y_mid + (line_h - num_s.get_height()) // 2))
    x_cursor = x_mid + num_s.get_width()
    if icon_s:
        surface.blit(icon_s, (x_cursor + gap_num_icon, y_mid + (line_h - ih) // 2))
        x_cursor += gap_num_icon + iw
    surface.blit(tail_s, (x_cursor + gap_icon_tail, y_mid + (line_h - tail_s.get_height()) // 2))

    pr = rect.inflate(-32, -48)

    # Contexte du popup (nécessaire pour le mode missions_unlock)
    ctx  = dict(globals().get('popup_tokens_ctx') or {})
    area = str(ctx.get('area') or '').strip().lower()
    mid  = str(ctx.get('mission_id') or '')

    # Regroupe les popups de déblocage immédiat (missions + staff)
    is_unlock_popup = area in ('missions_unlock', 'coach_unlock', 'kine_unlock')
    
    # ⛔️ Missions : aucun sous-titre (on garde les textes personnalisés pour coach/kine)
    if area == 'missions_unlock':
        try:
            globals()['popup_tokens_text_accel']  = ""
            globals()['popup_tokens_text_unlock'] = ""
        except Exception:
            pass

    # Bouton "Classique/Payer" : supprimé pour tous les déblocages immédiats
    if is_unlock_popup:
        btn_classic = None
    else:
        btn_classic = pygame.Rect(rect.x + 18, rect.bottom - 56, 365, 36)
        pygame.draw.rect(surface, (235,235,235), btn_classic, border_radius=8)
        pygame.draw.rect(surface, NOIR, btn_classic, 2, border_radius=8)
        classic_label = "Payer"
        surface.blit((FONT_M or FONT_S).render(classic_label, True, NOIR),
                     (btn_classic.centerx - (FONT_M or FONT_S).size(classic_label)[0]//2,
                      btn_classic.centery - (FONT_M or FONT_S).get_height()//2))


    # Pastille verte unique "Débloquer immédiatement"
    if is_unlock_popup:
        # 1) Montant exact
        if area == 'missions_unlock' and mid:
            ms = (globals().get('MISSIONS_ROADMAP') or []) + (globals().get('MISSIONS_POOL') or [])
            mm = next((x for x in ms if str(x.get('id')) == mid), None)
            try:
                amount_exact = _mission_unlock_cost(mm)
            except Exception:
                amount_exact = int((mm or {}).get('unlock_cost_tokens',
                                                  (mm or {}).get('token_cost', 0)) or 0)
        else:
            # Coach / Kiné : on prend directement le montant passé dans le contexte
            try:
                amount_exact = int(ctx.get('amount') or
                                   globals().get('popup_tokens_amount') or 0)
            except Exception:
                amount_exact = 0

        # 2) Pastille verte à droite (même layout que Missions)
        PW, PH = globals().get('PILL_SIZE', (120, 36))
        MB     = int(globals().get('PILL_MARGIN_BOTTOM', 16))
        dx     = int(globals().get('POPUP_UNLOCK_DX', 220))  # décalage horizontal vers la droite
        anchor = pygame.Rect(rect.centerx - PW//2 + dx,
                             rect.bottom - MB - PH,
                             PW, PH)
        btn_unlock = show_unlock_pill_above(surface, anchor, amount_exact,
                                            font=(FONT_S or FONT))

        # 3) Bouton "Annuler" en bas-gauche
        btn_cancel = pygame.Rect(rect.x + 18, rect.bottom - 56, 160, 36)
        pygame.draw.rect(surface, (235,235,235), btn_cancel, border_radius=8)
        pygame.draw.rect(surface, NOIR,            btn_cancel, 2,           border_radius=8)

        _label = "Annuler"
        _font  = (FONT_M or FONT_S or FONT)
        surface.blit(
            _font.render(_label, True, NOIR),
            (btn_cancel.centerx - _font.size(_label)[0]//2,
             btn_cancel.centery - _font.get_height()//2)
        )

        # 4) Publication (modern + legacy) — aucun bouton "Payer" dans ces modes
        globals()['popup_tokens_btn_classic'] = None
        globals()['popup_tokens_btn_cancel']  = btn_cancel
        globals()['popup_tokens_btn_unlock']  = btn_unlock
        globals()['popup_btn_cancel']         = btn_cancel
        globals()['popup_btn_ok']             = btn_unlock

    else:
        # Pastille standard (rendu existant, pour les autres zones)
        MR = int(globals().get('PILL_MARGIN_RIGHT', 16))
        MB = int(globals().get('PILL_MARGIN_BOTTOM', 16))
        PW, PH = globals().get('PILL_SIZE', (120, 36))
        pill_anchor = pygame.Rect(rect.right - MR - PW, rect.bottom - MB - PH, PW, PH)



    # ----- Bouton "Classique" (gauche en bas) — identique à 20251028_10h02 -----
    if area not in ('missions', 'missions_unlock'):
        ctx   = dict(globals().get('popup_tokens_ctx', {}) or {})
