# [REWARD_TOKENS_STATE]
REWARD_TOKENS = {
    "active": False,      # compteur visuel en cours ?
    "target": 0,          # objectif total de tokens à afficher
    "current": 0.0,       # progression (float pour lissage)
    "rate": float(globals().get("RECOMPENSE_TOKENS_PAR_SECONDE", 60)),  # vitesse tokens/sec
    "last_ms": 0,         # pour delta-time
    "last_chime_val": 0,  # dernier palier “chime”
}

def start_reward_tokens(count:int):
    c = max(0, int(count or 0))
    REWARD_TOKENS.update({"active": c>0, "target": c, "current": 0.0, "last_ms": 0, "last_chime_val": 0})
    globals()['MISSION_REWARD_PENDING'] = True
    globals()['HIDE_MISSION_PANEL']     = False

def update_reward_tokens(now_ms:int):
    if not REWARD_TOKENS["active"]:
        return
    if REWARD_TOKENS["last_ms"] == 0:
        REWARD_TOKENS["last_ms"] = now_ms
        return
    dt = max(0, (now_ms - REWARD_TOKENS["last_ms"]) / 1000.0)
    REWARD_TOKENS["last_ms"] = now_ms

    # Avance
    REWARD_TOKENS["current"] += REWARD_TOKENS["rate"] * dt
    cur_int = int(REWARD_TOKENS["current"])
    tgt     = int(REWARD_TOKENS["target"])

    # “Chime” à chaque palier de 5 tokens
    if cur_int // 5 > REWARD_TOKENS["last_chime_val"] // 5 and cur_int < tgt:
        try:
            # play_chime_token() -> à implémenter si tu as un mixer son
            pass
        except Exception:
            pass
    REWARD_TOKENS["last_chime_val"] = cur_int

    # Fin
    if cur_int >= tgt:
        REWARD_TOKENS["current"] = float(tgt)
        REWARD_TOKENS["active"]  = False
        try:
            # play_chime_token_final()
            pass
        except Exception:
            pass
        # Créditer réellement les tokens une fois le comptage fini
        globals()['TOKENS'] = int(globals().get('TOKENS', 0)) + tgt
        globals()['MISSION_REWARD_PENDING'] = False
        globals()['HIDE_MISSION_PANEL']     = True

def draw_reward_tokens(surface):
    """Affiche un texte centré 'TOKENS +X' pendant le comptage (sans voile)."""
    if not (REWARD_TOKENS["active"] or globals().get('MISSION_REWARD_PENDING', False)):
        return
    cur_int = int(REWARD_TOKENS["current"])
    tgt     = int(REWARD_TOKENS["target"])
    txt     = f"+{cur_int}/{tgt} TOKENS" if REWARD_TOKENS["active"] else f"+{tgt} TOKENS"
    try:
        font_big = globals().get('FONT_TITRE') or pygame.font.SysFont(None, 72)
        text_surf = font_big.render(txt, True, (212, 175, 55))  # doré
        # ombre légère
        shadow = font_big.render(txt, True, (0,0,0))
        cx = globals().get('LARGEUR', surface.get_width()) // 2
        cy = globals().get('HAUTEUR', surface.get_height()) // 2
        surface.blit(shadow, (cx - shadow.get_width()//2 + 2, cy - shadow.get_height()//2 + 2))
        surface.blit(text_surf, (cx - text_surf.get_width()//2, cy - text_surf.get_height()//2))

    except Exception:
        pass





def mark_unlocks_after(ng:int, ns:int):
    """
    Si on est (ou passe) en 1-3, on débloque la "grappe" 2-1/2-2/2-3.
    Idempotent (ré-appels sans effet).
    """
    if (ng, ns) == (1, 3):
        unlocked = globals().get('LEVELS_UNLOCKED')
        unlocked.update({(2, 1), (2, 2), (2, 3)})



def capacity_cap_active():
    """Retourne True si on doit capper les recettes à 80% (stade 1-3, mi-saison, popularité 100/100)."""
    ng = int(globals().get('niveau_global_jeu', 1))
    ns = int(globals().get('niveau_stade', 1))
    if (ng == 1 and ns == 3) and not globals().get('_msg_capacite_limitee_shown', False):
        globals()['afficher_message_capacite_limitee'] = True
        globals()['_msg_capacite_limitee_shown'] = True
    # Essaie de récupérer la notion de mi-saison ; fallback False si non définie
    mi_saison = bool(globals().get('mi_saison', False))
    pop = int(globals().get('popularite', 0))  # suppose 0..100

    return (ng, ns) == (1, 3) and mi_saison and pop >= 100




