def access_bottleneck_active():
    """
    Vrai si le plafonnement 80% doit s'appliquer ET que l'accès/parking n'est pas encore upgradé.
    - On s’appuie sur capacity_cap_active() (stade 1-3, mi-saison, pop=100).
    - On le coupe si 'PARKINGS_UPGRADED' est True (ou un équivalent d’upgrade).
    - Si tu gères des travaux: si 'travaux_parkings_en_cours' est True, on considère que le bottleneck est encore actif.
    """
    cap = capacity_cap_active()

    # Drapeaux “anticipés” (sécurisés par défaut)
    upgraded = bool(globals().get('PARKINGS_UPGRADED', False))
    travaux  = bool(globals().get('travaux_parkings_en_cours', False))

    # Si c'est déjà upgradé → plus de bandeau/plus de cap
    if upgraded:
        return False

    # S’il y a des travaux en cours, on garde le cap/bandeau jusqu’à la fin.
    return cap or (cap and travaux)




def draw_rect_alpha(dest, rect, rgba, border_color=None, border_width=0, radius=0):
    surf = pygame.Surface((rect.w, rect.h), pygame.SRCALPHA)
    if radius > 0:
        pygame.draw.rect(surf, rgba, surf.get_rect(), border_radius=radius)
    else:
        surf.fill(rgba)
    dest.blit(surf, rect.topleft)
    if border_color and border_width > 0:
        pygame.draw.rect(dest, border_color, rect, border_width, border_radius=radius)




def calculer_pondération(joueur):

    poste = joueur.get("poste", "")
    precision = joueur["precision"] * 100
    vitesse = joueur["vitesse"]
    force = joueur["force"]
    defense = joueur["defense"]
    endurance = joueur["endurance"]

    
    

    # [KINE] Lecture douce de la configuration Kiné courante
    try:
        _kine_tier = int(globals().get("KINE_TIER", 0) or 0)
    except Exception:
        _kine_tier = 0

    _kine_cfg_all = globals().get("KINE_IA_CONFIG", {})
    try:
        _kine_cfg = (_kine_cfg_all or {}).get(_kine_tier) or (_kine_cfg_all or {}).get(0) or {}
    except Exception:
        _kine_cfg = {}

    try:
        _kine_fatigue_coeff = float(_kine_cfg.get("fatigue_coeff", 1.0) or 1.0)
    except Exception:
        _kine_fatigue_coeff = 1.0

    try:
        _kine_penalty_blessure = float(_kine_cfg.get("perf_penalty_blessure", 0.30) or 0.30)
    except Exception:
        _kine_penalty_blessure = 0.30

    if poste == "Meneur":
        pondération = (
            precision * 0.30 +  # précision très importante
            vitesse * 0.30 +
            endurance * 0.20 +
            defense * 0.10 +
            force * 0.10
        )
    elif poste == "Ailier":
        pondération = (
            precision * 0.25 +
            vitesse * 0.25 +
            force * 0.20 +
            defense * 0.15 +
            endurance * 0.15
        )
    elif poste == "Pivot":
        pondération = (
            force * 0.30 +
            defense * 0.25 +
            precision * 0.15 +
            endurance * 0.15 +
            vitesse * 0.15
        )
    elif poste == "Arrière":
        pondération = (
            precision * 0.28 +
            vitesse * 0.28 +
            endurance * 0.20 +
            defense * 0.14 +
            force * 0.10
        )
    else:
        # Poste inconnu : utiliser pondération générique
        pondération = (
            precision * 0.25 +
            vitesse * 0.25 +
            force * 0.20 +
            defense * 0.15 +
            endurance * 0.15
        )

    age = joueur["age"]
    if age <= 22:
        coefficient_age = 0.9
    elif 23 <= age <= 26:
        coefficient_age = 1.0
    elif 27 <= age <= 30:
        coefficient_age = 1.05
    elif 31 <= age <= 34:
        coefficient_age = 0.95
    else:
        coefficient_age = 0.85

    pondération *= coefficient_age
        
    fatigue = joueur.get("matchs_consecutifs", 0)
    if fatigue > 3:
        base_coef = 1 - 0.05 * (fatigue - 3)
        alea = random.uniform(-0.03, 0.03) if globals().get("_mode_simulation", False) else 0.0   # 🎲 Variation aléatoire entre -3 % et +3 %
        coefficient_fatigue = max(0.75, base_coef + alea)

        # [KINE] Atténue l’impact de la fatigue selon le niveau de Kiné
        try:
            _delta_fat = coefficient_fatigue - 1.0  # négatif (malus)
            coefficient_fatigue = 1.0 + _delta_fat * _kine_fatigue_coeff
        except Exception:
            pass
        
        pondération *= coefficient_fatigue

    # 🆕 Effet du repos : un peu de repos aide, trop de repos frustre
    repos = joueur.get("repos_consecutifs", 0)
    if repos > 0:
        if repos == 1:
            coef_repos = 1.02   # +2 % (repos court)
        elif repos == 2:
            coef_repos = 1.04   # +4 %
        elif repos == 3:
            coef_repos = 1.00   # neutre
        elif repos == 4:
            coef_repos = 0.96   # -4 % (frustration)
        else:  # repos >= 5
            coef_repos = 0.92   # -8 % max
        # micro-variabilité en match uniquement
        if globals().get("_mode_simulation", False):
            coef_repos *= (1 + random.uniform(-0.01, 0.01))
        pondération *= coef_repos

    # [KINE][BLESSURE] – impact sur la performance si le joueur est diminué
    try:
        _est_blesse = bool(joueur.get("blessure")) or int(joueur.get("matches_conval", 0) or 0) > 0
    except Exception:
        _est_blesse = False

    if _est_blesse:
        pen = _kine_penalty_blessure
        # garde-fous : 0 <= pen <= 0.5
        try:
            if pen < 0.0:
                pen = 0.0
            elif pen > 0.5:
                pen = 0.5
        except Exception:
            pen = 0.30
        pondération *= (1.0 - pen)
    
    
    motivation = joueur.get("motivation", 80)
    pondération *= 1 + (motivation - 80) / 200


    return round(pondération, 2)


def _ensure_avatar_key(joueur):
    """
    Assigne une avatar_key déterministe si absente.
    1) si NAME_TO_AVATAR contient le prénom -> on l'utilise,
    2) sinon hash du nom/id vers AVATAR_POOL[0..11] → stable/déterministe.
    """
    try:
        # AVATAR_POOL 12 fichiers 01..12 déjà utilisés en noyau dur
        AVATAR_POOL = [f"images/avatars/avatar_{i:02d}.png" for i in range(1, 13)]
        name_to_avatar = globals().get("NAME_TO_AVATAR", {})  # optionnel si tu l’as ajouté côté noyau
        if "avatar_key" not in joueur or not joueur["avatar_key"]:
            key = (joueur.get("nom") or joueur.get("name") or str(joueur))
            # priorité mapping par prénom si dispo
            if isinstance(key, str) and key in name_to_avatar:
                joueur["avatar_key"] = name_to_avatar[key]
            else:
                import hashlib
                h = int(hashlib.sha1(str(key).encode("utf-8")).hexdigest(), 16)
                joueur["avatar_key"] = AVATAR_POOL[h % len(AVATAR_POOL)]
    except Exception:
        # dernière sécurité
        joueur.setdefault("avatar_key", "images/avatars/avatar_07.png")




