for joueur in joueurs:
    joueur["matchs_consecutifs"] = 0
    joueur["repos_consecutifs"] = 0

    # [PHYSIQUE] Initialisation légère de l'état physique, sans écraser un éventuel état existant
    if "fatigue" not in joueur:
        joueur["fatigue"] = 0          # 0 = frais, sera augmenté après les matchs
    if "blessure" not in joueur:
        joueur["blessure"] = False     # False = pas blessé
    if "matches_conval" not in joueur:
        joueur["matches_conval"] = 0   # 0 = pas de convalescence en cours

    joueur["pondération"] = round(calculer_pondération(joueur), 2)
    
    age = joueur["age"]
    base_motivation = 80

    if age < 23:
        base_motivation = random.randint(75, 95)  # Bon équilibre. Joueurs "sérieux", motivés, marge raisonnable.
    elif age > 30:
        base_motivation = random.randint(60, 80)  # Tous moyens, moins d’écart entre les joueurs
    else:
        base_motivation = random.randint(65, 90)


    if joueur["pondération"] > 80:
        base_motivation += 5
    elif joueur["pondération"] < 65:
        base_motivation -= 5

    joueur["motivation"] = max(50, min(100, base_motivation))
 
    salaire_int = int(70000 + joueur["pondération"] * 500)
    joueur["salaire"] = f"{min(130000, max(70000, salaire_int)):,}".replace(",", ".") + " €"

    # % de tir de base initial (si pas déjà défini)
    if "reussite_2pts" not in joueur:
        perf0 = joueur["pondération"]
        base2 = 0.48 + (perf0 - 75) / 400.0   # ≈ 38% à 58%
        base3 = 0.33 + (perf0 - 75) / 600.0   # ≈ 25% à 41%
        base2 += random.uniform(-0.02, 0.02)  # léger écart individuel
        base3 += random.uniform(-0.02, 0.02)
        joueur["reussite_2pts"] = max(0.30, min(0.65, base2))
        joueur["reussite_3pts"] = max(0.20, min(0.45, base3))



def mettre_a_jour_joueurs_equipe():
    global joueurs
    joueurs = [j for j in joueurs if j["age"] < AGE_RETRAITE] 
    
    for joueur in joueurs:
        joueur["age"] += 1

        if joueur["age"] >= 30:
            joueur["pondération"] *= 0.97
        elif joueur["age"] <= 23:
            joueur["pondération"] *= 1.03

        joueur["pondération"] = round(joueur["pondération"], 2)

        salaire = int(70000 + (joueur["pondération"] * 500))
        salaire = max(70000, min(salaire, 130000))
        # Inflation globale éventuelle
        try:
            _infl = float(globals().get('SALARY_INFLATION_FACTOR', 1.0) or 1.0)
        except Exception:
            _infl = 1.0
        salaire = int(salaire * _infl)
        joueur["salaire"] = f"{salaire:,}".replace(',', '.') + " €"
        

def mettre_a_jour_joueurs_adverses():
    for nom_equipe in list(equipes_adverses.keys()):
         equipe = equipes_adverses[nom_equipe]
         equipe = [j for j in equipe if j["age"] < AGE_RETRAITE]
         if not equipe:
             del equipes_adverses[nom_equipe]
         else:
             equipes_adverses[nom_equipe] = equipe

   
    for equipe in equipes_adverses.values():
        for joueur in equipe:
            joueur["age"] += 1  # Vieillissement

            # Régression naturelle des stats avec l'âge
            if joueur["age"] >= 28:
                joueur["vitesse"] = max(50, joueur["vitesse"] - random.randint(1, 3))
                joueur["endurance"] = max(50, joueur["endurance"] - random.randint(1, 2))
                joueur["precision"] = round(max(0.60, joueur["precision"] - random.uniform(0.01, 0.03)), 2)

            # Mise à jour de la pondération et salaire
            joueur["pondération"] = calculer_pondération(joueur)
            salaire = int(70000 + joueur["pondération"] * 500)
            salaire = max(70000, min(salaire, 130000))
            # Inflation globale éventuelle
            try:
                _infl = float(globals().get('SALARY_INFLATION_FACTOR', 1.0) or 1.0)
            except Exception:
                _infl = 1.0
            salaire = int(salaire * _infl)
            joueur["salaire"] = f"{salaire:,}".replace(",", ".") + " €"



    
