def salaire_str_vers_int(s):
    return int(s.replace(' €', '').replace('.', '').replace(' ', ''))

def int_vers_salaire_str(val):
    """Formate un salaire entier en string, en tenant compte de l'inflation globale."""
    try:
        _infl = float(globals().get('SALARY_INFLATION_FACTOR', 1.0) or 1.0)
    except Exception:
        _infl = 1.0
    try:
        _val = int(val)
    except Exception:
        return f"{val} €"
    _val = int(_val * _infl)
    return f"{_val:,}".replace(',', '.') + " €"




