def estimer_valeur_joueur(joueur):
    age = joueur["age"]
    pond = joueur["pondération"]

    if age < 23:
        facteur_age = 0.85
    elif age <= 29:
        facteur_age = 1.2
    else:
        facteur_age = 0.75

    valeur = int(pond * 10000 * facteur_age)
    return max(50000, min(valeur, 300000))  # Valeur marchande bornée



