# === Missions: helpers =======================================================
def _missions_eval_condition(cond_expr, st):
    # cond_expr e.g. "win_streak>=2"
    try:
        # Construit un petit contexte d'éval sécurisé
        counters = st["counters"]
        stadium_up = st.get("stadium_upgraded_flag", 0)
        env = {
            "win_streak": counters.get("win_streak", 0),
            "pts_85_plus": counters.get("pts_85_plus", 0),
            "youth_ok_matches": counters.get("youth_ok_matches", 0),
            "tournois_participations": counters.get("tournois_participations", 0),
            "stadium_upgraded": 1 if stadium_up else 0,
        }
        return bool(eval(cond_expr, {"__builtins__": {}}, env))
    except Exception:
        return False

# [MISSIONS][LEVEL-GATE:HELPER]
def _mission_is_eligible(m: dict, lv: int) -> bool:
    """
    True si la mission 'm' est affichable/activable au niveau 'lv'.
    Fallback safe : si min/max absents, tout est éligible.
    """
    if m.get("hidden", False):
        return False
    mn = int(m.get("min_lv", 1))
    mx = int(m.get("max_lv", 10**6))
    return mn <= int(lv) <= mx


def missions_activate_one():
    st = globals().get('missions_state', {})
    if st.get("current"):
        return
    done = set(st.get("completed", []))

    # [MISSIONS][LEVEL-GATE:ACTIVATE]
    lv = int(globals().get('niveau_global_jeu', 1))  # 👈 niveau courant du jeu
    for m in MISSIONS_POOL:
        if not _mission_is_eligible(m, lv):
            continue
        if m.get("hidden"):
            continue
        if m["id"] in done:
            continue
        st["current"] = dict(m)
        # --- Démarre un petit blink (x3) à l’activation auto aussi ---
        try:
            import pygame
            now = pygame.time.get_ticks()
        except Exception:
            now = 0
        globals()['MISSION_BLINK_ACTIVE']  = True
        globals()['MISSION_BLINK_VISIBLE'] = True
        globals()['MISSION_BLINK_COUNT']   = 0
        globals()['MISSION_BLINK_NEXT_MS'] = now + int(globals().get('MISSION_BLINK_INTERVAL_MS', 180))
        break
  


def missions_grant_rewards(m: dict):
    """Crédite les récompenses de la mission et lance l’overlay tokens (safe & idempotent)."""
    import pygame

    # [MISSIONS][SET COMPLETED FLAG — succès garanti car on est dans 'grant_rewards']
    prog = globals().setdefault('MISSIONS_PROGRESS', {"done": set(), "completed": set(),
                                                      "in_progress": set(), "selected": None})
    # id mission: on privilégie 'm', fallback sur l'état courant si besoin
    mid = str((m or {}).get("id") or
              ((globals().get('missions_state', {}) or {}).get('current', {}) or {}).get('id') or "")
    if mid:
        # ensure sets
        done = prog.get("done", set());       done = set(done or [])
        comp = prog.get("completed", set());  comp = set(comp or [])
        ip   = prog.get("in_progress", set()); ip = set(ip or [])

        # add to done + completed, remove from in_progress
        done.add(mid);  prog["done"] = done
        comp.add(mid);  prog["completed"] = comp
        if mid in ip:
            ip.discard(mid)
            prog["in_progress"] = ip

        globals()['MISSIONS_PROGRESS'] = prog

    # Supporte 2 schémas: plat (reward_tokens/reward_skin) OU dict reward={'tokens':X,'skin':...}
    rw = m.get("reward") or {}
    try:
        tokens = int(m.get("reward_tokens", 0) or rw.get("tokens", 0) or 0)
    except Exception:
        tokens = 0
    skin = m.get("reward_skin") or rw.get("skin")

    # ➕ Tokens
    if tokens > 0:
        globals()['TOKENS'] = int(globals().get('TOKENS', 0)) + tokens
        try:
            start_token_reward(tokens)  # démarre le compteur animé (overlay)
        except Exception:
            pass

    # 🎨 Skin
    if skin:
        s = set(globals().get('SKINS_UNLOCKED', set()) or [])
        s.add(skin)
        globals()['SKINS_UNLOCKED'] = s

    # 🔔 Toast (avec icône token si présent)
    label = m.get("titre") or m.get("label") or m.get("id") or "Mission"
    suffix = f"  +{tokens} [TOK]" if tokens > 0 else ""
    globals()['ui_flash_msg'] = f"Mission accomplie : {label}{suffix}"
    try:
        globals()['ui_flash_until'] = pygame.time.get_ticks() + 2500
    except Exception:
        pass

    # [MISSIONS][NO-AUTO-NEXT] — empêche l’activation automatique de la mission suivante
    globals()['MISSION_ACTIVE'] = False
    try:
        st = dict(globals().get('missions_state') or {})
        if 'current' in st:
            st.pop('current', None)   # libère la mission courante (facultatif mais propre)
            globals()['missions_state'] = st
    except Exception:
        pass

def missions_apply_tuning(m: dict):
    """
    Applique la logique tuning pour une mission côté XP club / niveau de club.

    - Ne touche PAS à la trésorerie ni aux TOKENS.
    - Utilise TUNING_ACTIONS pour ajouter de l'XP de club (CLUB_XP / CLUB_LEVEL),
      en complément de l'XP joueur déjà gérée par xp_add().
    """
    if not m:
        return

    # 1) Choix de l'action de tuning à partir de la mission
    #    - priorité à une clé explicite m["tuning_action_id"] si un jour tu veux affiner
    #    - sinon mapping simple par type de mission
    action_id = (m or {}).get("tuning_action_id")
    if not action_id:
        mtype = str((m or {}).get("type") or "")
        if mtype == "perf":
            action_id = "mission_moyenne"
        elif mtype == "meta":
            action_id = "mission_difficile"
        elif mtype == "compo":
            action_id = "mission_facile"
        else:
            # Type inconnu ou pas mappé → aucun effet tuning
            return

    action = TUNING_ACTIONS.get(action_id)
    if not action:
        return

    # 2) Récupérer le gain d'XP prévu dans le tableau de tuning
    try:
        gain_xp = int(action.get("gain_xp", 0) or 0)
    except Exception:
        gain_xp = 0

    if gain_xp <= 0:
        return

    # 3) Ajouter l'XP au club via le moteur existant (_apply_xp)
    #    → respecte LEVEL_THRESHOLDS, LEVELUP_TOKENS, etc.
    try:
        _apply_xp(gain_xp, f"mission:{action_id}")
    except Exception:
        # On ne bloque jamais le jeu pour un problème de tuning
        pass


def missions_apply_tuning(m: dict):
    """Applique le tuning pour une mission côté CLUB_XP / CLUB_LEVEL.

    - Ne touche pas à la trésorerie ni aux TOKENS (le flux Missions existant reste la référence).
    - Utilise TUNING_ACTIONS pour ne gérer que la partie XP / LV.
    """
    if not m:
        return

    # 1) Choix de l'action de tuning à partir du type de mission
    action_id = (m or {}).get("tuning_action_id")
    if not action_id:
        mtype = str((m or {}).get("type") or "")
        if mtype == "perf":
            action_id = "mission_moyenne"
        elif mtype == "meta":
            action_id = "mission_difficile"
        else:
            # Pas de mapping précis → tuning neutre (aucun effet)
            return

    # 2) Lire l'état club actuel
    try:
        budget = int(globals().get('tresorerie', 0))
    except Exception:
        budget = 0
    try:
        tokens = int(globals().get('TOKENS', 0))
    except Exception:
        tokens = 0
    try:
        xp_club = int(globals().get('CLUB_XP', 0))
    except Exception:
        xp_club = 0
    try:
        niveau_global_jeu = int(globals().get('CLUB_LEVEL', 1))
    except Exception:
        niveau_global_jeu = 1

    # 3) Appliquer le tuning uniquement sur la composante XP/LV
    try:
        _, _, xp_new, lvl_new = appliquer_tuning(
            action_id,
            budget=budget,
            tokens=tokens,
            xp_club=xp_club,
            niveau_global_jeu=niveau_global_jeu,
            appliquer_cout=False,      # ⚠️ pas de coût € ici
            appliquer_tokens=False,    # ⚠️ pas de tokens débités/crédités ici
            appliquer_xp=True,         # ✅ seulement l'XP / LV club
        )
    except Exception:
        return

    globals()['CLUB_XP'] = xp_new
    globals()['CLUB_LEVEL'] = lvl_new


def missions_check_completion():
    st = globals().get('missions_state', {})
    cur = st.get("current")
    if not cur: 
        return
    if _missions_eval_condition(cur["check"], st):
        # Clôturer
        st["completed"].append(cur["id"])
        missions_grant_rewards(cur)

        # ➜ Filet de sécurité : armer aussi l’overlay progressif si récompense tokens
        try:
            rw  = cur.get("reward") or {}
            tok = int(cur.get("reward_tokens", 0) or rw.get("tokens", 0) or 0)
            if tok > 0:
                try:
                    start_token_reward(tok)
                except Exception:
                    globals()['TOKEN_REWARD_DEFERRED'] = int(globals().get('TOKEN_REWARD_DEFERRED', 0) or 0) + tok
        except Exception:
            pass

        st["current"] = None

        # ➕ Créditer l'XP de la mission
        try:
            reward_xp = int(cur.get("reward_xp", 0) or 0)
        except Exception:
            reward_xp = 0
        xp_add(reward_xp, "Mission")

        # ➕ Tuning Missions → XP / LV club (cohérence globale du jeu)
        try:
            missions_apply_tuning(cur)
        except Exception:
            pass


        # ──► Cacher le bandeau jusqu'à la prochaine mission
        globals()['MISSION_ACTIVE'] = False
        globals()['HIDE_MISSION_PANEL'] = True
        globals()['MISSIONS_WAITING_MANUAL_UNLOCK'] = True

def missions_after_match(match_info):
    """Hook après match (score, victoire, compo jeunes…)."""
    if not globals().get('MISSION_ACTIVE', False): 
        return
    st = globals().get('missions_state', {})

    # 1) Victoires consécutives
    res = "Victoire" if (match_info.get("score_equipe",0) > match_info.get("score_adverse",0)) else \
          "Défaite" if (match_info.get("score_equipe",0) < match_info.get("score_adverse",0)) else "Égalité"
    if res == "Victoire":
        st["counters"]["win_streak"] = st["counters"].get("win_streak", 0) + 1
    else:
        st["counters"]["win_streak"] = 0

    # 2) Points élevés
    if int(match_info.get("score_equipe", 0)) >= 86:
        st["counters"]["pts_85_plus"] = st["counters"].get("pts_85_plus", 0) + 1

    # 3) Compo: >=2 joueurs <24 ans dans la sélection (on regarde 'equipe' courante)
    try:
        jeunes = 0
        for idx in globals().get('equipe', []):
            j = globals().get('joueurs', [])[idx]
            if int(j.get("age", 99)) < 24:
                jeunes += 1
        if jeunes >= 2:
            st["counters"]["youth_ok_matches"] = st["counters"].get("youth_ok_matches", 0) + 1
    except Exception:
        pass

    missions_check_completion()

# [MISSIONS][SCHEDULER]
def missions_scheduler_tick(journee_actuelle: int):
    """
    Active une mission uniquement les journées autorisées.
    Exemples: J2, J9, J16 (cadence 'hebdo' approx).
    """
    st = globals().get('missions_state', {})
    if not globals().get('MISSION_ACTIVE', False):
        return

    if globals().get('MISSIONS_WAITING_MANUAL_UNLOCK', False):  # ⬅️ nouveau**
        return
    
    if st.get("current"):
        return

    JOURNEES_AUTORISEES = {2, 9, 16}  # ajuste comme tu veux
    if int(journee_actuelle) in JOURNEES_AUTORISEES:
        missions_activate_one()


def missions_after_purchase(_joueur):
    """Hook après achat Mercato (placeholder pour des futures missions d’achats)."""
    if not globals().get('MISSION_ACTIVE', False): 
        return
    # rien à incrémenter pour le pool actuel → no-op

def missions_on_enter_screen(screen_name):
    """Hook à l’entrée d’un écran (menu_saison, tournois…). Sert aussi à surveiller le stade."""
    if not globals().get('MISSION_ACTIVE', False): 
        return
    st = globals().get('missions_state', {})

    # a/a [MISSIONS][ENTER-SCREEN:DEDUP-3-LINES]
    last = st.get("last_screen")
    if last == screen_name:
        return
    st["last_screen"] = screen_name
    # /a/a

    # Participation tournois: on incrémente à l’entrée de l’écran Tournois
    if screen_name == "tournois":
        st["counters"]["tournois_participations"] = st["counters"].get("tournois_participations", 0) + 1

    # Déblocage niveau de stade: détecte un changement (ng,ns)
    cur_level = (int(globals().get('niveau_global_jeu',1)), int(globals().get('niveau_stade',1)))
    last = st.get("last_stadium_level", cur_level)
    if cur_level != last:
        st["stadium_upgraded_flag"] = 1
        st["last_stadium_level"] = cur_level
    else:
        st["stadium_upgraded_flag"] = st.get("stadium_upgraded_flag", 0)

    missions_check_completion()


# === FIX BANDEAU MISSIONS (sans compteur, centré) ============================

#[MISSIONS][DRAW-PANEL:GAUGE-RIGHT + SPACING + EQUAL-MARGINS]
def missions_draw_panel_compact(surface):
    """
    Bandeau Missions :
    - Titre centré "Mission Active" / "Missions INACTIVES"
    - Jauge réduite (à droite du libellé de la mission en cours)
    - Espace accru entre les 2 lignes
    - Marges haut/bas identiques (contenu centré verticalement avec padding)
    """
    import pygame

    if globals().get('__mission_panel_drawn'):
        return
   

    # Lecture config (x,y,w,h)
    x, y = globals().get('MISSION_PANEL_POS', (72, 88))
    w    = int(globals().get('MISSION_PANEL_WIDTH', 640))
    h    = int(globals().get('MISSION_PANEL_HEIGHT', 120))

    active = bool(globals().get('MISSION_ACTIVE', False))
    st = globals().get('missions_state', {})
    cur = st.get("current")

        # [MISSIONS][DISK COLOR SWITCH ON SUCCESS]
    prog = globals().get('MISSIONS_PROGRESS', {"completed": set(), "in_progress": set(), "selected": None})
    completed = prog.get("completed", set())
    try:
        # id de la mission courante
        mid = str((cur or {}).get("id") or "")
    except Exception:
        mid = ""

    _mission_done = (mid in completed)

    # couleurs (garde tes valeurs si différentes)
    COLOR_DONE   = (40, 160, 60)   # vert “succès”
    COLOR_NORMAL = (235, 120, 20)  # orange actuel

    disk_color = COLOR_DONE if _mission_done else COLOR_NORMAL


    # Fond + glow
    panel = pygame.Surface((w, h), pygame.SRCALPHA)
    if globals().get('HIDE_MISSION_PANEL', False):
        return
    for i in range(6):
        alpha = max(12 - i*2, 0)
        pygame.draw.rect(panel, (60, 200, 120, alpha), (2-i, 2-i, w-4+2*i, h-4+2*i), border_radius=16)
    pygame.draw.rect(panel, (248,248,248, 245), (0, 0, w, h), border_radius=14)
    pygame.draw.rect(panel, (35,35,35, 200),  (0, 0, w, h), width=1, border_radius=14)
    if active:
        pygame.draw.rect(panel, (40, 180, 110, 190), (3, 3, w-6, h-6), width=2, border_radius=12)

    # --- BLINK: avancer l'état ---
    try:
        now = pygame.time.get_ticks()
    except Exception:
        now = 0
    if globals().get('MISSION_BLINK_ACTIVE', False):
        if now >= int(globals().get('MISSION_BLINK_NEXT_MS', 0)):
            # toggle visibilité
            vis = bool(globals().get('MISSION_BLINK_VISIBLE', True))
            vis = not vis
            globals()['MISSION_BLINK_VISIBLE'] = vis
            globals()['MISSION_BLINK_NEXT_MS'] = now + int(globals().get('MISSION_BLINK_INTERVAL_MS', 180))
            # comptage des OFF uniquement
            if not vis:
                globals()['MISSION_BLINK_COUNT'] = int(globals().get('MISSION_BLINK_COUNT', 0)) + 1
                if globals()['MISSION_BLINK_COUNT'] >= 3:  # x3 OFF => fin du blink
                    globals()['MISSION_BLINK_ACTIVE']  = False
                    globals()['MISSION_BLINK_VISIBLE'] = True
    if globals().get('MISSION_BLINK_ACTIVE', False) and not globals().get('MISSION_BLINK_VISIBLE', True):
        return

    # Titre centré (sans compteur)
    title = "Missions INACTIVES" if not active else "Mission Active"
    title_surf = FONT.render(title, True, (0,0,0))
    title_w, title_h = title_surf.get_size()


    # Layout constants
    PAD_Y = 12              # padding haut/bas (sera appliqué *également* en bas)
    GAP_TITLE_TO_L1 = 10    # espace sous le titre avant la ligne 1
    GAP_LINES = 5           # espace entre ligne 1 et ligne 2 (augmenté)
    TEXT_LEFT = 18          # marge gauche pour les textes de lignes

    # Inactif → message simple
    if not active:
        title_x = (w - title_w) // 2
        panel.blit(title_surf, (title_x, 12))
        info = "Basculer MISSION_ACTIVE=True pour activer (aucun effet pour l’instant)."
        panel.blit(POLICE_PETITE.render(info, True, (100,100,100)), (16, 12 + title_h + 14))
        surface.blit(panel, (x, y))
        return

    # 🔔 Si clignotement ET OFF -> n’afficher que le fond (pas de contenu)
    if globals().get('MISSION_BLINK_ACTIVE', False) and (not globals().get('MISSION_BLINK_VISIBLE', True)):
        surface.blit(panel, (x, y))
        return

    # S’assurer d’avoir une mission en cours
    if not cur:
        missions_activate_one()
        cur = st.get("current")

    # Progress (v/m) selon l'id
    def _progress_for(cur_id: str):
        c = st.get("counters", {})
        if cur_id == "perf_win2":
            v, m = c.get("win_streak", 0), 2
        elif cur_id == "perf_85pts":
            v, m = c.get("pts_85_plus", 0), 1
        elif cur_id == "compo_youth2x2":
            v, m = c.get("youth_ok_matches", 0), 2
        elif cur_id == "meta_tournois2":
            v, m = c.get("tournois_participations", 0), 2
        elif cur_id == "meta_stade_next":
            v, m = (1 if st.get("stadium_upgraded_flag") else 0), 1
        else:
            v, m = 0, 1
        return max(0, min(v, m)), m

    v, m = _progress_for(cur.get("id", ""))
    ratio = 0 if m <= 0 else min(1.0, float(v) / float(m))


    # Prépare les deux lignes
    l1_text = f"Mission en cours : {cur['label']}"
    l1_surf = POLICE_PETITE.render(l1_text, True, (22,22,22))
    l1_w, l1_h = l1_surf.get_size()

    reward_parts = []
    tok  = cur.get("reward_tokens", 0)
    xp   = cur.get("reward_xp", 0)
    skin = cur.get("reward_skin")

    # ← tokens : uniquement le nombre
    tok_int = int(tok or 0)
    if tok_int > 0:
        reward_parts.append(str(tok_int))
    show_token_icon = (tok_int > 0)

    if xp:
        reward_parts.append(f"{int(xp)} XP")
    if skin:
        reward_parts.append(f"skin : {skin}")

    reward_str = " + ".join(reward_parts) if reward_parts else "—"
    l2_surf = POLICE_PETITE.render(f"Récompense : {reward_str}", True, (60,60,60))
    l2_w, l2_h = l2_surf.get_size()
            
    # Jauge (réduite) placée à droite du libellé de L1
    gauge_w, gauge_h = 90, 8
    l1_x = TEXT_LEFT
    GAUGE_GAP = 12
    gauge_x = l1_x + l1_w + GAUGE_GAP
    RIGHT_PAD = 16
    if gauge_x + gauge_w > w - RIGHT_PAD:
        gauge_x = w - RIGHT_PAD - gauge_w

    # Hauteur/centrage vertical du contenu
    line1_h  = max(l1_h, gauge_h)
    content_h = title_h + GAP_TITLE_TO_L1 + line1_h + GAP_LINES + l2_h
    start_y   = PAD_Y + max(0, (h - 2*PAD_Y - content_h)//2)

    # 1) Titre centré
    title_x = (w - title_w) // 2
    panel.blit(title_surf, (title_x, start_y))

    # 2) L1 + jauge
    l1_y = start_y + title_h + GAP_TITLE_TO_L1
    panel.blit(l1_surf, (l1_x, l1_y))
    gauge_y = l1_y + (l1_h - gauge_h)//2
    pygame.draw.rect(panel, (225,225,225), (gauge_x, gauge_y, gauge_w, gauge_h), border_radius=4)
    pygame.draw.rect(panel, (42,170,100),  (gauge_x, gauge_y, int(gauge_w * ratio), gauge_h), border_radius=4)
    vm_surf = POLICE_PETITE.render(f"{v}/{m}", True, (50,50,50))
    panel.blit(vm_surf, (gauge_x + gauge_w + 6, gauge_y + 1))

    # 3) L2 : Récompense (simple : préfixe + nb tokens + icône + reste)
    l2_y = l1_y + line1_h + GAP_LINES
    x = TEXT_LEFT

    # a) Préfixe
    pre = POLICE_CLASSEMENT_BOLD.render("Récompense :", True, (60,60,60))
    panel.blit(pre, (x, l2_y))
    x += pre.get_width() + 6

    # b) Si tokens
    if show_token_icon:
        num = POLICE_CLASSEMENT_BOLD.render(str(tok_int), True, (60,60,60))
        panel.blit(num, (x, l2_y))
        x += num.get_width()

        icon = (globals().get('img_token') or globals().get('token_img') or globals().get('icon_token'))
        if icon:
            ih = max(14, num.get_height() - 2)
            iw = int(icon.get_width() * ih / icon.get_height())
            icon_s = pygame.transform.smoothscale(icon, (iw, ih))
            panel.blit(icon_s, (x + 6, l2_y + (num.get_height() - ih)//2))
            x += 6 + iw

    # c) Le reste (XP, skin)
    tail_parts = []
    if xp:   tail_parts.append(f"{int(xp)} XP")
    if skin: tail_parts.append(f"skin : {skin}")
    if tail_parts:
        tail = ("  +  " if show_token_icon else "")  +  "  +  ".join(tail_parts)
        tail_s = POLICE_CLASSEMENT_BOLD.render(tail, True, (60,60,60))
        panel.blit(tail_s, (x, l2_y))

    # Affichage final
    surface.blit(panel, (x, y))
    globals()['__mission_panel_drawn'] = True


# [MISSIONS][BOARD:STATE+HELPERS]
globals().setdefault('MISSIONS_OFFERS', [])  # offres visibles sur le board (jusqu'à 4)

def missions_board_refresh_offers(n=4):
    """Remplit MISSIONS_OFFERS avec n missions non terminées, non 'hidden'."""
    st = globals().get('missions_state', {})
    done = set(st.get("completed", []))
    offers = []
    # a/a [MISSIONS][LEVEL-GATE:BOARD]
    lv = int(globals().get('niveau_global_jeu', 1))
    for m in MISSIONS_POOL:
        if not _mission_is_eligible(m, lv):
            continue
        if m.get("hidden"):
            continue
        if m["id"] in done:
            continue
        if st.get("current") and st["current"].get("id") == m["id"]:
            continue
        offers.append(dict(m))
        if len(offers) >= n:
            break
    globals()['MISSIONS_OFFERS'] = offers
    

def missions_board_accept(mission_id: str):
    """Accepte une mission du board si aucun slot n’est occupé (1 seule mission active)."""
    st = globals().get('missions_state', {})
    if st.get("current"):      # déjà une mission active → refuse
        globals()['ui_flash_msg'] = "Une mission est déjà en cours."
        return False
    
    for m in globals().get('MISSIONS_OFFERS', []):
        if m["id"] == mission_id:
            st["current"] = dict(m)
            globals()['missions_state'] = st

            # [MISSIONS][UNIFY] — sync immédiate avec la roadmap
            prog = globals().setdefault('MISSIONS_PROGRESS', {
                "completed": set(), "in_progress": set(), "selected": None
            })
            mid = st["current"]["id"]
            prog["selected"] = mid
            ip = prog.get("in_progress")
            if isinstance(ip, set):
                ip.add(mid)
            else:
                s = set(ip) if isinstance(ip, list) else set()
                s.add(mid)
                prog["in_progress"] = s
            globals()['MISSIONS_PROGRESS'] = prog

            # ► réafficher le bandeau pour la nouvelle mission
            globals()['HIDE_MISSION_PANEL'] = False
            globals()['MISSION_ACTIVE'] = True

            # démarrer le clignotement (re-use)
            try:
                now = pygame.time.get_ticks()
            except Exception:
                now = 0
            globals()['MISSION_BLINK_ACTIVE']  = True
            globals()['MISSION_BLINK_VISIBLE'] = True
            globals()['MISSION_BLINK_COUNT']   = 0
            globals()['MISSION_BLINK_NEXT_MS'] = now + int(globals().get('MISSION_BLINK_INTERVAL_MS', 180))
            # vider les offres (ou les laisser, au choix)
            globals()['MISSIONS_OFFERS'] = []
            return True

    return False


def _mission_unlock_cost(m):
    # 1) priorise le coût spécifique à la mission
    # 2) sinon accepte 'token_cost' si déjà présent dans tes anciens blocs
    # 3) sinon fallback global (au pire TOKENS_ACCEL_MISSION si existant)
    return int(
        (m or {}).get('unlock_cost_tokens',
        (m or {}).get('token_cost',
        globals().get('TOKENS_UNLOCK_MISSION',
        globals().get('TOKENS_ACCEL_MISSION', 4))))
    )


def missions_unlock_immediate(mid: str) -> bool:
    """
    Débloque immédiatement la mission 'mid' en débitant le nombre de tokens
    défini pour CETTE mission. Ne change pas d'écran.
    """
    # 1) Retrouver la mission (pool/roadmap unifiée)
    missions = list(globals().get('MISSIONS_POOL', globals().get('MISSIONS_ROADMAP', [])))
    m = next((mm for mm in missions if str(mm.get('id')) == str(mid)), None)
    if not m:
        globals()['ui_flash_msg']   = f"Mission inconnue: {mid}"
        try: globals()['ui_flash_until'] = pygame.time.get_ticks() + 1800
        except Exception: pass
        return False

    # 2) Calcul du coût via le helper
    cost  = _mission_unlock_cost(m)
    solde = int(globals().get('TOKENS', 0))

    # 3) Vérif solde
    if solde < cost:
        globals()['ui_flash_msg']   = f"Tokens insuffisants (requis: {cost})"
        try: globals()['ui_flash_until'] = pygame.time.get_ticks() + 2200
        except Exception: pass
        return False

    # 4) Débit réel
    globals()['TOKENS'] = solde - cost

    # 5) Marquer la mission comme "en cours" / sélectionnée côté roadmap
    prog = globals().setdefault('MISSIONS_PROGRESS', {"done": set(), "in_progress": set(), "selected": None})
    ip   = prog.get("in_progress")
    if not isinstance(ip, set):
        ip = set(ip or [])
    ip.add(mid)
    prog["in_progress"] = ip
    prog["selected"]    = mid
    globals()['MISSIONS_PROGRESS'] = prog

    # 6) Synchroniser le panneau (option : la rendre "current" aussi)
    st = globals().setdefault('missions_state', {})
    st["current"] = dict(m)
    globals()['HIDE_MISSION_PANEL'] = False
    globals()['MISSION_ACTIVE']     = True
    globals()['MISSIONS_WAITING_MANUAL_UNLOCK'] = False

    # 7) Petit feedback utilisateur
    globals()['ui_flash_msg']   = f"Mission débloquée : {m.get('label', mid)} (-{cost} TOK)"
    try: globals()['ui_flash_until'] = pygame.time.get_ticks() + 2200
    except Exception: pass

    return True


# ============================================================================ 


def xp_add(amount, reason=""):
    amt = int(amount or 0)
    if amt <= 0:
        return
    # total
    cur = int(globals().get('xp_total', 0))
    cur += amt
    globals()['xp_total'] = cur

    # feedback léger (réutilise le bandeau flash existant)
    try:
        globals()['message_flash'] = f"+{amt} XP" + (f" · {reason}" if reason else "")
    except Exception:
        pass

    # level-up (palier(s) possibles en chaîne)
    lvl = int(globals().get('player_level', 1))
    thresholds = list(globals().get('XP_THRESHOLDS', [100, 250, 500, 900, 1400, 2000]))
    while (lvl - 1) < len(thresholds) and cur >= thresholds[lvl - 1]:
        lvl += 1
        globals()['player_level'] = lvl
        # petit toast de level-up
        globals()['message_flash'] = f"Niveau {lvl} atteint !"

    globals()['player_level'] = lvl



def generer_joueurs_mercato(nb_joueurs=6):

    postes = ["Meneur", "Ailier", "Pivot", "Arrière"]

    # [MERCATO] Pool locale de prénoms et lettres pour le format "Prénom X."
    prenoms_pool = [
        "Lucas", "Noah", "Ethan", "Liam", "Hugo", "Enzo", "Gabriel", "Théo",
        "Mathis", "Tom", "Alexis", "Nathan", "Adam", "Sacha", "Yanis", "Baptiste",
        "Clément", "Romain", "Jules", "Victor"
    ]
    lettres_pool = list("ABCDEFGHIJKLMNOPQRSTUVWXYZ")
    noms_utilises = set()

    for _ in range(nb_joueurs):
        age = random.randint(18, 34)
        precision = round(random.uniform(0.65, 0.90), 2)
        vitesse = random.randint(60, 90)
        force = random.randint(55, 95)
        defense = random.randint(60, 90)
        endurance = random.randint(65, 90)

        # --- NOM SPÉCIFIQUE MERCATO : "Prénom X." avec combinaison unique ---
        nom_affiche = None
        # On essaie plusieurs fois pour éviter les doublons ; avec 20*26 possibilités,
        # on est très large pour les ~6 joueurs par vague.
        for _tentative in range(100):
            prenom = random.choice(prenoms_pool)
            lettre = random.choice(lettres_pool)
            cle = (prenom, lettre)
            if cle not in noms_utilises:
                noms_utilises.add(cle)
                nom_affiche = f"{prenom} {lettre}."
                break
        if not nom_affiche:
            # Fallback ultra rare : on se rabat sur generate_player_name()
            nom_affiche = str(generate_player_name() or "").strip()

        joueur = {
            "nom": nom_affiche,
            "poste": random.choice(postes),
            "age": age,
            "precision": precision,
            "vitesse": vitesse,
            "force": force,
            "defense": defense,
            "endurance": endurance,
            "reussite_2pts": round(random.uniform(0.45, 0.7), 2),
            "reussite_3pts": round(random.uniform(0.25, 0.5), 2)
        }
        
        joueur["pondération"] = round(calculer_pondération(joueur), 2)
        salaire = int(70000 + joueur["pondération"] * 500)
        joueur["salaire"] = f"{max(70000, min(salaire, 130000)):,}".replace(",", ".") + " €"
        joueurs_mercato.append(joueur)
        

# [ADVERSAIRE][OPTION A – fatigue globale + absences simulées]
def get_adversaire_fatigue_coeff(nom_adverse=None):
    """
    Retourne un coefficient multiplicatif de fatigue pour l'équipe adverse.
    Option A : malus léger en fonction du nombre de matchs déjà joués.
    """
    try:
        nb_matchs = len(globals().get('historique_matchs', []))
    except Exception:
        nb_matchs = 0

    if nb_matchs <= 0:
        return 1.0

    # On suppose ~22 journées de saison régulière : malus max d'environ 8 %
    max_malus = 0.08
    ratio = max(0.0, min(nb_matchs, 22)) / 22.0
    malus = max_malus * ratio
    return 1.0 - malus


def get_adversaire_absence_malus(score_brut, nom_adverse=None):
    """
    Simule l'absence d'un titulaire adverse.
    Retourne un nombre de points à retirer du score adverse.
    """
    import random

    if score_brut <= 0:
        return 0

    # Probabilité qu'un titulaire adverse soit "absent" (blessure/suspension simulée)
    proba_absence = 0.25
    if random.random() >= proba_absence:
        return 0

    # Malus proportionnel au score : entre -5 % et -12 %
    amp = random.uniform(0.05, 0.12)
    return int(round(score_brut * amp))


def appliquer_modulateurs_adversaire(score_brut, nom_adverse=None):
    """
    Applique Option A sur le score adverse :
      - fatigue globale d'équipe (coefficient multiplicatif)
      - malus d'absence simulée (points en moins)
    """
    coeff_fatigue = get_adversaire_fatigue_coeff(nom_adverse)
    score = int(round(score_brut * coeff_fatigue))

    malus_abs = get_adversaire_absence_malus(score, nom_adverse)
    score -= malus_abs

    # Garde-fou : on évite les scores négatifs
    if score < 0:
        score = 0

    return score


def simuler_match():
    global equipe, nom_equipe, prochain_adversaire
    global liste_adversaires_aller
    global mercato_disponible, mercato_compteur
    global etat, classement
    global afficher_message_findesaison, saison_courante, bandeau_debut_saison, pret_nouvelle_saison, reset_saison_pending
    global historique_matchs

       
    matchs_joues = len(globals().get('historique_matchs', []))

    try:
        tm = globals().get('titulaires_match', set())
        if (not equipe) and tm:
            if isinstance(tm, (set, list, tuple)):
                equipe = set(tm)  # on reste cohérent avec le type historique (set d'indices)
            else:
                equipe = set()
    except Exception:
        pass


    if not equipe:
        print("⚠️ Aucune équipe sélectionnée. Impossible de simuler le match.")
        return {
            "score_equipe": 0,
            "score_adverse": 0,
            "resultat": "Erreur : pas d'équipe",
            "mvp_equipe": {"nom": "N/A"},
            "mvp_match": {"nom": "N/A"},
            "adversaire": prochain_adversaire if prochain_adversaire else "???"
        }


        # Utiliser le prochain_adversaire déjà prévu
    equipe_adverse, nom_adverse = generer_equipe_adverse_depuis_nom(prochain_adversaire)


    global _mode_simulation
    _mode_simulation = True
    pondere_joueurs = [calculer_pondération(joueurs[i]) for i in equipe]
    if pondere_joueurs:
        moyenne_pond_equipe = sum(pondere_joueurs) / len(pondere_joueurs)
    else:
        moyenne_pond_equipe = 70  # valeur par défaut de secours

    moyenne_pond_adverse = sum(calculer_pondération(j) for j in equipe_adverse) / len(equipe_adverse)


        # Influence des pondérations sur le score simulé
    base_score = random.randint(70, 90)
    diff_pond = moyenne_pond_equipe - moyenne_pond_adverse

    score_equipe = int(base_score + diff_pond * 25 + random.randint(-5, 5))
    score_adverse = int(base_score - diff_pond * 25 + random.randint(-5, 5))

        # S'assurer que les scores sont réalistes
    score_equipe = max(50, min(score_equipe, 120))
    score_adverse = max(50, min(score_adverse, 120))

        # Initialisation des listes pour stocker les scores des joueurs
    score_joueur_equipe = []
    score_joueur_adverse = []

    # [COACH][BRIQUE AVANCÉE] – meilleurs joueurs simulés si coach niv ≥ 2
    try:
        coach_tier = int(globals().get('COACH_TIER', 0) or 0)
    except Exception:
        coach_tier = 0
    use_coach_advanced = bool(globals().get('COACH_ENABLED') and coach_tier >= 2)

    if use_coach_advanced:
        # Version avancée : on ne simule que les meilleurs joueurs de ton équipe
        meilleurs_joueurs = sorted(
            [joueurs[i] for i in equipe if "pondération" in joueurs[i]],
            key=lambda j: j["pondération"],
            reverse=True
        )[:5]
        for joueur in meilleurs_joueurs:
            # Niv2 : même variance qu'avant ; Niv3 : variance légèrement réduite
            rand_amp = 10
            if coach_tier >= 3:
                rand_amp = 8
            score = calculer_pondération(joueur) + random.uniform(-rand_amp, rand_amp)
            score_joueur_equipe.append((joueur, score))
    else:
        # Version standard (sans coach ou coach niv 1) : tous les joueurs sélectionnés
        for i in equipe:
            joueur = joueurs[i]
            score = calculer_pondération(joueur) + random.uniform(-10, 10)
            score_joueur_equipe.append((joueur, score))

    # Adversaire : inchangé (pas de coach pour eux)
    for joueur in equipe_adverse:
        score = calculer_pondération(joueur) + random.uniform(-10, 10)
        score_joueur_adverse.append((joueur, score))


    # 🔁 Mettre à jour le % tir de CHAQUE joueur pour ce match
    def _maj_reussite_tirs(_j):
        perf_live = calculer_pondération(_j)  # inclut fatigue/motivation
        r2 = 0.48 + (perf_live - 75) / 400.0
        r3 = 0.33 + (perf_live - 75) / 600.0
        r2 += random.uniform(-0.015, 0.015)
        r3 += random.uniform(-0.015, 0.015)
        _j["reussite_2pts"] = max(0.30, min(0.65, r2))
        _j["reussite_3pts"] = max(0.20, min(0.45, r3))

    for _j, _ in score_joueur_equipe:
        _maj_reussite_tirs(_j)

    for _j, _ in score_joueur_adverse:
        _maj_reussite_tirs(_j)

   

    total_equipe = sum(score for _, score in score_joueur_equipe)
    total_adverse = sum(score for _, score in score_joueur_adverse)

    score_final_equipe = int(total_equipe // 10)
    score_final_adverse = int(total_adverse // 10)

    # [ADVERSAIRE][OPTION A – fatigue globale + absences simulées]
    score_final_adverse = appliquer_modulateurs_adversaire(score_final_adverse, nom_adverse)

    # --- Bonus de profondeur d'effectif ---
    remplacants = max(0, len(equipe) - 5)

    if False:  # ⛔ désactivé tant que le Niveau 2 n'est pas débloqué
        bonus_profondeur = 0
        for i in equipe[5:]:  # du 6e joueur jusqu'au dernier
            if "pondération" in joueurs[i]:
                bonus_profondeur += int(joueurs[i]["pondération"] // 10)  # ex: pondération 76 => +7
    else:
        # ✅ version simple par défaut — activée seulement si coach niveau ≥ 2
        try:
            coach_tier = int(globals().get('COACH_TIER', 0) or 0)
        except Exception:
            coach_tier = 0

        if globals().get('COACH_ENABLED') and coach_tier >= 2:
            # 1 point par remplaçant utile, max 3
            bonus_profondeur = min(remplacants, 3) * 1
        else:
            bonus_profondeur = 0

    score_final_equipe += bonus_profondeur

    # [COACH][BONUS SIMPLE] – impact direct du niveau de coach sur le score final
    try:
        coach_tier = int(globals().get('COACH_TIER', 0) or 0)
    except Exception:
        coach_tier = 0

    if globals().get('COACH_ENABLED') and coach_tier > 0:
        # Coefficient d'impact du coach en fonction du niveau du club
        try:
            club_level = int(globals().get('CLUB_LEVEL', 1))
        except Exception:
            club_level = 1

        try:
            facteur = get_coach_factor(club_level)
        except Exception:
            # garde-fou : ancien comportement
            facteur = 2.0

        coach_bonus = int(round(facteur * coach_tier))
        score_final_equipe += coach_bonus


    meilleur_joueur_equipe, _ = max(score_joueur_equipe, key=lambda x: x[1])
    meilleur_joueur_match, _ = max(score_joueur_equipe + score_joueur_adverse, key=lambda x: x[1])

    if score_final_equipe > score_final_adverse:
        resultat = "Victoire"
    elif score_final_equipe < score_final_adverse:
        resultat = "Défaite"
    else:
        resultat = "Match Nul"


    # ➜ XP simple selon le résultat du match (centralisé via get_match_xp)
    if not globals().get('_xp_match_done'):
        # 1) Niveau actuel du club (pour de futures évolutions du barème)
        try:
            club_level = int(globals().get('CLUB_LEVEL', 1))
        except Exception:
            club_level = 1

        # 2) Barème d'XP via la fonction centrale
        try:
            xp_gain = int(get_match_xp(resultat, club_level))
        except Exception:
            # Garde-fou : on retombe exactement sur l'ancien comportement
            if resultat == "Victoire":
                xp_gain = 30
            elif resultat == "Match Nul":
                xp_gain = 10
            else:
                xp_gain = 4

        # 3) Libellé de la raison pour le log d'XP
        if resultat == "Victoire":
            reason = "match_victoire"
        elif resultat == "Match Nul":
            reason = "match_nul"
        else:
            reason = "match_defaite"

        if xp_gain > 0:
            _apply_xp(xp_gain, reason)

        globals()['_xp_match_done'] = True




    mettre_a_jour_popularite(resultat)

    global popularite
    if resultat == "Victoire":
        popularite = min(popularite + 5, 100)
    elif resultat == "Défaite":
        popularite = max(popularite - 5, 0)


    # Match à domicile si son numéro est impair (0, 2, 4, ... donc index pair)
    _saison_count = sum(1 for _e in historique_matchs
                         if not isinstance(_e, dict) or _e.get('type') in (None, 'saison'))
    est_domicile = (_saison_count % 2) == 0

    recette_billetterie = (globals().get("recettes_match_billetterie", 0) if est_domicile else 0)
    recette_boutique    = (globals().get("recettes_match_boutique", 0)    if est_domicile else 0)



    mettre_a_jour_classement(nom_equipe, nom_adverse, score_final_equipe, score_final_adverse)
    match_info = {
        "texte": f"{nom_equipe} {score_final_equipe} - {score_final_adverse} {nom_adverse}|{resultat}",
        "domicile": est_domicile,
        "adversaire": nom_adverse,
        "score_equipe": score_final_equipe,
        "score_adverse": score_final_adverse,
        "recette_billetterie": recette_billetterie,
        "recette_boutique": recette_boutique
    }

    if str(globals().get('match_contexte','saison')) == 'saison':
         historique_matchs.append(match_info)     # on ne journalise dans l'historique que les matchs de Saison


    # Hook missions : après match (inactif si MISSION_ACTIVE=False)  
    try:
        missions_after_match(match_info)
    except Exception:
        pass

    try:
        stade_travaux_apres_match()
    except Exception:
        pass



    # Choisir un nouvel adversaire aléatoire (différent du dernier)
    if len(historique_matchs) < total_matchs_saison:
        anciens = [nom_adverse]
        candidats = [e for e in noms_equipes_possibles if e not in anciens and e != nom_equipe]
        prochain = random.choice(candidats) if candidats else nom_adverse
        prochain_adversaire = prochain



    # Statistiques simulées
    tirs_2_1 = random.randint(55, 70)
    tirs_2_2 = random.randint(55, 70)
    tirs_3_1 = random.randint(30, 45)
    tirs_3_2 = random.randint(30, 45)
    passes_1 = random.randint(10, 18)
    passes_2 = random.randint(10, 18)
    fautes_1 = random.randint(10, 20)
    fautes_2 = random.randint(10, 20)

    statistiques_saison.append({
        "tirs_2_pts": [tirs_2_1, tirs_2_2],
        "tirs_3_pts": [tirs_3_1, tirs_3_2],
        "passes": [passes_1, passes_2],
        "fautes": [fautes_1, fautes_2],
        "mvp_equipe": {
            "nom": meilleur_joueur_equipe["nom"],
            "points": random.randint(12, 28),
            "passes": random.randint(4, 10),
            "tirs_2_pts": [random.randint(20, 35), random.randint(30, 50)],
            "tirs_3_pts": [random.randint(10, 25), random.randint(20, 35)]
        },
        "mvp_match": {
            "nom": meilleur_joueur_match["nom"],
            "points": random.randint(20, 35),
            "passes": random.randint(5, 12),
            "tirs_2_pts": [random.randint(25, 40), random.randint(35, 55)],
            "tirs_3_pts": [random.randint(15, 30), random.randint(25, 40)]
        }
    })

        # Enregistrer les résultats complets pour affichage (MVP, score, etc.)
    resultats_matchs_complets.append({
        "score": f"{nom_equipe} {score_final_equipe} - {score_final_adverse} {nom_adverse}",
        "resultat": resultat,
        "mvp_match": {
            "nom": meilleur_joueur_match["nom"]
        }
    })


    # Snapshot utilisé par le return (évite IndexError si reset plus tard)
    _last_stats_for_return = statistiques_saison[-1] if statistiques_saison else {}

    # [KINE][PHYSIQUE] Paramètres de convalescence selon le Kiné actif
    try:
        _kine_tier = int(globals().get("KINE_TIER", 0) or 0)
    except Exception:
        _kine_tier = 0

    _kine_cfg_all = globals().get("KINE_IA_CONFIG", {})
    try:
        _kine_cfg = (_kine_cfg_all or {}).get(_kine_tier) or (_kine_cfg_all or {}).get(0) or {}
    except Exception:
        _kine_cfg = {}

    try:
        _kine_recup_matches = int(_kine_cfg.get("recup_matches", 3) or 3)
    except Exception:
        _kine_recup_matches = 3

    try:
        _kine_injury_min_tier = int(globals().get("KINE_INJURY_MIN_TIER", 2) or 2)
    except Exception:
        _kine_injury_min_tier = 2



    # 🔁 Mise à jour de la motivation de chaque joueur après le match
    for idx, joueur in enumerate(joueurs):

        # [KINE][PHYSIQUE] Compte à rebours simple de la convalescence
        try:
            mc = int(joueur.get("matches_conval", 0) or 0)
        except Exception:
            mc = 0
        if mc > 0:
            mc -= 1
            joueur["matches_conval"] = mc
            if mc <= 0:
                # Fin de convalescence : le joueur n'est plus considéré blessé
                joueur["blessure"] = False
        
        if idx in equipe:
            joueur["motivation"] += 2  # 🎯 Joueur a participé au match

            if joueur["nom"] == meilleur_joueur_match["nom"]:
                joueur["motivation"] += 4  # 🏆 MVP du match = gros bonus
            elif joueur["nom"] == meilleur_joueur_equipe["nom"]:
                joueur["motivation"] += 2  # 🌟 MVP de l'équipe = bonus moyen

            if resultat == "Victoire":
                joueur["motivation"] += 2
            elif resultat == "Défaite":
                joueur["motivation"] -= 3
                
            joueur["matchs_consecutifs"] = joueur.get("matchs_consecutifs", 0) + 1   # ✅ fatigue si le joueur a joué
            joueur["repos_consecutifs"] = 0 
        else:
             joueur["motivation"] -= 2  # ⛔ Non sélectionné : baisse légère
             joueur["matchs_consecutifs"] = 0          # ✅ repos : on remet à zéro la série
             joueur["repos_consecutifs"] = joueur.get("repos_consecutifs", 0) + 1

        # [KINE][PHYSIQUE] Risque simple de blessure pour les joueurs ayant joué
        if idx in equipe and _kine_tier >= _kine_injury_min_tier:
            # On ne re-blesse pas un joueur déjà en convalescence
            if not joueur.get("blessure") and int(joueur.get("matches_conval", 0) or 0) == 0:
                try:
                    proba_blessure = 0.03  # 3 % de base, ajustable plus tard
                    if random.random() < proba_blessure:
                        joueur["blessure"] = True
                        joueur["matches_conval"] = _kine_recup_matches
                except Exception:
                    pass
             
        joueur["motivation"] = max(50, min(100, joueur["motivation"]))  # 🧱 Sécuriser les bornes entre 50 et 100
        
    _mode_simulation = False
    for joueur in joueurs:
        joueur["pondération"] = round(calculer_pondération(joueur), 2)


    # ➤ Activer le Mercato après 11 matchs (à partir du 12ᵉ)
    if 11 <= matchs_joues < 14:
        mercato_disponible = True
    else:
        mercato_disponible = False

    # Compte à rebours avant ouverture
    if matchs_joues < 11:
        mercato_compteur = 11 - matchs_joues
    else:
        mercato_compteur = 0


    # --- snapshot : les travaux de fin de saison vident les listes ---
    _last_stats_for_return = statistiques_saison[-1] if statistiques_saison else {}

    # Vérifie si la saison est terminée (après avoir produit les stats du match)
    if (
        len(historique_matchs) >= total_matchs_saison
        and str(globals().get('etat', '')).lower() not in ('playoffs', 'prime_champion')
        and str(globals().get('po_phase', '')).lower() != 'termine'
    ):
        print("🎉 Fin de la saison détectée")
        try:
            me = (globals().get('nom_equipe') or
                  globals().get('team_name') or
                  globals().get('club_name'))
            wins = {}
            for m in historique_matchs:
                if not isinstance(m, dict):
                    continue
                # Reconstruire home/away & scores à partir de ta structure
                if isinstance(m.get('domicile'), bool):
                    adv_name = (m.get('adversaire') or m.get('nom_adversaire') or m.get('opposant'))
                    home = me if m['domicile'] else adv_name
                    away = adv_name if m['domicile'] else me
                    # SAFE GUARD : évite None/vides
                    if not (isinstance(home, str) and isinstance(away, str) and home and away):
                        continue

                    se = m.get('score_equipe'); sa = m.get('score_adverse')
                    try:
                        se = int(str(se).replace(' ', '').replace('.', ''))
                        sa = int(str(sa).replace(' ', '').replace('.', ''))
                    except Exception:
                        continue  # scores non numériques → on ignore ce match

                    sd    = se if m['domicile'] else sa
                    saway = sa if m['domicile'] else se
                    if sd > saway:
                        wins[home] = wins.get(home, 0) + 1
                    elif saway > sd:
                        wins[away] = wins.get(away, 0) + 1

            classement_wins = sorted(wins.items(), key=lambda x: (-x[1], str(x[0]).lower()))
            seeds = [e for e, _ in classement_wins[:4]]

        except Exception:
            seeds = []
            me = (globals().get('nom_equipe') or
                  globals().get('team_name') or
                  globals().get('club_name') or "")

        def _i(x):
            try:
                return int(str(x).replace(' ', '').replace('.', ''))
            except Exception:
                return 0

        def _name(e):
            return (e.get("nom") or e.get("equipe") or e.get("Equipe") or
                    e.get("team") or e.get("Team") or "").strip()

        # --- NEW: Top-4 via 'classement' comme source de vérité (fallback discret) ---
        _classement_global = globals().get('classement') or []
        if not isinstance(_classement_global, list):
            _classement_global = []

        try:
            _cls_sorted = sorted(
                [e for e in _classement_global if isinstance(e, dict)],
                key=lambda e: (-_i(e.get("points", 0)),
                               -_i(e.get("victoires", 0)),
                               _name(e).lower())
            )
        except Exception:
            _cls_sorted = []

        top4 = []
        for e in _cls_sorted:
            nm = _name(e)
            if nm:
                top4.append(nm)
            if len(top4) == 4:
                break

        # Fallback ultra sobre si le tri échoue mais que la liste est déjà ordonnée
        if not top4 and _classement_global:
            for e in _classement_global[:4]:
                if isinstance(e, dict):
                    nm = _name(e)
                    if nm:
                        top4.append(nm)
                        if len(top4) == 4:
                            break
                        
        # --- NEW: normalisation nom d'équipe + condition consolidée ---
        def _n(x): return str(x).strip().lower()
        _seeds_ok = (len(seeds) >= 4) and (_n(me) in {_n(n) for n in seeds})
        _top4_ok  = (len(top4) >= 4) and (_n(me) in {_n(n) for n in top4})

        if _seeds_ok or _top4_ok:
            # Lancer les PO
            # choisir la source valide (seeds si complet, sinon top4)
            equipes_po = seeds if len(seeds) >= 4 else top4
            globals()['playoffs_en_cours'] = True
            globals()['playoffs_equipes']  = equipes_po
            globals()['playoffs_bracket']  = [(equipes_po[0], equipes_po[3]), (equipes_po[1], equipes_po[2])]
            globals()['etat'] = 'playoffs'
            globals()['en_playoffs'] = True   
            globals()['po_en_cours'] = True
            globals()['afficher_message_findesaison'] = True

            

            adv = None
            for a, b in globals()['playoffs_bracket']:
                if _n(a) == _n(me): adv = b
                if _n(b) == _n(me): adv = a

            if adv:
                globals()['prochain_adversaire'] = adv
            try:
                lst = globals().get('playoffs_equipes') or equipes_po
                rang = 1 + next(i for i, n in enumerate(lst) if _n(n) == _n(me))
                globals()['message_blocage'] = f"🏆 Playoffs : vous êtes {rang}e !"
                globals()['temps_blocage']   = pygame.time.get_ticks()
            except Exception:
                pass

            # ➜ On retourne tout de suite (pas de reset ici)
            return {
                "score_equipe": score_final_equipe,
                "score_adverse": score_final_adverse,
                "mvp_equipe": meilleur_joueur_equipe,
                "mvp_match":  meilleur_joueur_match,
                "resultat": resultat,
                "adversaire": nom_adverse,
                "stats": _last_stats_for_return
            }
        else:
            # Pas de PO → fin de saison normale
            # AJOUT : photographier l'écran Finances de la saison qui se termine
            try: _capture_finances_snapshot()
            except: pass

            s_prev = int(globals().get('saison_courante', 1))
            snaps = globals().setdefault('finance_snapshots', {})
            if s_prev not in snaps:
                import os
                snaps[s_prev] = os.path.join("captures", f"finance_saison_{s_prev}.png")

            
            saison_terminee()
            globals()['afficher_message_findesaison'] = True
            globals()['saison_courante'] = int(globals().get('saison_courante', 1)) + 1
            globals()['bandeau_debut_saison'] = f"Démarrage Saison {globals()['saison_courante']} — 1er Match de kick-off"
            globals()['pret_nouvelle_saison'] = True
            globals()['reset_saison_pending'] = True

            # --- RESET UI & PANELS POUR NOUVELLE SAISON ---
            globals()['zone_selectionnee_saison'] = ""            # retour au menu neutre
            globals()['decalage_scroll_calendrier'] = 0
            globals()['hauteur_contenu_calendrier'] = 0
            globals()['croix_fermeture_calendrier'] = None

            # Panneaux / données saison à zéro
            globals()['classement'] = []
            globals()['statistiques_saison'] = []
            globals()['calendrier'] = []                          # force le fallback (ou regen) du calendrier
            globals()['mercato_disponible'] = False
            globals()['mercato_ouvert'] = False


            # --- RESET TOURNOIS (saison suivante) ---
            globals()['tournoi_a_deja_lance'] = False
            globals()['dernier_bouton_tournoi_clique'] = ""
            globals()['mon_equipe_a_gagne_le_tournoi'] = False

            # Revenir sur les valeurs par défaut déclarées plus haut
            globals()['tournoi_actif'] = "printemps"          # cf. ligne ~631
            globals()['niveau_tournoi_selectionne'] = "Débutant"  # cf. ligne ~632

            # Purge état interne de chaque tournoi/niveau (brackets, résultats, etc.)
            _td = globals().get('tournois_disponibles', {})
            if isinstance(_td, dict):
                for _nom, _tour in _td.items():
                    _niveaux = _tour.get('niveaux', {})
                    if isinstance(_niveaux, dict):
                        for _niv, _obj in _niveaux.items():
                            if isinstance(_obj, dict):
                                _obj['matchs'] = []
                                _obj['tour_actuel'] = 0
                                _obj['resultats'] = []
                                _obj['etat'] = "en_attente"
                                _obj['vainqueur'] = ""
                                _obj['classement'] = []
                # Remet aussi l'état GLOBAL du tournoi (sinon menu grisé en s+1)
                try:
                    _tour['etat'] = "en_attente"
                except Exception:
                    pass

            # -- Reset "4 victoires" pour la nouvelle saison (fin de match)
            globals()['popup_victoire_4matchs_affichee'] = False
            globals()['afficher_message_4_victoires'] = False
            globals()['index_debut_saison'] = len(globals().get('historique_matchs', []))



            return {
                "score_equipe": score_final_equipe,
                "score_adverse": score_final_adverse,
                "mvp_equipe": meilleur_joueur_equipe,
                "mvp_match":  meilleur_joueur_match,
                "resultat": resultat,
                "adversaire": nom_adverse,
                "stats": _last_stats_for_return
            }

    # retour standard
    return {
        "score_equipe": score_final_equipe,
        "score_adverse": score_final_adverse,
        "mvp_equipe": meilleur_joueur_equipe,
        "mvp_match": meilleur_joueur_match,
        "resultat": resultat,
        "adversaire": nom_adverse,
        "stats": _last_stats_for_return
    }
    

def mettre_a_jour_popularite(resultat):
    global popularite

    if resultat == "Victoire":
        popularite += 3
    elif resultat == "Défaite":
        popularite -= 2
    elif resultat == "Match Nul":
        popularite += 1

    # Bornes de sécurité
    popularite = max(0, min(popularite, 100))


def appliquer_inflation_salariale():
    """Augmente le facteur d'inflation globale une fois par fin de saison.
    - SALARY_INFLATION_RATE : +x % par saison
    - SALARY_INFLATION_FACTOR : multiplicateur appliqué partout où on formate/calcul les salaires
    """
    try:
        taux = float(globals().get('SALARY_INFLATION_RATE', 0.0) or 0.0)
    except Exception:
        taux = 0.0
    if taux <= 0:
        return

    try:
        facteur = float(globals().get('SALARY_INFLATION_FACTOR', 1.0) or 1.0)
    except Exception:
        facteur = 1.0

    facteur *= (1.0 + taux)
    globals()['SALARY_INFLATION_FACTOR'] = facteur
    print(f"💶 Inflation salariale appliquée : +{int(taux*100)} % → x{facteur:.3f}")


        

def saison_terminee():
    global saison_actuelle, historique_matchs, statistiques_saison, prochain_adversaire

    saison_actuelle += 1
    try:
        appliquer_inflation_salariale()
    except Exception:
        pass
    
    historique_matchs.clear()
    statistiques_saison.clear()
    globals()['numero_saison'] = saison_actuelle


    # Réinitialise les classements
    reinitialiser_statistiques()

    # Tirer un nouvel adversaire pour démarrer la nouvelle saison
    candidats = [e for e in noms_equipes_possibles if e != nom_equipe]
    prochain_adversaire = random.choice(candidats)

    mettre_a_jour_joueurs_equipe()
    _js = globals().get('joueurs', [])
    _eq = list(globals().get('equipe', []))  # indices
    sel = globals().get('ma_selection')      # parfois une liste de dicts
    if not sel:  # fabrique une liste de dicts à partir des indices d'`equipe`
        sel = [_js[i] for i in _eq if isinstance(i, int) and 0 <= i < len(_js)]

    globals()['ma_selection'] = sel

    for joueur in sel:
        if joueur.get("achete") and "salaire_complet" in joueur:
            joueur["salaire"] = int_vers_salaire_str(joueur["salaire_complet"])

    print(f"🆕 Début de la saison {saison_actuelle}")

    

def initialiser_classement():
    global classement, nom_equipe  # Assure-toi que nom_equipe est global ici
    classement = [
        {"nom": nom_equipe if nom_equipe.strip() else "Votre équipe", "victoires": 0, "defaites": 0, "matchs_nuls": 0, "points": 0}
    ]
    for nom in noms_equipes_possibles:
       if nom != nom_equipe:
           classement.append({
               "nom": nom,
               "victoires": 0,
               "defaites": 0,
               "matchs_nuls": 0,
               "points": 0
        })

    # Tri du classement
    classement.sort(key=lambda x: (-x["points"], -x["victoires"]))



def po_noms_top4(depuis_classement):
    """Retourne la liste des 4 équipes en tête, robustement."""
    noms = []
    if isinstance(depuis_classement, list):
        # On suppose que 'classement' est déjà trié par points/victoires
        for e in depuis_classement[:4]:
            nom = e.get("nom") if isinstance(e, dict) else str(e)
            if nom:
                noms.append(nom)
    # sécurité : on complète si nécessaire
    if 'nom_equipe' in globals() and nom_equipe and nom_equipe not in noms:
        noms.append(nom_equipe)
    if 'noms_equipes_possibles' in globals():
        import random
        candidats = [n for n in noms_equipes_possibles if n not in noms and n != nom_equipe]
        while len(noms) < 4 and candidats:
            noms.append(random.choice(candidats))
    while len(noms) < 4:
        noms.append(f"Équipe {len(noms)+1}")
    return noms


def po_lancer(depuis_classement):
    """Initialise le bracket 1v4 / 2v3, met la phase à 'demies' et passe en mode PO."""
    global po_en_cours, po_phase, po_bracket, po_match_courant
    top4 = po_noms_top4(depuis_classement)
    po_bracket = {
        "demi1":  {"A": top4[0], "B": top4[3], "vainqueur": None, "joue": False},
        "demi2":  {"A": top4[1], "B": top4[2], "vainqueur": None, "joue": False},
        "finale": {"A": None,    "B": None,    "vainqueur": None, "joue": False},
    }
    po_phase = "demies"
    po_en_cours = True
    po_match_courant = None




def mettre_a_jour_classement(equipe1, equipe2, score1, score2):
    global classement

    # Ajoute les équipes si elles ne sont pas déjà dans le classement
    for nom in [equipe1, equipe2]:
        if not any(e["nom"] == nom for e in classement):
            classement.append({"nom": nom, "victoires": 0, "defaites": 0, "matchs_nuls": 0, "points": 0})

    e1 = next(e for e in classement if e["nom"] == equipe1)
    e2 = next(e for e in classement if e["nom"] == equipe2)

    # Mise à jour des résultats
    if score1 > score2:
        e1["victoires"] += 1
        e1["points"] += 3
        e2["defaites"] += 1
    elif score1 < score2:
        e2["victoires"] += 1
        e2["points"] += 3
        e1["defaites"] += 1
    else:
        e1["matchs_nuls"] += 1
        e2["matchs_nuls"] += 1
        e1["points"] += 1
        e2["points"] += 1

    autres_equipes = [e for e in classement if e["nom"] != equipe1 and e["nom"] != equipe2]
    
    for i in range(0, len(autres_equipes), 2):  # On prend les adversaires deux par deux
        if i + 1 < len(autres_equipes):  # Vérifie qu'il y a bien deux équipes à comparer
            e1_adversaire = autres_equipes[i]
            e2_adversaire = autres_equipes[i + 1]

            # Décider du type de match (victoire/défaite ou match nul)
            match_resultat = random.choice(['victoire', 'nul'])

            if match_resultat == 'victoire':
                # Choisir l'équipe gagnante de manière aléatoire
                score1_adversaire = random.randint(50, 100)
                score2_adversaire = random.randint(50, 100)

                if score1_adversaire > score2_adversaire:
                    e1_adversaire["victoires"] += 1
                    e1_adversaire["points"] += 3
                    e2_adversaire["defaites"] += 1
                else:
                    e2_adversaire["victoires"] += 1
                    e2_adversaire["points"] += 3
                    e1_adversaire["defaites"] += 1
            else:
                # En cas de match nul, les deux équipes obtiennent un point
                e1_adversaire["matchs_nuls"] += 1
                e2_adversaire["matchs_nuls"] += 1
                e1_adversaire["points"] += 1
                e2_adversaire["points"] += 1

    classement.sort(key=lambda x: (-x["points"], -x["victoires"]))




# ---- helper: léger effet 3D pour cartes/onglets ----

def draw_tab_3d(surface, rect, base_color, active=False, outline=None):
    import pygame
    if outline is None:
        outline = NOIR  # suppose que NOIR est déjà défini dans ta palette

    # fond + bordure
    pygame.draw.rect(surface, base_color, rect, border_radius=8)
    pygame.draw.rect(surface, outline, rect, 2, border_radius=8)

    # léger biseau (haut/gauche clair, bas/droite sombre)
    light = tuple(min(255, c + 35) for c in base_color)
    dark  = tuple(max(0,   c - 35) for c in base_color)
    pygame.draw.line(surface, light, (rect.left+2, rect.top+2),    (rect.right-2, rect.top+2), 1)
    pygame.draw.line(surface, light, (rect.left+2, rect.top+2),    (rect.left+2,  rect.bottom-2), 1)
    pygame.draw.line(surface, dark,  (rect.left+2, rect.bottom-2), (rect.right-2, rect.bottom-2), 1)
    pygame.draw.line(surface, dark,  (rect.right-2, rect.top+2),   (rect.right-2, rect.bottom-2), 1)

    # petit trait pour “carte active” (optionnel)
    if active:
        underline = pygame.Rect(rect.x+4, rect.bottom-5, rect.w-8, 3)
        pygame.draw.rect(surface, dark, underline)
# ---- fin helper ----




