def dessiner_billetterie():
    global champs_billet_rects, champs_places_rects
    global fleches_billet, fleches_places  
    global overlay_msgs_billetterie
    global prevision_billetterie
    if 'overlay_msgs_billetterie' not in globals() or overlay_msgs_billetterie.get_size() != (LARGEUR, HAUTEUR):
        overlay_msgs_billetterie = pygame.Surface((LARGEUR, HAUTEUR), pygame.SRCALPHA)
    overlay_msgs_billetterie.fill((0, 0, 0, 0))


    categories = ["Catégorie A (VIP)", "Catégorie B (Préférence)", "Catégorie C (Grand Public)"]
    champs_billet_rects.clear()
    champs_places_rects.clear()
    GAP_FLECHES = 5  # augmente ↓ pour plus d’écart (ex. 10, 12)

    H_CASE  = 35   # même hauteur pour Catégorie, Prix, Places
    ROW_GAP = 20   # écart vertical entre lignes

    # ---- Colonnage harmonisé (centré) ----
    W_CAT, CAF_W_PRIX, W_PLACES = 290, 90, 90   # largeurs des cases
    G = 20                                   # gouttière entre colonnes

    total_w = W_CAT + G + CAF_W_PRIX + G + W_PLACES
    left = LARGEUR // 2 - total_w // 2 - 100


    try:
        total_salaires_equipe = sum(
            int(joueurs[i]['salaire'].replace(' €','').replace('.','').replace(' ',''))
            for i in equipe
        )
    except Exception:
        total_salaires_equipe = 0

    capacite_actuelle = get_capacite_stade()

    # % max PRIX (A,B,C) : A=0.004% ; B=0.003% ; C=0.002%
    prix_max_pct    = [0.00004, 0.00003, 0.00002]  # A > B > C
    places_max_pct  = [0.10,    0.40,    0.50   ]


    prix_max_abs   = [int(total_salaires_equipe * p) for p in prix_max_pct]
    places_max_abs = [int(capacite_actuelle * p)     for p in places_max_pct]


    x_cat    = left
    x_prix   = x_cat + W_CAT + G
    x_places = x_prix + CAF_W_PRIX + G

    
    # 🔳 Encadré pour la capacité actuelle
    ORANGE_CLAIR = (255, 220, 180)
    capacite_actuelle = get_capacite_stade()
    rect_capacite = pygame.Rect(x_cat, 185, total_w, 35)
    pygame.draw.rect(FENETRE, ORANGE_CLAIR, rect_capacite)
    pygame.draw.rect(FENETRE, NOIR, rect_capacite, 2)
    texte_capacite = FONT.render(f"Capacité max : {capacite_actuelle} places", True, NOIR)
    texte_capacite_rect = texte_capacite.get_rect(center=rect_capacite.center)
    FENETRE.blit(texte_capacite, texte_capacite_rect)



    # 🧾 Titres des colonnes
    titre_prix = POLICE_MOYENNE.render("Prix (€)", True, NOIR)
    titre_places = POLICE_MOYENNE.render("Nbr places", True, NOIR)
    FENETRE.blit(titre_prix, (x_prix + 10, 230))
    FENETRE.blit(titre_places, (x_places + 5, 230))

        # Réinitialise les flèches (3 catégories)
    fleches_billet  = [ {"up": pygame.Rect(0,0,0,0), "down": pygame.Rect(0,0,0,0)} for _ in range(3) ]
    fleches_places  = [ {"up": pygame.Rect(0,0,0,0), "down": pygame.Rect(0,0,0,0)} for _ in range(3) ]

    total_recette = 0
    total_places = 0

    for i, cat in enumerate(categories):
        y = 260 + i * (H_CASE + ROW_GAP)

        # Catégorie
        rect_cat = pygame.Rect(x_cat, y, W_CAT, H_CASE)
        pygame.draw.rect(FENETRE, BLEU, rect_cat)
        pygame.draw.rect(FENETRE, NOIR, rect_cat, 2)
        txt = POLICE_MOYENNE.render(cat, True, BLANC)
        FENETRE.blit(txt, txt.get_rect(center=rect_cat.center))

        # Prix
        rect_prix = pygame.Rect(x_prix, y, CAF_W_PRIX, H_CASE)
        pygame.draw.rect(FENETRE, BLANC, rect_prix)
        pygame.draw.rect(FENETRE, NOIR, rect_prix, 2)
        texte_prix = saisies_billet[i] + ("|" if champ_actif_billet == i else "")
        surf_prix = POLICE_MOYENNE.render(texte_prix, True, NOIR)
        FENETRE.blit(surf_prix, (rect_prix.x + 6, rect_prix.centery - surf_prix.get_height() // 2))
        champs_billet_rects.append(rect_prix)

        # Flèches ↑/↓ intégrées dans le champ PRIX
        arrow_w = 18
        gutter  = 2
        arrow_col_p = pygame.Rect(rect_prix.right - arrow_w - gutter, rect_prix.top + 4, arrow_w, rect_prix.height - 8)
        pygame.draw.rect(FENETRE, (245, 245, 245), arrow_col_p)
        pygame.draw.line(FENETRE, NOIR, (arrow_col_p.left, arrow_col_p.top), (arrow_col_p.left, arrow_col_p.bottom), 1)

        # Boutons ↑/↓ avec écart contrôlé
        P = 3  # padding haut/bas
        btn_w = arrow_w - 6
        inner_h = arrow_col_p.height - 2 * P
        btn_h = max(8, (inner_h - GAP_FLECHES) // 2)

        up_p = pygame.Rect(arrow_col_p.centerx - btn_w // 2, arrow_col_p.top + P, btn_w, btn_h)
        dn_h = max(8, inner_h - GAP_FLECHES - btn_h)
        dn_p = pygame.Rect(arrow_col_p.centerx - btn_w // 2, up_p.bottom + GAP_FLECHES, btn_w, dn_h)


        fleches_billet[i]["up"]   = up_p
        fleches_billet[i]["down"] = dn_p

        pygame.draw.rect(FENETRE, (245,245,245), up_p); pygame.draw.rect(FENETRE, NOIR, up_p, 1)
        pygame.draw.rect(FENETRE, (245,245,245), dn_p); pygame.draw.rect(FENETRE, NOIR, dn_p, 1)

        # Triangles (un peu marginés)
        pygame.draw.polygon(FENETRE, NOIR, [(up_p.centerx, up_p.top+3), (up_p.left+4, up_p.bottom-3), (up_p.right-4, up_p.bottom-3)])
        pygame.draw.polygon(FENETRE, NOIR, [(dn_p.centerx, dn_p.bottom-3), (dn_p.left+4, dn_p.top+3), (dn_p.right-4, dn_p.top+3)])


        # Places
        rect_places = pygame.Rect(x_places, y, W_PLACES, H_CASE)
        # Cat C : si la valeur courante dépasse (capacité - A - B), on la ramène
        if i == 2:
            a = int(saisies_places[0]) if est_nombre(saisies_places[0]) else 0
            b = int(saisies_places[1]) if est_nombre(saisies_places[1]) else 0
            c_max = max(0, capacite_actuelle - a - b)
            cur_c = int(saisies_places[2]) if est_nombre(saisies_places[2]) else 0
            if cur_c > c_max:
                saisies_places[2] = str(c_max)

        pygame.draw.rect(FENETRE, BLANC, rect_places)
        pygame.draw.rect(FENETRE, NOIR, rect_places, 2)
        texte_places = saisies_places[i] + ("|" if champ_actif_places == i else "")
        surf_places = POLICE_MOYENNE.render(texte_places, True, NOIR)
        FENETRE.blit(surf_places, (rect_places.x + 6, rect_places.centery - surf_places.get_height() // 2))
        champs_places_rects.append(rect_places)

        

        # Flèches ↑/↓ intégrées dans le champ PLACES
        arrow_w = 18
        gutter  = 2
        arrow_col_s = pygame.Rect(rect_places.right - arrow_w - gutter, rect_places.top + 4, arrow_w, rect_places.height - 8)
        pygame.draw.rect(FENETRE, (245, 245, 245), arrow_col_s)
        pygame.draw.line(FENETRE, NOIR, (arrow_col_s.left, arrow_col_s.top), (arrow_col_s.left, arrow_col_s.bottom), 1)

        btn_w = arrow_w - 6
        inner_h = arrow_col_s.height - 2 * P
        btn_h = max(8, (inner_h - GAP_FLECHES) // 2)

        up_s = pygame.Rect(arrow_col_s.centerx - btn_w // 2, arrow_col_s.top + P, btn_w, btn_h)
        dn_h = max(8, inner_h - GAP_FLECHES - btn_h)
        dn_s = pygame.Rect(arrow_col_s.centerx - btn_w // 2, up_s.bottom + GAP_FLECHES, btn_w, dn_h)

        fleches_places[i]["up"]   = up_s
        fleches_places[i]["down"] = dn_s

        pygame.draw.rect(FENETRE, (245,245,245), up_s); pygame.draw.rect(FENETRE, NOIR, up_s, 1)
        pygame.draw.rect(FENETRE, (245,245,245), dn_s); pygame.draw.rect(FENETRE, NOIR, dn_s, 1)
        pygame.draw.polygon(FENETRE, NOIR, [(up_s.centerx, up_s.top+3), (up_s.left+4, up_s.bottom-3), (up_s.right-4, up_s.bottom-3)])
        pygame.draw.polygon(FENETRE, NOIR, [(dn_s.centerx, dn_s.bottom-3), (dn_s.left+4, dn_s.top+3), (dn_s.right-4, dn_s.top+3)])


        # === Message rouge si limite atteinte/dépassée ===
        prix_i   = int(saisies_billet[i]) if est_nombre(saisies_billet[i]) else 0
        places_i = int(saisies_places[i]) if est_nombre(saisies_places[i]) else 0

        cap_msg = places_max_abs[i]
        if i == 2:
            a = int(saisies_places[0]) if est_nombre(saisies_places[0]) else 0
            b = int(saisies_places[1]) if est_nombre(saisies_places[1]) else 0
