def dessiner_interface_stade():
    import pygame
    FENETRE.fill((230, 230, 230))  # Nettoie l'écran
    global message_blocage, temps_blocage

    # 🔔 Affichage temporaire d’un message (confirmation ou erreur)
    if message_blocage and pygame.time.get_ticks() - temps_blocage < 3500:
        txt_col = ROUGE if ("❌" in message_blocage or "⛔" in message_blocage) else (0, 140, 0)
        texte = FONT.render(message_blocage, True, txt_col)
        rect_msg = texte.get_rect(center=(LARGEUR // 2, 115))
        FENETRE.blit(texte, rect_msg)

    # 1) 🏟️ Affichage du fond (image du stade)
    try:
        stade_image = pygame.image.load("images/stade.png").convert_alpha()
        stade_image = pygame.transform.scale(stade_image, (LARGEUR, HAUTEUR))
        stade_image.set_alpha(160)  # transparence OK
        FENETRE.blit(stade_image, (0, 0))
    except Exception:
        # on ne casse rien si l'image manque
        pass

    # 2) 🧭 Onglets
    index_match = len(historique_matchs)  # Parité pour domicile/extérieur incrémentée ailleurs
    ng_cur = int(globals().get('niveau_global_jeu', 1))
    ns_cur = int(globals().get('niveau_stade', 1))

    # [POPUP 1-3] Afficher dès que le stade est réellement au niveau 1-3 (post-travaux), une seule fois
    if (ng_cur == 1 and ns_cur == 3) and not globals().get('_msg_capacite_limitee_shown', False):
        globals()['afficher_message_capacite_limitee'] = True
        globals()['_msg_capacite_limitee_shown'] = True
        

    base_tabs = ["Stade", "Billetterie", "Boutique"]
    tabs = base_tabs[:]
    if (ng_cur > 1) or (ng_cur == 1 and ns_cur >= 2):
        tabs.append("Cafétéria")
    if (ng_cur > 1) or (ng_cur == 1 and ns_cur >= 3):
        tabs.append("Parkings")

    # --- POPUP Capacité limitée (stade 1-3) — rendu dans l'écran Stade ---
    if globals().get('afficher_message_capacite_limitee', False):
        popup_img = globals().get('message_findesaison_img')
        if not popup_img:
            # petit gabarit blanc si l’image n’est pas encore chargée
            popup_img = pygame.Surface((465, 540), pygame.SRCALPHA)
            pygame.draw.rect(popup_img, (255, 255, 255, 240), popup_img.get_rect(), border_radius=12)
        popup_rect = message_findesaison_img.get_rect(center=(LARGEUR // 2, HAUTEUR // 2))
        FENETRE.blit(message_findesaison_img, popup_rect)

        # En-têtes (même style que "fin de saison")
        t1 = POLICE_PETITE.render("From:    Direction", True, NOIR)
        FENETRE.blit(t1, (popup_rect.x + 30, popup_rect.y + 38))
        _alias = (globals().get('alias_manager') or "").strip()
        _dest  = f"To:    Manager{(' ' + _alias) if _alias else ''}"
        t2 = POLICE_PETITE.render(_dest, True, NOIR)
        FENETRE.blit(t2, (popup_rect.x + 30, popup_rect.y + 90))
        objet_capacite = "Object:    Capacité de public limitée"
        t3 = POLICE_PETITE.render(objet_capacite, True, NOIR)
        FENETRE.blit(t3, (popup_rect.x + 30, popup_rect.y + 142))

        import textwrap
        texte_long = (
            "Tes performances attirent de plus en plus de public !  Mais les accès restent limités,"
            " ce qui pénalise les recettes de Billetterie et Boutique.\n"
            "=> Tu peux créer des parkings et recevoir plus de public.\n"
            "Qu'est-ce que tu en penses? "
        )

        # Archive automatiquement ce popup dans Messages & alertes (une seule fois)
        try:
            enregistrer_message_popup_once(
                "popup_capacite_limitee",   # identifiant unique pour ce type de popup
                objet_capacite,            # la ligne "Object: ..."
                texte_long                 # le texte long utilisé juste au-dessus
            )
        except Exception:
            pass

        x = popup_rect.x + 30
        y = popup_rect.y + 200
        line_height = 28
        gap_between_paragraphs = 8

        for bloc in texte_long.split("\n"):               # respecte les sauts de ligne forcés
            for ligne in textwrap.wrap(bloc, width=50):   # wrap à l’intérieur de chaque bloc
                FENETRE.blit(POLICE_PETITE.render(ligne, True, NOIR), (x, y))
                y += line_height
            y += gap_between_paragraphs 
        try:
            croix_fermeture_4victoires
        except NameError:
            croix_fermeture_4victoires = pygame.Rect(0, 0, 24, 24)

        # Croix de fermeture (réutilise la même rect globale)
        croix_fermeture_4victoires.x = popup_rect.right - 35
        croix_fermeture_4victoires.y = popup_rect.top + 5
        pygame.draw.rect(FENETRE, (200, 0, 0), croix_fermeture_4victoires)
        pygame.draw.rect(FENETRE, NOIR, croix_fermeture_4victoires, 2)
        x_txt = POLICE_PETITE.render("X", True, BLANC)
        FENETRE.blit(x_txt, x_txt.get_rect(center=croix_fermeture_4victoires.center))

        globals()['message_capacite_limitee_close_rect'] = croix_fermeture_4victoires

        return  # modal : bloque l’UI en dessous pendant que le popup est affiché

    globals()['titres_stade'] = tabs
    cur_zone = globals().get('zone_selectionnee', 'stade')
    if cur_zone not in [t.lower() for t in tabs]:
        globals()['zone_selectionnee'] = 'stade'
    zone_selectionnee = globals()['zone_selectionnee']

    # Reflow des onglets (garde la même largeur/hauteur)
    if 'rects_stade' in globals() and rects_stade:
        base_rect = rects_stade[0]
    else:
        base_rect = pygame.Rect(140, 60, 160, 40)

    OFFSET_TABS_X = 35
    SEP_TABS = 22
    start_x = max(10, base_rect.x - OFFSET_TABS_X)
    w, h, y = base_rect.w, base_rect.h, base_rect.y
    gap = w + SEP_TABS

    rects_dyn = [pygame.Rect(start_x + i * gap, y, w, h) for i in range(len(tabs))]
    globals()['rects_stade'] = rects_dyn

    for i, t in enumerate(globals()['titres_stade']):
        r = rects_stade[i]
        zone = t.lower()
        if index_match % 2 == 1 and zone in ["billetterie", "boutique", "cafétéria"]:
            couleur = (150, 150, 150)
        elif globals().get('zone_selectionnee', 'stade') == zone:
            couleur = (0, 70, 140)
        else:
            couleur = BLEU
        pygame.draw.rect(FENETRE, couleur, r)
        pygame.draw.rect(FENETRE, NOIR, r, 2)
        tx = FONT.render(t, True, NOIR)
        FENETRE.blit(tx, tx.get_rect(center=r.center))

    if globals().get('afficher_popup_tokens', False):
        draw_token_reminder_popup(FENETRE)
        return  # modal : on bloque tout le reste de l’UI

    # 3) 📄 Contenus
    if zone_selectionnee == "billetterie":
        titre_niveau = POLICE_TITRE.render(f"Niveau {ng_cur}-{ns_cur}", True, NOIR)
        FENETRE.blit(titre_niveau, (425, 120))
        total_places = dessiner_billetterie()
        if total_places > get_capacite_stade():
            alerte = FONT.render("(!) Capacité de places dépassée !", True, ROUGE)
            FENETRE.blit(alerte, (LARGEUR // 2 - alerte.get_width() // 2, 500))

    elif zone_selectionnee == "stade":
        # sync travaux (safe)
        try:
            _stade_travaux_sync()
        except Exception:
            pass

        titre_niveau = POLICE_TITRE.render(f"Niveau {ng_cur}-{ns_cur}", True, NOIR)
        FENETRE.blit(titre_niveau, (425, 120))

        # bandeau saturation accès
        if access_bottleneck_active():
            try:
                _pf = POLICE_PETITE
            except Exception:
                _pf = pygame.font.SysFont("comicsansms", 18)
            rect_info = pygame.Rect(80, 160, 600, 36)
            pygame.draw.rect(FENETRE, (255, 220, 160), rect_info)
            pygame.draw.rect(FENETRE, NOIR, rect_info, 2)
            msg = "Affluence maximale (Niv 1-3) : recettes plafonnées -20%. Améliorez Accès/Parking."
            FENETRE.blit(_pf.render(msg, True, NOIR), (rect_info.x + 10, rect_info.y + 8))

        # Panneaux infos à gauche
        valeur_formatee = f"{int(globals().get('COUT_ENTRETIEN_ANNUEL_NIVEAU1', 0)):,}".replace(",", ".") + " €"
        infos = [
            ("Capacité actuelle", f"{get_capacite_stade()}"),
            ("Entretien", "Bon"),
            ("Coût d'entretien ", valeur_formatee),
        ]
        for j, (label, valeur) in enumerate(infos):
            box_label = pygame.Rect(LARGEUR // 2 - 375, 275 + j * 60, 220, 50)
            box_val   = pygame.Rect(LARGEUR // 2 - 145, 275 + j * 60, 120, 50)
            pygame.draw.rect(FENETRE, NOIR, box_label, 2)
            pygame.draw.rect(FENETRE, BLANC, box_val)
            pygame.draw.rect(FENETRE, NOIR, box_val, 2)
            txt_label = FONT.render(label, True, NOIR)
            txt_val   = FONT.render(valeur, True, NOIR)
            FENETRE.blit(txt_label, (box_label.left + 10, box_label.centery - txt_label.get_height() // 2))
            FENETRE.blit(txt_val,   (box_val.centerx - txt_val.get_width() // 2, box_val.centery - txt_val.get_height() // 2))

        # --- Travaux en cours ? (pour le titre spécifique et la barre de progression)
        travaux = bool(globals().get('stade_travaux_en_cours', False))
        rem = int(globals().get('stade_travaux_matches_restants', 0))
        tgt = globals().get('stade_travaux_cible', (ng_cur, ns_cur))
        (ng_t, ns_t) = ((int(tgt[0]), int(tgt[1])) if travaux else (ng_cur, ns_cur))

        if travaux:
            lib = "match" if rem == 1 else "matchs"
            titre_txt = f"Niveau {ng_cur}-{ns_cur}  ->  en travaux vers {ng_t}-{ns_t}  ({rem} {lib})"
            col_titre = (120, 70, 0)  # brun/orange
            TITRE_X_OFFSET = -350
            TITRE_Y_OFFSET = 50
            titre_travaux = POLICE_TITRE.render(titre_txt, True, col_titre)
            FENETRE.blit(titre_travaux, (425 + TITRE_X_OFFSET, 120 + TITRE_Y_OFFSET))

            total = int(globals().get('stade_travaux_duree_totale', rem if rem > 0 else 1))
            fait  = max(0, total - rem)
            ratio = max(0.0, min(1.0, fait / total)) if total > 0 else 0.0

            petite_font = pygame.font.SysFont("comicsansms", 18)
            txt = petite_font.render(f"Travaux : {fait}/{total} matchs (reste {rem})", True, (60, 40, 0))
            FENETRE.blit(txt, (425 + TITRE_X_OFFSET, 120 + TITRE_Y_OFFSET + 43))

            bar_x = 425 + TITRE_X_OFFSET
            bar_y = 130 + TITRE_Y_OFFSET + 36 + 26
            bar_w = 320
            bar_h = 12
            pygame.draw.rect(FENETRE, (220, 220, 220), (bar_x, bar_y, bar_w, bar_h), border_radius=6)
            fill_w = int(bar_w * ratio)
            if fill_w > 0:
                pygame.draw.rect(FENETRE, (0, 160, 80), (bar_x, bar_y, fill_w, bar_h), border_radius=6)
            pygame.draw.rect(FENETRE, (100, 100, 100), (bar_x, bar_y, bar_w, bar_h), 1, border_radius=6)

        # 🖼️ Image terrain à droite — simple & robuste (avec cas spéciaux 1-2, 1-3, 2-1)
        import os, math, pygame

        ng_cur = int(globals().get('niveau_global_jeu', 1))
        ns_cur = int(globals().get('niveau_stade', 1))

        surface = None
        rect = None

        # ✅ Cas spéciaux : images dédiées pour l’écran "Stade" AVANT upgrade
        special_files = {
            (1, 2): ("images/stade_121.png", "images/stade_121.jpg", "images/stade_121.PNG"),
            (1, 3): ("images/stade_131.png", "images/stade_131.jpg", "images/stade_131.PNG"),
            (2, 1): ("images/stade_212.png", "images/stade_212.jpg", "images/stade_212.PNG"),
        }
        paths = special_files.get((ng_cur, ns_cur))
        if paths:
            for p in paths:
                if os.path.exists(p):
                    try:
                        surface = pygame.image.load(p).convert()
                    except Exception:
                        surface = None
                    if isinstance(surface, pygame.Surface):
                        break

        # 1) surfaces préchargées (si rien trouvé plus haut)
        if not isinstance(surface, pygame.Surface):
            surface = (globals().get(f"stade_{ng_cur}{ns_cur}_img")
                       or globals().get(f"image_stade_{ng_cur}{ns_cur}")
                       or globals().get(f"stade_{ng_cur}_{ns_cur}_img")
                       or globals().get(f"image_stade_{ng_cur}_{ns_cur}"))

        # 2) fichiers génériques (si toujours rien)
        if not isinstance(surface, pygame.Surface):
            for path in (
                f"images/stade_{ng_cur}{ns_cur}.png",
                f"images/stade_{ng_cur}_{ns_cur}.png",
                f"images/image_stade_{ng_cur}{ns_cur}.png",
                f"images/image_stade_{ng_cur}_{ns_cur}.png",
                f"images/terrain_niveau{ng_cur}{ns_cur}.png",
                f"images/terrain_niveau{ng_cur}_{ns_cur}.png",
                f"images/terrain_niveau{ng_cur}-{ns_cur}.png",
            ):
                if os.path.exists(path):
                    try:
                        surface = pygame.image.load(path).convert()
                    except Exception:
                        surface = None
                    if isinstance(surface, pygame.Surface):
                        break

        # 3) Affichage (avec effet) + fallback garantissant 'rect'
        if isinstance(surface, pygame.Surface):
            largeur_base, hauteur_base = 330, 220
            scale = 1 + 0.10 * math.sin(pygame.time.get_ticks() / 700)
            nouvelle_largeur = int(largeur_base * scale)
            image_scaled = pygame.transform.scale(surface, (nouvelle_largeur, hauteur_base))
            rect = image_scaled.get_rect(center=(LARGEUR // 2 + 250, 400))
            FENETRE.blit(image_scaled, rect)
        else:
            temp = pygame.Surface((300, 210), pygame.SRCALPHA)
            temp.fill((200, 200, 200, 255))
            rect = temp.get_rect(center=(LARGEUR // 2 + 250, 400))
            FENETRE.blit(temp, rect)


        # Centrer le bouton sous l'image du terrain
        MARGIN_TOP = 12
        bouton_evolution_stade.centerx = rect.centerx
        bouton_evolution_stade.top = rect.bottom + MARGIN_TOP
        globals()['btn_stade_upgrade'] = bouton_evolution_stade

        # --- Bouton Évolution du stade (simple & robuste) ---
        try:
            nxt = stade_prochain_palier()
        except TypeError:
            # compat: si la signature attend (ng, ns)
            try:
                nxt = stade_prochain_palier(ng_cur, ns_cur)
            except Exception:
                nxt = None

        if travaux:
            pygame.draw.rect(FENETRE, GRIS_CLAIR, bouton_evolution_stade)
            pygame.draw.rect(FENETRE, NOIR, bouton_evolution_stade, 2)
            txt = FONT.render("Tvx en cours", True, NOIR)
            FENETRE.blit(txt, txt.get_rect(center=bouton_evolution_stade.center))
        elif nxt is not None:
            pygame.draw.rect(FENETRE, BLEU_FONCE, bouton_evolution_stade)
            pygame.draw.rect(FENETRE, NOIR, bouton_evolution_stade, 2)
            txt = FONT.render("Faire évoluer", True, BLANC)
            FENETRE.blit(txt, txt.get_rect(center=bouton_evolution_stade.center))
        else:
            pygame.draw.rect(FENETRE, GRIS_CLAIR, bouton_evolution_stade)
            pygame.draw.rect(FENETRE, NOIR, bouton_evolution_stade, 2)
            txt = FONT.render("Max atteint", True, NOIR)
            FENETRE.blit(txt, txt.get_rect(center=bouton_evolution_stade.center))

    elif zone_selectionnee == "boutique":
        titre_niveau = POLICE_TITRE.render(f"Niveau {niveau_global_jeu}-{niveau_stade}", True, NOIR)
        FENETRE.blit(titre_niveau, (425, 120))
        dessiner_boutique()

    elif zone_selectionnee == "parkings":
        ng = int(globals().get('niveau_global_jeu', 1))
        ns = int(globals().get('niveau_stade', 1))
        # 👇 Masquer le titre à 1-3, 2-1, 2-2 et 2-3
        hide_title = (ng == 1 and ns == 3) or (ng == 2 and ns in (1, 2, 3))
        if not hide_title:
            titre_niveau = POLICE_TITRE.render(f"Niveau {ng}-{ns}", True, NOIR)
            FENETRE.blit(titre_niveau, (425, 120))

        # 🔓 Déblocage cartes : même règle que pour l'onglet (et couvre 2-1)
        unlocked_parking = (ng > 1) or (ng == 1 and ns >= 3)

        if unlocked_parking:
            dessiner_parking()
        else:
            texte = FONT.render("À partir du Niveau 2-1.", True, NOIR)
            FENETRE.blit(texte, (LARGEUR // 2 - texte.get_width() // 2, 300))

    elif zone_selectionnee == "cafétéria":
        titre_niveau = POLICE_TITRE.render(f"Niveau {ng_cur}-{ns_cur}", True, NOIR)
        FENETRE.blit(titre_niveau, (425, 120))

        # Disponible seulement à partir de 1-3
        if (ng_cur, ns_cur) < (1, 3):
            texte = FONT.render("Cafétéria disponible à partir du Niveau 1.3", True, NOIR)
            FENETRE.blit(texte, (LARGEUR // 2 - texte.get_width() // 2, 300))
            return

        # Toujours afficher la cafétéria (plus de message “match extérieur”)
        try:
            _stock_cafe_bind()
        except Exception:
            pass

        dessiner_cafeteria()


    elif zone_selectionnee == "boutique":
        titre_niveau = POLICE_TITRE.render(f"Niveau {niveau_global_jeu}-{niveau_stade}", True, NOIR)
        FENETRE.blit(titre_niveau, (425, 120))
        dessiner_boutique()

    elif zone_selectionnee == "parkings":
        ng = int(globals().get('niveau_global_jeu', 1))
        ns = int(globals().get('niveau_stade', 1))
        # 👇 Masquer le titre à 1-3, 2-1, 2-2 et 2-3
        hide_title = (ng == 1 and ns == 3) or (ng == 2 and ns in (1, 2, 3))
        if not hide_title:
            titre_niveau = POLICE_TITRE.render(f"Niveau {ng}-{ns}", True, NOIR)
            FENETRE.blit(titre_niveau, (425, 120))
            
        # 🔓 Déblocage cartes : même règle que pour l'onglet (et couvre 2-1)
        unlocked_parking = (ng > 1) or (ng == 1 and ns >= 3)

        if unlocked_parking:
            dessiner_parking()
        else:
            texte = FONT.render("À partir du Niveau 2-1.", True, NOIR)
            FENETRE.blit(texte, (LARGEUR // 2 - texte.get_width() // 2, 300))



    # 4. 🔙 Bouton retour
    pygame.draw.rect(FENETRE, ROUGE, bouton_retour)
    FENETRE.blit(FONT.render("Menu", True, BLANC), (bouton_retour.x + 10, bouton_retour.y + 5))

    # [Garde] on ne montre PAS le bouton global quand on est sur l’onglet Parkings
    if str(globals().get('zone_selectionnee','')).lower() != "parkings":
        pygame.draw.rect(FENETRE, BLEU_FONCE, bouton_confirmer_stade)
        pygame.draw.rect(FENETRE, NOIR, bouton_confirmer_stade, 2)
        texte_confirmer = FONT.render("Confirmer", True, BLANC)
        texte_rect = texte_confirmer.get_rect(center=bouton_confirmer_stade.center)
        FENETRE.blit(texte_confirmer, texte_rect)
    globals()['bouton_confirmer_stade'] = bouton_confirmer_stade


    # [STADE][2.2] Bouton "Accélérer (8 tokens)" si des travaux sont en cours
    try:
        # Position/tailles simples ; ajuste si besoin
        x_btn, y_btn, w_btn, h_btn = 720, 520, 210, 38
        globals()['bouton_accel_travaux'] = pygame.Rect(x_btn, y_btn, w_btn, h_btn)

        # suppose qu'il existe une variable 'travaux_restants_matchs' (>0 si travaux en cours)
        r = int(globals().get("travaux_restants_matchs", 0))
        if r > 0:
            # fond + contour
            pygame.draw.rect(FENETRE, (240,230,255), bouton_accel_travaux, border_radius=8)
            pygame.draw.rect(FENETRE, (60,40,120),   bouton_accel_travaux, 2, border_radius=8)
            # libellé
            txt = POLICE_MOYENNE.render("Accélérer (8 tokens)", True, (40,20,80))
            FENETRE.blit(txt, (bouton_accel_travaux.x + 10, bouton_accel_travaux.y + 6))
    except Exception:
        pass

    # --- Popup tokens global si armé ---
    token_popup_draw_legacy(FENETRE) 



def dessiner_stade_upgrade():
    import pygame, os
    global stade_candidat, stade_options_rects
    global btn_upgrade_annuler, btn_upgrade_confirmer
    global stade_rects_non_cliquables
    global stade_13_img
    global stade_12_img
    global stade_upgrade_scroll_y, stade_upgrade_scroll_max
    if 'stade_upgrade_scroll_y' not in globals():
        stade_upgrade_scroll_y = 0
    stade_upgrade_scroll_max = 0  # recalculé à chaque frame


    HOVER_SCALE  = 1.22   # zoom au survol
    SELECT_SCALE = 1.15   # zoom quand sélectionné


    # --- listes de travail ---
    if 'stade_rects_non_cliquables' not in globals():
        stade_rects_non_cliquables = []
    else:
        stade_rects_non_cliquables.clear()

    if 'stade_options_rects' not in globals():
        stade_options_rects = []
    else:
        stade_options_rects.clear()

    # --- fond (identique à l'écran Stade) ---
    bg = globals().get("image_stade_img")
    if isinstance(bg, pygame.Surface):
        FENETRE.blit(bg, (0, 0))
    else:
        pygame.draw.rect(FENETRE, (235, 235, 235), (0, 0, LARGEUR, HAUTEUR))

    # --- titre ---
    titre = POLICE_TITRE.render("Évolution du stade", True, NOIR)
    FENETRE.blit(titre, titre.get_rect(center=(LARGEUR // 2, 60)))

    # --- sous-titre (niveau + capacité + entretien annuel) ---
    cap_actuelle = capacite_stade_niveaux.get(niveau_global_jeu, {}).get(niveau_stade, 0)
    cout_entretien = int(globals().get('COUT_ENTRETIEN_ANNUEL_NIVEAU1', 0))
    sous = POLICE_MOYENNE.render(
        f"Niveau actuel : {niveau_global_jeu}.{niveau_stade}   •   Capacité : {cap_actuelle:,} places   •   Coût entretien annuel : {cout_entretien:,} €".replace(",", " "),
        True, (60, 60, 60)
    )
    FENETRE.blit(sous, sous.get_rect(center=(LARGEUR // 2, 100)))

    # --- helpers données ---
    ng_actuel = int(globals().get('niveau_global_jeu', 1))
    ns_actuel = int(globals().get('niveau_stade', 1))
    ng_cur, ns_cur = ng_actuel, ns_actuel


    def _cap(ng, ns):
        d = globals().get('capacite_stade_niveaux', {})
        try:    return int(d[ng][ns])
        except: return 0

    def _cout(ng, ns):
        m = globals().get('cout_niveau_stade', {})
        try:    return int(m.get((ng, ns), 0))
        except: return 0

    def _ns_candidates_for_ng(ng):
        """Union des ns connus via capacités et coûts (robuste si une table manque)."""
        s = set()
        caps = globals().get('capacite_stade_niveaux', {}).get(ng, {})
        for k in caps.keys():
            try: s.add(int(k))
            except: pass
        m = globals().get('cout_niveau_stade', {})
        for (g, ns) in m.keys():
            if g == ng:
                try: s.add(int(ns))
                except: pass
        # (optionnel) si une autre table existe :
        ce = globals().get('cout_evolution_stade', {}).get(ng, {})
        for k in ce.keys():
            try: s.add(int(k))
            except: pass
        return sorted(s)

    # --- construction des options (4 paliers) ---
    ngs = set()
    ngs.update(list(globals().get('capacite_stade_niveaux', {}).keys()))
    ngs.update([g for (g, _) in globals().get('cout_niveau_stade', {}).keys()])
    ngs.update(list(globals().get('cout_evolution_stade', {}).keys()))
    ngs = sorted({int(x) for x in ngs})

    NB_PALIERS = 999  # (peut rester, mais plus nécessaire)
    options = []

    # 🔹 1) On collecte TOUS les (ng, ns) connus via les tables (capacités + coûts + éventuelle table cout_evolution_stade)
    options_raw = []
    for ng in ngs:
        for ns in _ns_candidates_for_ng(ng):
            options_raw.append((ng, ns, _cout(ng, ns), _cap(ng, ns)))

    # 🔹 2) Tri croissant (ng, ns) pour garder 1.1, 1.2, 1.3, 2.1, 2.2, 2.3, ...
    options_raw.sort(key=lambda t: (int(t[0]), int(t[1])))

    # 🔹 3) Déduplication au cas où les tables se recoupent
    seen = set()
    for ng, ns, cout, cap in options_raw:
        if (ng, ns) in seen:
            continue
        seen.add((ng, ns))
        options.append((ng, ns, cout, cap))

    # 🔹 4) Filet de sécurité (normalement inutile)
    if not options:
        options = []


    # --- logique de déverrouillage ---
    def _est_debloque(ng, ns):
        ng_cur = int(globals().get('niveau_global_jeu', 1))
        ns_cur = int(globals().get('niveau_stade', 1))

        # 1.x : 1.2 et 1.3 toujours cliquables
        if ng == 1 and ns in (2, 3):
            return True

        # 2.1 : débloqué si 1.3 finalisé
        if ng == 2 and ns == 1:
            return (ng_cur > 1) or (ng_cur == 1 and ns_cur >= 3)

        # 2.2 et 2.3 : débloqués dès que 2.1 est atteint
        if ng == 2 and ns in (2, 3):
            return (ng_cur > 2) or (ng_cur == 2 and ns_cur >= 1)

        # Autres cas : déverrouillés par défaut (future extension)
        return True



    # --- helper rendu cover (image plein cadre) ---
    def _blit_cover_to_rect(img, rect):
        iw, ih = img.get_size()
        rw, rh = rect.size
        if iw <= 0 or ih <= 0 or rw <= 0 or rh <= 0:
            return
        scale = max(rw / iw, rh / ih)
        new_size = (max(1, int(iw * scale)), max(1, int(ih * scale)))
        img2 = pygame.transform.smoothscale(img, new_size)
        ox = (new_size[0] - rw) // 2
        oy = (new_size[1] - rh) // 2
        sub = img2.subsurface(pygame.Rect(ox, oy, rw, rh))
        FENETRE.blit(sub, rect.topleft)

    # --- charger l'image plein-cadre pour les fiches 1.2, 1.3 (une seule fois) ---

    if 'stade_12_img' not in globals() or not isinstance(globals().get('stade_12_img'), pygame.Surface):
        stade_12_img = None
        for _cand in ("images/stade_12.png", "images/stade_12.jpg", "images/stade_12.jpeg"):
            if os.path.exists(_cand):
                try:
                    stade_12_img = pygame.image.load(_cand).convert_alpha()
                    break
                except Exception as e:
                    print(f"[stade] Échec chargement {_cand}: {e}")
                
    if 'stade_13_img' not in globals() or not isinstance(stade_13_img, pygame.Surface):
        stade_13_img = None
        for _cand in ("images/stade_13.png", "images/stade_13.jpg", "images/stade_13.jpeg"):
            if os.path.exists(_cand):
                try:
                    stade_13_img = pygame.image.load(_cand).convert_alpha()
                    break
                except Exception as e:
                    print(f"[stade] Échec chargement {_cand}: {e}")

    # --- mise en page (cartes) ---
    x0, y0 = 80, 150           # origine (coin haut-gauche) de la grille
    w, h = 410, 200            # **largeur & hauteur d’UNE carte**
    pas_x, pas_y = 460, 230    # pas horizontal/vertical entre cartes
    par_ligne = 2              # nombre de cartes par ligne

    color_border_sel = (0, 140, 0)
    color_border_nor = (0, 0, 0)

    mouse_pos = pygame.mouse.get_pos()

    if not any((ng == ng_cur and ns == ns_cur) for (ng, ns, _, _) in options):
        options.insert(0, (ng_cur, ns_cur, 0, _cap(ng_cur, ns_cur)))


    btn_y = HAUTEUR - 80
    viewport_top = y0
    viewport_bottom = btn_y - 20
    viewport_h = max(0, viewport_bottom - viewport_top)

    import math
    nb_lignes = math.ceil(len(options) / par_ligne) if par_ligne else 0
    content_bottom = y0 + (nb_lignes - 1) * pas_y + h if nb_lignes > 0 else y0
    content_h = max(0, content_bottom - viewport_top)

    stade_upgrade_scroll_max = max(0, content_h - viewport_h)
    stade_upgrade_scroll_y = max(0, min(stade_upgrade_scroll_y, stade_upgrade_scroll_max))

    globals()['stade_accel_rects'] = {}

    for i, (ng, ns, cout, cap) in enumerate(options):
        cx = x0 + (i % par_ligne) * pas_x
        cy = y0 + (i // par_ligne) * pas_y - stade_upgrade_scroll_y
        rect = pygame.Rect(cx, cy, w, h)

        # état
        est_sel    = bool(stade_candidat and stade_candidat[0] == ng and stade_candidat[1] == ns)
        est_locked = not _est_debloque(ng, ns)
        if est_locked:
            stade_rects_non_cliquables.append(rect)
        est_acquis = (ng < ng_cur) or (ng == ng_cur and ns <= ns_cur)

        # PAS de zoom si acquis
        hovered = rect.collidepoint(mouse_pos) and not est_locked and not est_acquis
        scale   = 1.0 if est_acquis else (SELECT_SCALE if est_sel else (HOVER_SCALE if hovered else 1.0))

        R = pygame.Rect(0, 0, int(w * scale), int(h * scale))
        R.center = rect.center
        

        # priorité : acquis > locked > normal
        if est_acquis:
            fill_color   = (255, 236, 200)   # orange très clair (lisible)
            border_color = (255, 140, 0)     # 🟧 orange visible
            col_t1 = (0, 90, 0)
            col_t2 = (30, 90, 30)
            col_t3 = (20, 70, 20)
            col_t4 = (30, 100, 30)
            try:
                globals()['stade_rects_non_cliquables'].append(rect)  # on évite tout "downgrade"
            except Exception:
                pass
        elif est_locked:
            fill_color   = (235, 235, 235)
            border_color = (150, 150, 150)
            col_t1 = (90, 90, 90)
            col_t2 = (110, 110, 110)
            col_t3 = (100, 100, 100)
            col_t4 = (130, 130, 130)
        else:
            fill_color   = BLANC
            border_color = color_border_sel if est_sel else color_border_nor
            col_t1 = NOIR
            col_t2 = (60, 60, 60)
            col_t3 = (30, 30, 30)
            col_t4 = (80, 80, 80)


        # rect "dessin" (agrandi), centré sur le rect logique (collision)
        R = pygame.Rect(0, 0, int(w * scale), int(h * scale))
        R.center = rect.center

        if hovered and not est_locked:
            shadow = pygame.Surface((R.w, R.h), pygame.SRCALPHA)
            shadow.fill((0, 0, 0, 40))
            FENETRE.blit(shadow, (R.x, R.y + 6))  # léger décalage vertical


        # fond
        pygame.draw.rect(FENETRE, fill_color, R, border_radius=14)

        # image full-card 1.2 / 1.3 (cover dans le rect agrandi)
        if ng == 1 and ns == 2 and isinstance(globals().get('stade_12_img'), pygame.Surface):
            _blit_cover_to_rect(stade_12_img, R)
        if ng == 1 and ns == 3 and isinstance(globals().get('stade_13_img'), pygame.Surface):
            _blit_cover_to_rect(stade_13_img, R)
        if ng == 2 and ns == 1 and isinstance(globals().get('stade_21_img'), pygame.Surface):
            _blit_cover_to_rect(stade_21_img, R)
        if ng == 2 and ns == 2 and isinstance(globals().get('stade_22_img'), pygame.Surface):
            _blit_cover_to_rect(stade_22_img, R)
        if ng == 2 and ns == 3 and isinstance(globals().get('stade_23_img'), pygame.Surface):
            _blit_cover_to_rect(stade_23_img, R)


        # voile gris si verrouillé
        if est_locked:
            overlay = pygame.Surface((R.w, R.h), pygame.SRCALPHA)
            overlay.fill((200, 200, 200, 160))
            FENETRE.blit(overlay, R.topleft)

        # bordure (sur R)
        pygame.draw.rect(FENETRE, border_color, R, 2, border_radius=14)

        # badge "Acquis" (sur R)
        if est_acquis:
            badge_rect = pygame.Rect(R.right - 76, R.y + 8, 68, 22)
            pygame.draw.rect(FENETRE, (0, 150, 0), badge_rect, border_radius=6)
            badge_txt = POLICE_PETITE.render("Acquis", True, BLANC)
            FENETRE.blit(badge_txt, badge_txt.get_rect(center=badge_rect.center))

        # textes (positions basées sur R)
        t1 = POLICE_GRANDE.render(f"Niveau {ng}.{ns}", True, col_t1)
        t1_rect = t1.get_rect(midtop=(R.centerx, R.y + 12))
        FENETRE.blit(t1, t1_rect)

        t2 = POLICE_MOYENNE_BOLD.render(f"Capacité : {cap:,} places".replace(",", " "), True, col_t2)
        FENETRE.blit(t2, (R.x + 16, R.y + 56))

        cout_str = f"{cout:,} €".replace(",", " ")
        t3 = POLICE_MOYENNE_BOLD.render(f"Coût : {cout_str}", True, col_t3)
        FENETRE.blit(t3, (R.x + 16, R.y + 90))

        try:
            duree = int(globals().get('duree_travaux_stade', {}).get((ng, ns), globals().get('DUREE_TRAVAUX_DEFAUT', 0)))
        except Exception:
            duree = globals().get('DUREE_TRAVAUX_DEFAUT', 0)
        t4 = POLICE_PETITE.render(f"Durée des tvx : {duree} matchs", True, col_t4)
        FENETRE.blit(t4, (R.x + 16, R.y + 125))

        # [ACCEL] Pastille (format Coach) — visible si carte non acquise ET non grisée
        try:
            cur_pair = (
                int(globals().get('niveau_global_jeu', 1)),
                int(globals().get('niveau_stade', 1))
            )
            is_not_reached = (ng, ns) > cur_pair

            grey_map = globals().get('stade_cards_grey', {})  # si tu gères un “état grisé”
            is_grey  = bool(grey_map.get((ng, ns), False))

            if is_not_reached and not is_grey:
                tokens_map = globals().get('TOKENS_ACCEL_STADE_BY_LEVEL', {})
                TOKENS_PER_MATCH = int(tokens_map.get((ng, ns), globals().get('TOKENS_ACCEL_STADE', 40)))

                # même taille/couleur que Coachs
                pill = show_accel_pill_left(FENETRE, R, amount=TOKENS_PER_MATCH)

                # publier la zone cliquable ; le handler décidera de l’action
                accel_rects = globals().setdefault('stade_accel_rects', {})
                accel_rects[(ng, ns)] = pill
        except Exception:
            pass


        # zone cliquable (tuple inchangé)
        stade_options_rects.append((rect, (ng, ns, cout, cap)))


    # --- petite barre de scroll à droite (optionnel) ---
    track_x = LARGEUR - 18
    track_y = viewport_top
    track_h = viewport_h
    if content_h > 0 and track_h > 20:
        pygame.draw.rect(FENETRE, (220, 220, 220), (track_x, track_y, 6, track_h), border_radius=3)
        # taille du "pouce" proportionnelle à la fenêtre
        thumb_h = max(24, int(track_h * (track_h / (content_h + 1))))
        # position du pouce en fonction du scroll
        ratio = 0 if stade_upgrade_scroll_max == 0 else (stade_upgrade_scroll_y / stade_upgrade_scroll_max)
        thumb_y = track_y + int((track_h - thumb_h) * ratio)
        pygame.draw.rect(FENETRE, (140, 140, 140), (track_x, thumb_y, 6, thumb_h), border_radius=3)

    
    # --- boutons bas ---
    btn_y = HAUTEUR - 80
    btn_upgrade_annuler  = pygame.Rect(80,  btn_y, 180, 46)
    btn_upgrade_confirmer = pygame.Rect(LARGEUR - 80 - 200, btn_y, 200, 46)

    draw_bouton_3D(btn_upgrade_annuler, (200, 60, 60), "Annuler")
    draw_bouton_3D(btn_upgrade_confirmer, (0, 120, 0), "Confirmer")

    globals()['btn_upgrade_annuler']   = btn_upgrade_annuler
    globals()['btn_upgrade_confirmer'] = btn_upgrade_confirmer  


    # --- aide ---
    aide = POLICE_PETITE.render("Clique une carte pour sélectionner un palier, puis 'Confirmer'.", True, (80, 80, 80))
    FENETRE.blit(aide, aide.get_rect(center=(LARGEUR // 2, btn_y - 20)))




def a_gagne_4_matchs_consecutifs(historique, nom_equipe):
    compteur = 0
    for match in reversed(historique):
        resultat = match.get("texte", "")
        if nom_equipe in resultat and "Victoire" in resultat:
            compteur += 1
            if compteur >= 4:
                return True
        else:
            compteur = 0  # remet à zéro dès qu'une défaite ou autre
    return False

def a_gagne_4_matchs_consecutifs_courante(historique, nom_equipe):
    """Vérifie 4V d'affilée sur la SAISON COURANTE uniquement."""
    start = int(globals().get('index_debut_saison', 0) or 0)
    h2 = [m for m in historique[start:]
          if isinstance(m, dict) and not (m.get("type") == "tournoi" or "frais_inscription" in m)]
    return a_gagne_4_matchs_consecutifs(h2, nom_equipe)





