def dessiner_tableau_classement_sans_fond(
    classement, nom_equipe,
    x_depart=100, y_depart=98,
    largeur_colonne=105, hauteur_ligne=32,
    police=POLICE_CLASSEMENT
):
    titres = ["Pos.", "Équipe", "Points", "Vict.", "Déf.", "Nuls"]

    # Titres de colonnes
    for i, titre in enumerate(titres):
        rect = pygame.Rect(x_depart + i * largeur_colonne, y_depart, largeur_colonne, hauteur_ligne)
        pygame.draw.rect(FENETRE, BLEU_FONCE, rect)
        pygame.draw.rect(FENETRE, NOIR, rect, 2)
        texte = police.render(titre, True, BLANC)
        texte_rect = texte.get_rect(center=rect.center)
        FENETRE.blit(texte, texte_rect)

    # Contenu du tableau
    for idx, equipe_data in enumerate(classement):
        y = y_depart + (idx + 1) * hauteur_ligne

        if idx < 2:
            couleur_fond = (100, 255, 100)
        elif idx >= len(classement) - 2:
            couleur_fond = (255, 150, 150)
        else:
            couleur_fond = BLANC

        if equipe_data['nom'] == nom_equipe:
            police_utilisee = pygame.font.SysFont("comicsansms", 18, bold=True)
        else:
            police_utilisee = police


        for col_idx, key in enumerate(["position", "nom", "points", "victoires", "defaites", "matchs_nuls"]):
            rect = pygame.Rect(x_depart + col_idx * largeur_colonne, y, largeur_colonne, hauteur_ligne)
            pygame.draw.rect(FENETRE, couleur_fond, rect)
            pygame.draw.rect(FENETRE, NOIR, rect, 1)

            texte_val = str(idx + 1) if key == "position" else str(equipe_data.get(key, ""))
            texte = police_utilisee.render(texte_val, True, NOIR)
            texte_rect = texte.get_rect(center=rect.center)
            FENETRE.blit(texte, texte_rect)


def _get_missions_bg():
    """Charge et met en cache le fond Missions (essaie plusieurs variantes)."""
    import pygame, os
    cached = globals().get('__MISSIONS_BG__', None)
    if cached is not None:
        return cached

    candidates = [
        "images/missions.png",
        "images/missions_bg.png",
        "images/Missions.png",
        "images/MISSIONS.png",
        "images/missions.jpg",
        "images/missions.jpeg",
    ]
    img = None
    for p in candidates:
        try:
            if os.path.isfile(p):
                img = pygame.image.load(p).convert_alpha()
                break
        except Exception:
            continue

    globals()['__MISSIONS_BG__'] = img  # cache (None si rien trouvé)
    return img



def dessiner_pre_playoffs():
    import pygame, math
    F = globals().get("FENETRE")
    LARGEUR = int(globals().get("LARGEUR", 1280))
    HAUTEUR = int(globals().get("HAUTEUR", 720))
    ballon = globals().get("ballon_img")
    if not (F and ballon):
        return

    # fond sombre
    F.fill((8, 10, 26))

    # Titre PLAY-OFFS (sans effet)
    POLICE_TITRE = globals().get("POLICE_TITRE") or pygame.font.SysFont("comicsansms", 48, bold=True)
    titre_txt = "PLAY-OFFS"
    surf    = POLICE_TITRE.render(titre_txt, True, (255,255,255))
    outline = POLICE_TITRE.render(titre_txt, True, (13,71,255))
    orc = outline.get_rect(center=(LARGEUR//2, int(HAUTEUR*0.28)))
    F.blit(outline, orc.move(0,2)); F.blit(surf, surf.get_rect(center=orc.center))

    # Halo simple dessiné (pas d'image)
    halo_r = 140
    halo = pygame.Surface((halo_r*2, halo_r*2), pygame.SRCALPHA)
    for i in range(halo_r, 0, -1):
        a = max(0, min(120, int(120 * (i/halo_r) ** 2)))
        pygame.draw.circle(halo, (20, 80, 255, a//2), (halo_r, halo_r), i)
        pygame.draw.circle(halo, (255, 255, 255, a//3), (halo_r, halo_r), i//2)
    halo_y = int(HAUTEUR*0.72)

    # Pulsation douce du ballon
    now = pygame.time.get_ticks()/1000.0
    scale = 1.0 + 0.03*math.sin(now*2*math.pi/1.5)
    ball = pygame.transform.rotozoom(ballon, 0, 0.9*scale)
    b_rect = ball.get_rect(center=(LARGEUR//2, halo_y))

    # Blits
    F.blit(halo, halo.get_rect(center=b_rect.center))
    F.blit(ball, b_rect)

    # Label CTA
    POLICE_MOYENNE_BOLD = globals().get("POLICE_MOYENNE_BOLD") or pygame.font.SysFont("comicsansms", 24, bold=True)
    label = POLICE_MOYENNE_BOLD.render("ENTRER EN PLAY-OFFS", True, (230,235,255))
    F.blit(label, label.get_rect(midtop=(b_rect.centerx, b_rect.bottom + 14)))

    # zone cliquable exportée (toujours définie)
    globals()['bouton_playoffs_ball_rect'] = b_rect



def dessiner_menu_saison():
    global titres_saison, rects_saison, zone_selectionnee_saison, ballon_rect
    global fleche_decalage, fleche_base_y, etat, resultats_matchs_complets
    global bouton_tournois
    global afficher_message_findesaison, message_findesaison_img, message_findesaison_close_rect
    global afficher_message_capacite_limitee, message_capacite_limitee_close_rect
    global zone_match, rect_allermatch
    global prochain_adversaire, croix_fermeture_calendrier
    global panel_calendrier_rect, hauteur_contenu_calendrier, decalage_scroll_calendrier
    global popup_victoire_4matchs_affichee, afficher_message_4_victoires

    rect_allermatch = None

