# === TOKENS POPUP (helper générique) =========================================
def token_popup_open_modern(amount:int, title:str="Confirmer le paiement", subtitle:str="", on_ok:str="", payload:dict=None):
    """API moderne (titre/sous-titre) — conserve les mêmes globals 'modernes'."""
    globals()['TOK_POPUP_ACTIVE'] = True
    globals()['TOK_POPUP_AMOUNT'] = int(amount or 0)
    globals()['TOK_POPUP_TITLE']  = title or "Confirmer le paiement"
    globals()['TOK_POPUP_SUB']    = subtitle or ""
    globals()['TOK_POPUP_ON_OK']  = on_ok or ""
    globals()['TOK_POPUP_DATA']   = dict(payload or {})

# Alias propre : toutes tes nouvelles utilisations peuvent continuer d’appeler token_popup_open(...)
token_popup_open = token_popup_open_modern


def token_popup_draw(surface):
    """Dessine le popup si actif. Publie btns OK/Cancel dans les globals."""
    if not globals().get('TOK_POPUP_ACTIVE'):
        globals()['TOK_BTN_OK'] = None
        globals()['TOK_BTN_NO'] = None
        return

    import pygame
    W = int(globals().get("LARGEUR", 1280))
    H = int(globals().get("HAUTEUR", 720))

    # overlay
    ov = pygame.Surface((W, H), pygame.SRCALPHA)
    ov.fill((0,0,0,120))
    surface.blit(ov, (0,0))

    bw, bh = 520, 220
    rx = (W - bw)//2
    ry = (H - bh)//2
    rect = pygame.Rect(rx, ry, bw, bh)

    # panneau
    pygame.draw.rect(surface, (245,245,245), rect, border_radius=14)
    pygame.draw.rect(surface, (25,25,25), rect, 2, border_radius=14)

    # textes
    try:
        fbig  = POLICE_MOYENNE
        fbody = pygame.font.SysFont("comicsansms", 20)
    except Exception:
        fbig  = pygame.font.SysFont(None, 28, bold=True)
        fbody = pygame.font.SysFont(None, 22)

    title = str(globals().get('TOK_POPUP_TITLE') or "Confirmer le paiement")
    sub   = str(globals().get('TOK_POPUP_SUB') or "")
    amt   = int(globals().get('TOK_POPUP_AMOUNT') or 0)

    # Titre
    t = fbig.render(title, True, (20,20,20))
    surface.blit(t, t.get_rect(midtop=(rect.centerx, rect.y+16)))

    # Sous-texte (montant)
    sub_txt = f"Dépenser {amt} tokens ?"
    if sub:
        sub_txt = f"{sub}\n{amt} tokens"
    y_sub = rect.y + 64
    for line in sub_txt.split("\n"):
        s = fbody.render(line, True, (50,50,50))
        surface.blit(s, s.get_rect(midtop=(rect.centerx, y_sub)))
        y_sub += s.get_height()+6

    # icône token (optionnel)
    icon = (globals().get('img_token') or globals().get('token_img') or globals().get('icon_token'))
    if icon:
        try:
            ih = 28
            iw = int(icon.get_width()*ih/icon.get_height())
            ico = pygame.transform.smoothscale(icon, (iw, ih))
            surface.blit(ico, (rect.centerx - iw//2, rect.y + bh - 90))
        except Exception:
            pass

    # boutons
    btn_w, btn_h, gap = 160, 44, 30
    bx1 = rect.centerx - btn_w - gap//2
    bx2 = rect.centerx + gap//2
    by  = rect.bottom - btn_h - 16

    btn_ok = pygame.Rect(bx1, by, btn_w, btn_h)
    btn_no = pygame.Rect(bx2, by, btn_w, btn_h)

    pygame.draw.rect(surface, (40,150,60), btn_ok, border_radius=10)
    pygame.draw.rect(surface, (20,80,30),  btn_ok, 2, border_radius=10)
    surface.blit(fbody.render("Oui, payer", True, (255,255,255)),
                 fbody.render("Oui, payer", True, (255,255,255)).get_rect(center=btn_ok.center))

    pygame.draw.rect(surface, (180,60,60), btn_no, border_radius=10)
    pygame.draw.rect(surface, (90,30,30),  btn_no, 2, border_radius=10)
    surface.blit(fbody.render("Annuler", True, (255,255,255)),
                 fbody.render("Annuler", True, (255,255,255)).get_rect(center=btn_no.center))

    # publier pour le handler
    globals()['TOK_BTN_OK'] = btn_ok
    globals()['TOK_BTN_NO'] = btn_no



