def clic_dans_cercle(pos, centre, rayon):
    dx = pos[0] - centre[0]
    dy = pos[1] - centre[1]
    return dx*dx + dy*dy <= rayon*rayon

def sauvegarder_jeu():
    """
    Sauvegarde non destructive de l'état du jeu (squelette).
    Écrit un petit snapshot JSON sans modifier l'état global.
    """
    try:
        import json, os, datetime
    except Exception:
        try:
            import json, os  # type: ignore
        except Exception:
            return
        datetime = None  # type: ignore

    g = globals()
    snapshot = {}

    # Quelques infos clés (on pourra enrichir plus tard)
    try:
        snapshot["numero_saison"] = int(g.get("numero_saison", 1))
    except Exception:
        pass
    try:
        snapshot["journee_courante"] = int(g.get("journee_courante", 0))
    except Exception:
        pass
    try:
        # BRIQUE 1 – ancrage du calendrier temps réel dans le profil
        # On fige la date/heure de départ de la saison (J1) dans le snapshot.
        sdt = g.get("saison_start_datetime", None)
        if not sdt:
            # fallback : on prend la valeur utilisée par le calendrier temps réel
            sdt = g.get("SAISON_START_DATETIME_STR", None)
        if sdt:
            snapshot["saison_start_datetime"] = str(sdt)
    except Exception:
        pass

    try:
        snapshot["nom_equipe"] = str(g.get("nom_equipe", "") or "")
        snapshot["alias_manager"] = str(g.get("alias_manager", "") or "")
    except Exception:
        pass
    try:
        snapshot["TOKENS"] = int(g.get("TOKENS", 0))
    except Exception:
        pass
    try:
        snapshot["budget"] = float(g.get("budget", 0))
    except Exception:
        pass

    # --- BRIQUE 2 : effectif & sélection ---
    def _sanitize_joueur_for_save(j):
        clean = {}
        for k, v in j.items():
            lk = str(k).lower()

            # On ignore toute info purement UI / technique (rects, surfaces, etc.)
            if "rect" in lk or "surface" in lk or lk.startswith("_"):
                continue

            # Types simples JSON-compatibles
            if isinstance(v, (int, float, str, bool)) or v is None:
                clean[k] = v

            # Listes / tuples de types simples
            elif isinstance(v, (list, tuple)):
                if all(isinstance(x, (int, float, str, bool)) or x is None for x in v):
                    clean[k] = list(v)

            # Petits dictionnaires simples (ex: sous-stats)
            elif isinstance(v, dict):
                if all(
                    isinstance(kk, str)
                    and (isinstance(vv, (int, float, str, bool)) or vv is None)
                    for kk, vv in v.items()
                ):
                    clean[k] = dict(v)

        return clean

    try:
        joueurs = g.get("joueurs", [])
        if isinstance(joueurs, list):
            snapshot["joueurs"] = [_sanitize_joueur_for_save(j) for j in joueurs]
    except Exception:
        pass

    try:
        eq_sav = g.get("equipe_sauvegardee", None)
        if isinstance(eq_sav, (set, list, tuple)):
            snapshot["equipe_sauvegardee"] = list(eq_sav)
    except Exception:
        pass



    # Historique des matchs (si présent et cohérent)
    try:
        hist = g.get("historique_matchs", [])
        if isinstance(hist, list):
            snapshot["historique_matchs"] = hist
    except Exception:
        pass

    # Classement (si présent et cohérent)
    try:
        cl = g.get("classement", None)
        if isinstance(cl, (list, dict)):
            snapshot["classement"] = cl
    except Exception:
        pass

        # --- BRIQUE 4 : missions & progression ---
    # On stocke uniquement des types JSON-compatibles (pas de set, pas de tuple, pas d’objets pygame)
    try:
        st = dict(g.get("missions_state") or {})
        ms = {}

        # Mission courante : on ne sauvegarde que l'ID
        cur = st.get("current")
        cur_id = None
        if isinstance(cur, dict):
            cur_id = cur.get("id")
        elif isinstance(cur, str):
            cur_id = cur
        if cur_id:
            ms["current_id"] = cur_id

        # Missions terminées
        comp = st.get("completed", [])
        if isinstance(comp, (list, tuple, set)):
            ms["completed"] = list(comp)

        # Compteurs
        counters = st.get("counters", {})
        if isinstance(counters, dict):
            safe_counters = {}
            for k, v in counters.items():
                try:
                    safe_counters[str(k)] = int(v)
                except Exception:
                    continue
            if safe_counters:
                ms["counters"] = safe_counters

        if ms:
            snapshot["missions_state"] = ms
    except Exception:
        pass

    try:
        prog = dict(g.get("MISSIONS_PROGRESS") or {})
        mp = {}

        done = prog.get("done", set())
        if isinstance(done, (list, tuple, set)):
            mp["done"] = list(done)

        inprog = prog.get("in_progress", set())
        if isinstance(inprog, (list, tuple, set)):
            mp["in_progress"] = list(inprog)

        sel = prog.get("selected", None)
        if sel is not None:
            mp["selected"] = sel

        if mp:
            snapshot["MISSIONS_PROGRESS"] = mp
    except Exception:
        pass


    # --- BRIQUE 3 : infrastructures (stade + parkings) ---
    try:
        snapshot["niveau_global_jeu"] = int(g.get("niveau_global_jeu", 1))
    except Exception:
        pass
    try:
        snapshot["niveau_stade"] = int(g.get("niveau_stade", 1))
    except Exception:
        pass
    try:
        snapshot["stade_travaux_en_cours"] = bool(g.get("stade_travaux_en_cours", False))
        snapshot["stade_travaux_left"] = int(g.get("stade_travaux_left", 0))
    except Exception:
        pass

    try:
        snapshot["niveau_parking"] = int(g.get("niveau_parking", 0))
    except Exception:
        pass
    try:
        snapshot["parking_travaux_en_cours"] = bool(g.get("parking_travaux_en_cours", False))
        snapshot["parking_travaux_left"] = int(g.get("parking_travaux_left", 0))
    except Exception:
        pass

        # --- BRIQUE 5 : staff (coach + kiné + recruteur) ---
    try:
        staff = {}

        # Coach
        staff["COACH_TIER"] = int(g.get("COACH_TIER", 0))
        staff["COACH_ENABLED"] = bool(g.get("COACH_ENABLED", False))
        staff["coach_contract_active"] = bool(g.get("coach_contract_active", False))
        staff["coach_contract_remaining"] = int(g.get("coach_contract_remaining", 0))
        staff["coach_contract_tier"] = int(g.get("coach_contract_tier", 0) or 0)
        staff["coach_contract_salary"] = int(g.get("coach_contract_salary", 0) or 0)
        lbl_coach = g.get("coach_contract_label")
        if isinstance(lbl_coach, str):
            staff["coach_contract_label"] = lbl_coach

        # Kiné
        staff["KINE_TIER"] = int(g.get("KINE_TIER", 0))
        staff["KINE_ENABLED"] = bool(g.get("KINE_ENABLED", False))
        staff["kine_contract_active"] = bool(g.get("kine_contract_active", False))
        staff["kine_contract_remaining"] = int(g.get("kine_contract_remaining", 0))
        staff["kine_contract_tier"] = int(g.get("kine_contract_tier", 0) or 0)
        staff["kine_contract_salary"] = int(g.get("kine_contract_salary", 0) or 0)
        lbl_kine = g.get("kine_contract_label")
        if isinstance(lbl_kine, str):
            staff["kine_contract_label"] = lbl_kine

        # Overrides déblocage
        staff["KINE_UNLOCKED_OVERRIDE"] = bool(g.get("KINE_UNLOCKED_OVERRIDE", False))
        staff["RECRUTEUR_UNLOCKED_OVERRIDE"] = bool(g.get("RECRUTEUR_UNLOCKED_OVERRIDE", False))

        # Sous-onglet staff courant (pour revenir sur le bon onglet)
        sub = g.get("staff_submenu")
        if isinstance(sub, str):
            staff["staff_submenu"] = sub

        # On ne pose la clé que si on a vraiment quelque chose
        if staff:
            snapshot["staff_state"] = staff
    except Exception:
        pass

        # --- BRIQUE 6 : billetterie & boutique ---
    try:
        # Billetterie : prix et nombres de places saisis
        sb = globals().get("saisies_billet", None)
        if isinstance(sb, (list, tuple)):
            snapshot["saisies_billet"] = [str(v) for v in sb]

        sp = globals().get("saisies_places", None)
        if isinstance(sp, (list, tuple)):
            snapshot["saisies_places"] = [str(v) for v in sp]

        # Boutique : prix et stock
        spb = globals().get("saisies_prix_boutique", None)
        if isinstance(spb, (list, tuple)):
            snapshot["saisies_prix_boutique"] = [str(v) for v in spb]

        stock_bout = globals().get("stock_boutique", None)
        if isinstance(stock_bout, dict):
            safe_stock = {}
            for k, v in stock_bout.items():
                try:
                    safe_stock[str(k)] = int(v)
                except Exception:
                    continue
            snapshot["stock_boutique"] = safe_stock
    except Exception:
        pass

        # --- BRIQUE 7 : cafétéria ---
    try:
        # Cumul de la cafétéria (nouvelle clé, après migration douce)
        try:
            snapshot["recettes_cafeteria_cumulees"] = int(
                globals().get("recettes_cafeteria_cumulees", 0) or 0
            )
        except Exception:
            pass

        # Prévision en cours (au cas où une prévision existe entre deux matchs)
        try:
            snapshot["prevision_cafeteria"] = int(
                globals().get("prevision_cafeteria", 0) or 0
            )
        except Exception:
            pass

        # Dernier match cafétéria (uniquement pour l'affichage dans Finances)
        try:
            snapshot["recettes_match_cafeteria"] = int(
                globals().get("recettes_match_cafeteria", 0) or 0
            )
        except Exception:
            pass
    except Exception:
        pass

    # --- BRIQUE 8 : tournois & coupes ---
    try:
        td = g.get("tournois_disponibles", None)
        if isinstance(td, dict):
            # Dict déjà composé uniquement de types simples (str, int, list, dict)
            snapshot["tournois_disponibles"] = td
    except Exception:
        pass

    try:
        ta = g.get("tournoi_actif", None)
        if isinstance(ta, str):
            snapshot["tournoi_actif"] = ta
    except Exception:
        pass

    try:
        niv = g.get("niveau_tournoi_selectionne", None)
        if isinstance(niv, str):
            snapshot["niveau_tournoi_selectionne"] = niv
    except Exception:
        pass

    try:
        snapshot["tournoi_a_deja_lance"] = bool(g.get("tournoi_a_deja_lance", False))
    except Exception:
        pass

    try:
        snapshot["mon_equipe_a_gagne_le_tournoi"] = bool(g.get("mon_equipe_a_gagne_le_tournoi", False))
    except Exception:
        pass

    # --- BRIQUE 9 : archives finances (captures salle des trophées) ---
    try:
        snaps = g.get("finance_snapshots", None)
        if isinstance(snaps, dict):
            # Copie défensive pour éviter les alias surprises
            snapshot["finance_snapshots"] = dict(snaps)
    except Exception:
        pass

    # --- BRIQUE 10 : salle des trophées ---
    try:
        trophies = g.get("TROPHIES", None)
        if isinstance(trophies, dict):
            # Dict déjà composé de types simples (int, bool, str, list, dict)
            # → JSON-safe
            snapshot["TROPHIES"] = trophies
    except Exception:
        pass

        # --- BRIQUE 11 : progression du club (XP & niveau) ---
    try:
        snapshot["CLUB_LEVEL"] = int(g.get("CLUB_LEVEL", 1))
    except Exception:
        pass
    try:
        snapshot["CLUB_XP"] = int(g.get("CLUB_XP", 0))
    except Exception:
        pass
    try:
        snapshot["CLUB_XP_SAISON"] = int(g.get("CLUB_XP_SAISON", 0))
    except Exception:
        pass

    # --- BRIQUE 12 : messages & alertes --------------------------------------
    # 1) Boîte de réception (liste de messages)
    try:
        msgs = g.get("messages_recus", [])
        if isinstance(msgs, list):
            # on force une vraie liste JSON-friendly
            snapshot["messages_recus"] = list(msgs)
    except Exception:
        pass

    # 2) Set des popups déjà archivés → liste de clés (JSON)
    try:
        deja = g.get('_messages_popup_deja_enregistres', None)
        if isinstance(deja, set):
            snapshot["_messages_popup_deja_enregistres_keys"] = sorted(str(k) for k in deja)
    except Exception:
        pass

    # 3) Flags tutoriels / popups persistants
    try:
        # Popup de bienvenue Gestion déjà affiché ?
         snapshot["popup_gestion_deja_affiche"] = bool(g.get("popup_gestion_deja_affiche", False))
         
         # Badge "nouveau tutoriel" sur l’icône Messages (True = non lu)
         snapshot["tutoriel_messages_non_lu"] = bool(g.get("tutoriel_messages_non_lu", False))
    except Exception:
        pass

        # --- BRIQUE 13 : sponsoring (contrat & historique) -----------------------
    # 1) Contrat de sponsor en cours
    try:
        snapshot["sponsor_actif"] = str(g.get("sponsor_actif", "") or "")
    except Exception:
        pass

    try:
        snapshot["sponsor_duree_restante"] = int(g.get("sponsor_duree_restante", 0) or 0)
    except Exception:
        pass

    try:
        snapshot["montant_sponsor_actuel"] = int(g.get("montant_sponsor_actuel", 0) or 0)
    except Exception:
        pass

    try:
        snapshot["recettes_sponsors"] = int(g.get("recettes_sponsors", 0) or 0)
    except Exception:
        pass

    # 2) Historique des sponsors signés (nom, montant)
    try:
        lst = g.get("sponsors_signes", [])
        if isinstance(lst, list):
            safe = []
            for item in lst:
                try:
                    nom, montant = item
                except Exception:
                    continue
                safe.append([str(nom), int(montant)])
            snapshot["sponsors_signes"] = safe
    except Exception:
        pass


    # --- BRIQUE 3.2 : sélection automatique du profil actif à partir alias/nom_equipe ---
    try:
        alias = str(g.get("alias_manager", "") or "").strip()
        team  = str(g.get("nom_equipe", "") or "").strip()

        if alias or team:
            # On construit une clé technique simple à partir de l'alias et/ou du nom d'équipe
            base = f"{alias}_{team}" if alias else team
            base = base.lower()

            # On ne garde que [a-z0-9] et on remplace le reste par "_"
            safe_chars = []
            for ch in base:
                if ("a" <= ch <= "z") or ("0" <= ch <= "9"):
                    safe_chars.append(ch)
                else:
                    safe_chars.append("_")

            profil_suggere = "".join(safe_chars).strip("_")

            # Si on a une clé non vide, on la pose comme profil actif
            if profil_suggere:
                g["profil_actif_id"] = profil_suggere
    except Exception:
        # On ne casse jamais la sauvegarde si quelque chose se passe mal ici
        pass



    # Horodatage (si datetime disponible)
    try:
        snapshot["saved_at"] = datetime.datetime.now().isoformat()  # type: ignore
    except Exception:
        pass

    # Écriture sur disque (structure multi-profils, rétro-compatible)
    try:
        base_dir = os.path.dirname(__file__)  # type: ignore
    except Exception:
        base_dir = "."
    path = os.path.join(base_dir, "savegame.json")  # type: ignore

    # Prépare la structure à écrire
    data_to_write = None
    try:
        # 1) On essaie de charger l'éventuel fichier existant
        current = {}
        try:
            with open(path, "r", encoding="utf-8") as f:
                current = json.load(f)
        except FileNotFoundError:
            current = {}
        except Exception:
            current = {}

        # 2) Si c'est déjà un conteneur multi-profils, on le réutilise
        if isinstance(current, dict) and isinstance(current.get("profils"), dict):
            root = current
        else:
            # Ancien format "flat" : on encapsule l'ancien snapshot
            root = {
                "version": 2,
                "profils": {},
            }
            if isinstance(current, dict) and current:
                # On garde l'ancien snapshot sous la clé "default"
                root["profils"]["default"] = current

        # 3) Profil courant (technique) – pour l'instant un seul slot "default"
        profil_id = str(g.get("profil_actif_id", "") or "") or "default"

        # On met à jour ce profil avec le snapshot courant
        root["profils"][profil_id] = snapshot
        root["profil_courant"] = profil_id

        data_to_write = root
    except Exception:
        # En cas de souci, on retombe sur l'ancien comportement : on écrit le snapshot seul
        data_to_write = snapshot

    try:
        with open(path, "w", encoding="utf-8") as f:
            json.dump(data_to_write, f, ensure_ascii=False, indent=2)
        print("[SAVE] Snapshot de la partie écrit dans", path)
    except Exception as e:
        print("[SAVE][ERR][write]", e)

        

def charger_jeu():
    """
    Charge la dernière sauvegarde depuis savegame.json.
    Ne modifie PAS l'état global : renvoie simplement un dict (ou {}).
    """
    try:
        import json, os
    except Exception:
        print("[SAVE][ERR] Impossible d'importer json / os pour charger_jeu")
        return {}

    # Même logique de chemin que dans sauvegarder_jeu()
    try:
        base_dir = os.path.dirname(__file__)  # type: ignore
    except Exception:
        base_dir = "."
    path = os.path.join(base_dir, "savegame.json")  # type: ignore

    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
    except FileNotFoundError:
        print("[SAVE] Aucun fichier de sauvegarde trouvé :", path)
        return {}
    except Exception as e:
        print("[SAVE][ERR][read]", e)
        try:
            import json as _json, os as _os
            if isinstance(e, _json.JSONDecodeError):
                backup = path + ".corrupt"
                try:
                    _os.replace(path, backup)
                    print("[SAVE][ERR] savegame.json corrompu, déplacé vers", backup)
                except Exception as e2:
                    print("[SAVE][ERR][backup]", e2)
        except Exception:
            pass

        return {}

    # Sélection du snapshot à partir d'un éventuel conteneur multi-profils
    snap = data
    profil_id_charge = None  # [BRIQUE 3.1] id du profil effectivement utilisé
    
    try:
        if isinstance(data, dict) and isinstance(data.get("profils"), dict):
            profils = data.get("profils") or {}
            profil_id = str(data.get("profil_courant") or "") or "default"

            if profil_id not in profils and profils:
                # Fallback : premier profil existant
                try:
                    profil_id = sorted(profils.keys())[0]
                except Exception:
                    profil_id = next(iter(profils.keys()))

            snap = profils.get(profil_id, {})
            profil_id_charge = profil_id
    except Exception:
        snap = data

    # [BRIQUE 3.1] Mémoriser le profil actif pour les prochaines sauvegardes
    try:
        if profil_id_charge:
            globals()["profil_actif_id"] = str(profil_id_charge)
    except Exception:
        pass

    # Nettoyage léger sur les nouvelles clés structurées
    try:
        if "historique_matchs" in snap and not isinstance(snap.get("historique_matchs"), list):
            snap["historique_matchs"] = list(snap.get("historique_matchs") or [])
    except Exception:
        pass

    try:
        if "classement" in snap and not isinstance(snap.get("classement"), (list, dict)):
            snap["classement"] = snap.get("classement") or []
    except Exception:
        pass

    print("[SAVE] Chargement réussi depuis", path)
    return snap


# --- [SAVE][BRIQUE 3.2] Utilitaires multi-profils (liste + chargement ciblé) ---

def lister_profils_disponibles():
    """
    Retourne la liste des profils présents dans savegame.json.

    Format de retour :
    [
        {
            "id": "default",
            "nom_equipe": "...",
            "alias_manager": "...",
            "saved_at": "...",
            "numero_saison": 1,
        },
        ...
    ]

    Ne modifie PAS l'état global.
    """
    try:
        import json, os
    except Exception:
        print("[SAVE][ERR] Impossible d'importer json / os pour lister_profils_disponibles")
        return []

    # Même logique de chemin que sauvegarder_jeu() / charger_jeu()
    try:
        base_dir = os.path.dirname(__file__)  # type: ignore
    except Exception:
        base_dir = "."
    path = os.path.join(base_dir, "savegame.json")  # type: ignore

    # Lecture brute du fichier
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
    except FileNotFoundError:
        # Aucun fichier → aucun profil disponible
        return []
    except Exception as e:
        print("[SAVE][ERR][read-list]", e)
        return []

    # Cas ancien format "flat" (pas encore de conteneur multi-profils)
    if not isinstance(data, dict) or not isinstance(data.get("profils"), dict):
        snap = data if isinstance(data, dict) else {}
        if not snap:
            return []
        return [{
            "id": "default",
            "nom_equipe": str(snap.get("nom_equipe", "") or ""),
            "alias_manager": str(snap.get("alias_manager", "") or ""),
            "saved_at": str(snap.get("saved_at", "") or ""),
            "numero_saison": int(snap.get("numero_saison") or 1),
        }]

    # Cas conteneur multi-profils
    profils = data.get("profils") or {}
    result = []
    for pid, snap in profils.items():
        if not isinstance(snap, dict):
            continue
        try:
            result.append({
                "id": str(pid),
                "nom_equipe": str(snap.get("nom_equipe", "") or ""),
                "alias_manager": str(snap.get("alias_manager", "") or ""),
                "saved_at": str(snap.get("saved_at", "") or ""),
                "numero_saison": int(snap.get("numero_saison") or 1),
            })
        except Exception:
            continue

    return result


def charger_profil(profil_id):
    """
    Charge un profil précis depuis savegame.json.
    Ne modifie PAS l'état global, renvoie simplement un dict (ou {}).

    Cette fonction servira pour l’écran « Choisir le joueur ».
    """
    try:
        import json, os
    except Exception:
        print("[SAVE][ERR] Impossible d'importer json / os pour charger_profil")
        return {}

    # Même logique de chemin que sauvegarder_jeu() / charger_jeu()
    try:
        base_dir = os.path.dirname(__file__)  # type: ignore
    except Exception:
        base_dir = "."
    path = os.path.join(base_dir, "savegame.json")  # type: ignore

    # Lecture du fichier
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
    except FileNotFoundError:
        print("[SAVE] Aucun fichier de sauvegarde trouvé pour charger_profil :", path)
        return {}
    except Exception as e:
        print("[SAVE][ERR][read-profil]", e)
        try:
            import json as _json, os as _os
            if isinstance(e, _json.JSONDecodeError):
                backup = path + ".corrupt"
                try:
                    _os.replace(path, backup)
                    print("[SAVE][ERR] savegame.json corrompu (profil), déplacé vers", backup)
                except Exception as e2:
                    print("[SAVE][ERR][backup-profil]", e2)
        except Exception:
            pass
        return {}

    snap = {}
    pid = str(profil_id or "")
    try:
        if isinstance(data, dict) and isinstance(data.get("profils"), dict):
            profils = data.get("profils") or {}
            if pid in profils:
                snap = profils.get(pid, {}) or {}
            else:
                # Fallback : même logique que charger_jeu()
                try:
                    snap = charger_jeu()
                except Exception:
                    snap = {}
        else:
            # Ancien format : fallback sur le comportement standard
            try:
                snap = charger_jeu()
            except Exception:
                snap = {}
    except Exception:
        try:
            snap = charger_jeu()
        except Exception:
            snap = {}

    if not isinstance(snap, dict):
        return {}

    # Nettoyage léger identique à charger_jeu()
    try:
        if "historique_matchs" in snap and not isinstance(snap.get("historique_matchs"), list):
            snap["historique_matchs"] = list(snap.get("historique_matchs") or [])
    except Exception:
        pass

    try:
        if "classement" in snap and not isinstance(snap.get("classement"), (list, dict)):
            snap["classement"] = snap.get("classement") or []
    except Exception:
        pass

    print(f"[SAVE] Profil '{pid}' chargé (charger_profil)")
    return snap




