def dessiner_gestion():
    global gestion_boutons
    FENETRE.blit(terrain3, (0, 0))
    global popularite

        # Afficher le nom de l'équipe en haut
    police_titre_gestion = pygame.font.SysFont("comicsansms", 48, bold=True)
    titre_gestion = police_titre_gestion.render("Management du Club :", True, BLANC)
    titre_rect = titre_gestion.get_rect(center=(LARGEUR // 2, 50))
    FENETRE.blit(titre_gestion, titre_rect)

    texte_nom = POLICE_TITRE.render(nom_equipe, True, BLANC)
    x_nom = titre_rect.right + 20   # 20 px de marge
    y_nom = titre_rect.y + (titre_rect.height // 2 - texte_nom.get_height() // 2)  # centré verticalement avec le titre
    FENETRE.blit(texte_nom, (x_nom, y_nom))
    
    zones = [
        ("Sponsors", None, "sponsors"),
        ("Finances", None, "finances"),
        ("Aller au Game", None, "transferts"),
        ("Calendrier", None, "calendrier"),
        ("Stade", None, "stade"),
        ("Equipe", None, "selection"),
        ("Messages", None, "messages"),
    ]

    # Affiche le rond "Staff" uniquement quand le niveau Coach est accessible
    try:
         _club_lvl = int(globals().get("CLUB_LEVEL", 1))
    except Exception:
        _club_lvl = 1
    try:
        _staff_coach_min = int(globals().get("STAFF_COACH_MIN_LEVEL", 1))
    except Exception:
        _staff_coach_min = 1
 
    if _club_lvl >= _staff_coach_min:
        # Insérer Staff juste avant "Messages" pour garder l'ordre visuel
        zones.insert(6, ("Staff", None, "staff"))

    # ➕ Débloque le cercle "Trophées" à partir de la Saison 2
    try:
        _saison_cur = int(globals().get('numero_saison', 1))
    except Exception:
        _saison_cur = 1
    if _saison_cur >= 2:
        zones.append(("Trophées", None, "trophees"))


    nb_zones = len(zones)
    angle_entre_zones = 360 / nb_zones  # espacement régulier en degrés

    centre_cercle = (LARGEUR // 2, HAUTEUR // 2 + 50)  # centre du cercle des boutons
    rayon_cercle = 200  # rayon du cercle imaginaire où sont disposés les boutons
    rayon_bouton = 50  # rayon des cercles boutons


    images_dict = {
        "transferts": ballon_img,
        "finances": image_finance,
        "sponsors": image_sponsors,
        "stade": image_stadebasket,
        "calendrier": image_calendrier_gestion,
        "selection": joueurs2_img,
        "staff": staff_img,
        "trophees": coupe_icon_img,
        "messages": icon_gestion_messages,
    }
    
    mouse_pos = pygame.mouse.get_pos()

    for i, (texte, _, zone) in enumerate(zones):
        angle_deg = i * angle_entre_zones - 90  # démarre en haut
        angle_rad = math.radians(angle_deg)
        x = int(centre_cercle[0] + rayon_cercle * math.cos(angle_rad))
        y = int(centre_cercle[1] + rayon_cercle * math.sin(angle_rad))
        centre = (x, y)

        # Zoom si souris dessus
        distance_souris = math.hypot(mouse_pos[0] - x, mouse_pos[1] - y)
        zoom_max = 1.3  # facteur d'agrandissement max
        zoom_zone = 100  # zone d'effet autour du bouton en pixels

        if distance_souris < zoom_zone:
            facteur_zoom = 1 + (zoom_max - 1) * (1 - distance_souris / zoom_zone)
            rayon_affiche = int(rayon_bouton * facteur_zoom)
        else:
            facteur_zoom = 1
            rayon_affiche = rayon_bouton

        gestion_boutons.append((centre, rayon_affiche, zone))

        # Ombre avec rayon zoomé
        ombre_offset = 5
        pygame.draw.circle(FENETRE, (180, 180, 180), (x + ombre_offset, y + ombre_offset), rayon_affiche)

        # Cercle blanc du bouton avec rayon zoomé
        pygame.draw.circle(FENETRE, BLANC, centre, rayon_affiche)

        # Contour noir avec rayon zoomé
        pygame.draw.circle(FENETRE, NOIR, centre, rayon_affiche, 3)

        # Image centrée (taille adaptée par zoom)
        if zone in images_dict and images_dict[zone] is not None:
            img = images_dict[zone]
            taille_img_base = img.get_width()

            # 🔍 On agrandit légèrement l'enveloppe dans le bouton "Messages"
            facteur_img = facteur_zoom
            if zone == "messages":
                facteur_img *= 1.10  # +10% (ajuste à 1.08 / 1.12 si besoin)

            taille_img_zoom = int(taille_img_base * facteur_img)
            img_redim = pygame.transform.smoothscale(img, (taille_img_zoom, taille_img_zoom))
            img_rect = img_redim.get_rect(center=centre)
            FENETRE.blit(img_redim, img_rect)

            # --- Badge "nouveau tutoriel" clignotant en haut-gauche du rond Messages ---
            if zone == "messages" and globals().get("tutoriel_messages_non_lu", False):
                try:
                    temps_actuel = pygame.time.get_ticks()
                    periode = int(globals().get("clignotement_vitesse", 300) or 300)
                    clignoter = ((temps_actuel // periode) % 2 == 0)

                    if clignoter:
                        # Position légèrement superposée en haut-gauche du cercle
                        bx = int(centre[0] - rayon_affiche * 0.55)
                        by = int(centre[1] - rayon_affiche * 0.55)
                        rayon_badge = max(8, int(rayon_bouton * 0.32))

                        # Fond du badge
                        pygame.draw.circle(FENETRE, ROUGE, (bx, by), rayon_badge)
                        pygame.draw.circle(FENETRE, BLANC, (bx, by), rayon_badge, 2)

                        # Petit "!" au centre du badge
                        try:
                            font_badge = pygame.font.SysFont("comicsansms", 18, bold=True)
                        except Exception:
                            font_badge = FONT
                        if font_badge:
                            txt_excl = font_badge.render("!", True, BLANC)
                            rect_excl = txt_excl.get_rect(center=(bx, by))
                            FENETRE.blit(txt_excl, rect_excl)
                except Exception:
                    pass


        # Affichage bulle rectangulaire au survol
        if distance_souris < rayon_affiche:
            # Taille de la bulle en fonction du texte
            padding_x, padding_y = 10, 5
            texte_bulle = FONT.render(texte, True, NOIR)
            bulle_rect = texte_bulle.get_rect()
            bulle_rect.inflate_ip(padding_x*2, padding_y*2)
            bulle_rect.midbottom = (centre[0], centre[1] - rayon_affiche - 10)

            # Calculer le point sur le bord du cercle dans la direction vers la bulle
            bulle_pos = (bulle_rect.centerx, bulle_rect.bottom)
            vect_x = bulle_pos[0] - centre[0]
            vect_y = bulle_pos[1] - centre[1]
            distance_vect = math.hypot(vect_x, vect_y)

            if distance_vect != 0:
                bord_x = centre[0] + (vect_x / distance_vect) * rayon_affiche
                bord_y = centre[1] + (vect_y / distance_vect) * rayon_affiche
            else:
                bord_x, bord_y = centre

            pygame.draw.line(FENETRE, BLANC, (bord_x, bord_y), bulle_pos, 2)
        
            # Fond bulle
            pygame.draw.rect(FENETRE, BLANC, bulle_rect, border_radius=5)
            # Texte bulle
            FENETRE.blit(texte_bulle, (bulle_rect.left + padding_x, bulle_rect.top + padding_y))

    # [GESTION][HUD] Cartouche centrale permanente (Tokens / Lv / XP) – fond translucide, 3 lignes
    try:
        cx, cy = LARGEUR // 2, HAUTEUR // 2 + 50  # centre du cercle des menus
        font18 = pygame.font.SysFont("comicsansms", 18, bold=True)

        t   = int(globals().get("TOKENS", 0))
        lvl = int(globals().get("CLUB_LEVEL", 1))
        xp  = int(globals().get("CLUB_XP", 0))

        # 1) Surfaces de texte (2 lignes)
        line1 = font18.render(f"Tokens : {t}", True, BLANC)
        line2 = font18.render(f"Lv : {lvl}   /   XP : {xp}", True, BLANC)

        # 2) Dimensions auto (largeur mini, sinon s’adapte au contenu)
        pad_x, pad_y = 12, 10
        gap = 6
        maxw   = max(line1.get_width(), line2.get_width())
        box_w  = max(220, maxw + 2*pad_x)             # largeur mini 220
        box_h  = line1.get_height() + line2.get_height() + gap + 2*pad_y

        box = pygame.Rect(0, 0, box_w, box_h)
        box.center = (cx, cy)

        # 3) Fond semi-transparent + bord
        overlay = pygame.Surface((box.w, box.h), pygame.SRCALPHA)
        pygame.draw.rect(overlay, MAUVE_HUD, overlay.get_rect(), border_radius=12) 
        FENETRE.blit(overlay, box.topleft)
        pygame.draw.rect(FENETRE, NOIR, box, 2, border_radius=12)


        # 4) Blit des 2 lignes
        x_text = box.x + pad_x
        y_text = box.y + pad_y
        FENETRE.blit(line1, (x_text, y_text))
        y_text += line1.get_height() + gap
        FENETRE.blit(line2, (x_text, y_text))
    except Exception:
        pass

    # [GESTION][COACH] désactivé ici — gestion uniquement via l’écran Staff
    globals()['btn_coach_toggle'] = None
    globals()['btn_coach_upgrade'] = None


    # Exemple : à la fin de dessiner_gestion()
    texte_pop = pygame.font.SysFont("comicsansms", 22, bold=True).render(f"Popularité : {popularite} / 100", True, BLANC)
    FENETRE.blit(texte_pop, (LARGEUR - 260, HAUTEUR - 615))

    # [GESTION] Bouton "Sauvegarder la partie"
    try:
        bw, bh = 220, 32
        bx = LARGEUR - bw - 30
        by = HAUTEUR - 80
        bouton_sauvegarde = pygame.Rect(bx, by, bw, bh)
        globals()["bouton_sauvegarde_gestion"] = bouton_sauvegarde

        pos_souris = pygame.mouse.get_pos()
        survol = bouton_sauvegarde.collidepoint(pos_souris)
        col_fond = (20, 110, 35) if survol else (10, 80, 25)

        pygame.draw.rect(FENETRE, col_fond, bouton_sauvegarde, border_radius=10)
        libelle_save = POLICE_CLASSEMENT.render("Sauvegarder la partie", True, BLANC)
        lib_rect_save = libelle_save.get_rect(center=bouton_sauvegarde.center)
        FENETRE.blit(libelle_save, lib_rect_save)

        # [GESTION] Bouton Mute Musique (ON/OFF) juste au-dessus de "Sauvegarder"
        try:
            mw, mh = 160, 28
            mx = LARGEUR - mw - 30
            my = by - mh - 10  # au-dessus du bouton sauvegarde

            bouton_mute = pygame.Rect(mx, my, mw, mh)
            globals()["bouton_mute_musique_gestion"] = bouton_mute

            pos_souris_m = pygame.mouse.get_pos()
            survol_m = bouton_mute.collidepoint(pos_souris_m)

            muted = bool(globals().get("MUSIC_MUTE", False))
            if muted:
                col_bg_m = (90, 90, 90) if survol_m else (60, 60, 60)
                label_txt = "Musique OFF"
            else:
                col_bg_m = (20, 80, 140) if survol_m else (10, 50, 90)
                label_txt = "Musique ON"

            pygame.draw.rect(FENETRE, col_bg_m, bouton_mute, border_radius=10)
            libelle_mute = POLICE_CLASSEMENT.render(label_txt, True, BLANC)
            lib_rect_mute = libelle_mute.get_rect(center=bouton_mute.center)
            FENETRE.blit(libelle_mute, lib_rect_mute)
        except Exception:
            pass

        # --- [GESTION] Toast "Partie sauvegardée : heure et jour" juste au-dessus du bouton ---
        try:
            now = pygame.time.get_ticks()
            msg = globals().get("ui_flash_msg", "")
            until = int(globals().get("ui_flash_until", 0))

            if msg and now < until:
                font_toast = globals().get("POLICE_PETITE") or FONT
                txt = font_toast.render(msg, True, BLANC)

                pad_x, pad_y = 10, 6
                box = txt.get_rect()
                box.inflate_ip(pad_x * 2, pad_y * 2)

                # Position : juste au-dessus du bouton sauvegarde
                box.midbottom = (bouton_sauvegarde.centerx, bouton_sauvegarde.top - 10)

                overlay = pygame.Surface((box.w, box.h), pygame.SRCALPHA)
                overlay.fill((0, 0, 0, 170))  # fond noir semi-transparent
                FENETRE.blit(overlay, box.topleft)
                FENETRE.blit(txt, (box.x + pad_x, box.y + pad_y))
        except Exception:
            pass
    except Exception:
        pass

    couleur_menu = (200, 50, 50) if bouton_retour.collidepoint(pygame.mouse.get_pos()) else ROUGE
    pygame.draw.rect(FENETRE, couleur_menu, bouton_retour)
    FENETRE.blit(FONT.render("Menu", True, BLANC), (bouton_retour.x + 10, bouton_retour.y - 50))
     

