def formater_euros(valeur):
    try:
        return f"{int(valeur):,} €".replace(",", ".")
    except:
        return str(valeur)

def _capture_finances_snapshot():
    """
    Rend l'écran 'Finances' sur une surface hors-écran puis sauve un PNG.
    Retourne le chemin du fichier si OK, sinon None.
    - Aucun impact visuel (on restaure FENETRE après rendu).
    - Tolérant aux erreurs (fallback : capture de l'écran courant si possible).
    """
    try:
        import os, time, pygame
        # Saison écoulée que l'on archive (clé de l'image)
        s_prev = int(globals().get('saison_courante', globals().get('numero_saison', 1)))

        # Surface cible (mêmes dimensions que la fenêtre affichée si possible)
        screen = globals().get('FENETRE', None)
        if screen and hasattr(screen, "get_size"):
            w, h = screen.get_size()
        else:
            # Taille de secours si FENETRE n'est pas prête
            w = int(globals().get('LARGEUR', 1200))
            h = int(globals().get('HAUTEUR', 800))

        surf = pygame.Surface((w, h))
        old = globals().get('FENETRE', None)

        # Rendu hors-écran : on redirige temporairement FENETRE
        globals()['FENETRE'] = surf
        try:
            # Si la fonction existe, on dessine l'écran finances complet
            if 'dessiner_finances' in globals() and callable(globals()['dessiner_finances']):
                globals()['dessiner_finances']()
            else:
                # Fallback ultra simple si l'écran finances n'est pas disponible
                surf.fill((245, 245, 245))
                font = (globals().get('POLICE_PETITE') or globals().get('FONT') or pygame.font.SysFont(None, 22))
                t1 = font.render("Archive Finance (fallback)", True, (40,40,40))
                t2 = font.render(time.strftime("%Y-%m-%d %H:%M:%S"), True, (80,80,80))
                surf.blit(t1, (20, 20))
                surf.blit(t2, (20, 50))
        except Exception:
            # Si le rendu hors-écran échoue, dernier recours : copier l'écran actuel
            try:
                if old:
                    surf.blit(old, (0, 0))
            except Exception:
                pass
        finally:
            # Toujours restaurer la fenêtre principale
            globals()['FENETRE'] = old

        # Sauvegarde du PNG
        os.makedirs("captures", exist_ok=True)
        path = os.path.join("captures", f"finance_saison_{s_prev}.png")
        pygame.image.save(surf, path)

        # Enregistre/garantit l'entrée dans finance_snapshots
        snaps = globals().setdefault('finance_snapshots', {})
        snaps[s_prev] = path

        return path
    except Exception:
        return None



def _sponsor_rollover_tick():
    """À appeler à chaque nouvelle saison : décrémente la durée.
       À 0 => libère seulement l'état visuel."""
    try:
        d = int(globals().get('sponsor_duree_restante', 0))
    except Exception:
        d = 0
    if d > 0:
        d -= 1
        globals()['sponsor_duree_restante'] = d
        if d <= 0:
            globals()['sponsor_actif'] = ""


    
def dessiner_sponsors():
    global sponsors_boutons
    global sponsor_actif
    FENETRE.blit(fond_sponsors_img, (0, 0))
    sponsors_boutons = []

    # ✅ Etat global UI
    try:
        _d_left = int(globals().get('sponsor_duree_restante', 0))
    except Exception:
        _d_left = 0
    _actif_nom = (globals().get('sponsor_actif') or "").strip()
    _contrat_en_cours = bool(_actif_nom) and (_d_left > 0)

    # 🔧 État visuel minimal : si la durée est expirée/absente, aucune carte n'est "active"
    try:
        d = int(globals().get('sponsor_duree_restante', 0))
    except Exception:
        d = 0
        globals()['sponsor_duree_restante'] = 0  # normalise proprement
    if d <= 0:
        if globals().get('sponsor_actif'):
            globals()['sponsor_actif'] = ""   # cartes redeviennent cliquables

    titre = POLICE_TITRE.render("Offres de Sponsors", True, NOIR)
    FENETRE.blit(titre, (LARGEUR // 2 - titre.get_width() // 2, 30))

    # Calcul total salaires actuel de l'équipe sélectionnée
    eq = globals().get("equipe") or globals().get("equipe_sauvegardee") or []

    try:
        indices = list(eq)
    except Exception:
        indices = []

    total_salaires = sum(
        int(joueurs[i]['salaire'].replace(' €', '').replace('.', '').replace(' ', ''))
        for i in indices
        if 0 <= i < len(joueurs)
    )
    cible_sponsoring = int(total_salaires * 0.6)

    def _lbl_bonus(nom):
        b  = SPONSOR_BONUS_PO.get(nom, {})
        bf = int(b.get("finale", 0))
        bc = int(b.get("champion", 0))
        if bf > 0 and bc > 0:
            return f"Si en Finale -> +{bf//1000}k€ ; Si Champion -> +{bc//1000}k€"
        elif bf > 0:
            return f"Si en Finale -> +{bf//1000}k€"
        elif bc > 0:
            return f"Si Champion -> +{bc//1000}k€"
        else:
            return "Aucun"

    sponsors_disponibles = [
        ("Gatorade", 2, _lbl_bonus("Gatorade")),
        ("Nike",     1, _lbl_bonus("Nike")),
        ("Red Bull", 3, _lbl_bonus("Red Bull")),
        ("Adidas",   2, _lbl_bonus("Adidas")),
    ]
        

    x = 100
    y = 120
    largeur_case = 600
    hauteur_case = 80
    espacement = 30

    # Affiche l’info d’état SANS toucher au global
    if _contrat_en_cours:
        texte_duree = FONT.render(
            f"Sponsor actif : {_actif_nom} ({_d_left} saison(s) restante(s))",
            True, VERT
        )
        FENETRE.blit(texte_duree, (LARGEUR // 2 - texte_duree.get_width() // 2, 80))


    for nom, duree, bonus in sponsors_disponibles:
        montant_base = cible_sponsoring

        # Pondération selon durée du contrat, corrigée selon ta logique précise
        if duree == 1:
            montant_total = int(montant_base * 1.0)   # contrat court = un peu plus généreux
        elif duree == 2:
            montant_total = int(montant_base * 0.8)   # 20% de moins par saison
        elif duree == 3:
            montant_total = int(montant_base * 0.7)   # long terme, moins par saison
        else:
            montant_total = montant_base

        rect = pygame.Rect(x, y, largeur_case, hauteur_case)

        # --- Etat visuel cohérent pendant toute la durée du contrat ---
        _est_actif  = _contrat_en_cours and (nom == _actif_nom)
        _est_lock   = _contrat_en_cours and (nom != _actif_nom)

        # 1) Couleur de fond
        if _contrat_en_cours:
            couleur = VERT_CLAIR if _est_actif else GRIS
        else:
            couleur = VERT_CLAIR if (sponsor_selectionne == nom) else ORANGE_CLAIR

        # 2) Dessin de la carte
        pygame.draw.rect(FENETRE, couleur, rect, border_radius=10)
        pygame.draw.rect(FENETRE, NOIR, rect, 2, border_radius=10)


        # 5) Textes (toujours lisibles)
        texte_nom = POLICE_GRANDE.render(nom, True, NOIR)
        texte_duree = POLICE_MOYENNE.render(f"{duree} an(s)", True, NOIR)
        texte_montant = POLICE_MOYENNE.render(formater_euros(montant_total) + "/saison", True, NOIR)
        texte_bonus = POLICE_PETITE.render(f"Bonus : {bonus}", True, (80, 80, 80))

        FENETRE.blit(texte_nom, (x + 20, y + 10))
        FENETRE.blit(texte_duree, (x + 250, y + 10))
        FENETRE.blit(texte_montant, (x + 400, y + 10))
        FENETRE.blit(texte_bonus, (x + 20, y + 45))

        # 6) Boutons cliquables (inchangé)
        sponsors_boutons.append((rect, nom, duree, montant_total, bonus))


        y += hauteur_case + espacement

    # Bouton Retour
    pygame.draw.rect(FENETRE, ROUGE, bouton_retour)
    pygame.draw.rect(FENETRE, NOIR, bouton_retour, 2)
    FENETRE.blit(FONT.render("Retour", True, BLANC), (bouton_retour.x + 10, bouton_retour.y + 5))

    # Bouton "Confirmer" -> grisé et inactif si un contrat est en cours
    try:
        _d_left = int(globals().get('sponsor_duree_restante', 0))
    except Exception:
        _d_left = 0
    sponsor_actif = globals().get('sponsor_actif') if _d_left > 0 else ""
    _ui_contrat_en_cours = (_d_left > 0) and bool(sponsor_actif)

    if 'bouton_confirmer_sponsor' in globals() and bouton_confirmer_sponsor:
        if _contrat_en_cours:
            pygame.draw.rect(FENETRE, GRIS, bouton_confirmer_sponsor)
            pygame.draw.rect(FENETRE, NOIR, bouton_confirmer_sponsor, 2)
            lab = FONT.render(f"Contrat actif", True, NOIR)
            FENETRE.blit(lab, lab.get_rect(center=bouton_confirmer_sponsor.center))
        elif globals().get('sponsor_selectionne'):
            pygame.draw.rect(FENETRE, BLEU_FONCE, bouton_confirmer_sponsor)
            pygame.draw.rect(FENETRE, NOIR, bouton_confirmer_sponsor, 2)
            lab = FONT.render("Confirmer", True, BLANC)
            FENETRE.blit(lab, lab.get_rect(center=bouton_confirmer_sponsor.center))



