# --- 🟧 3. Initialisation du tournoi ---
def initialiser_tournoi_coupe():
    global total_recettes, total_depenses
    global niveau_tournoi_selectionne, tournoi_actif

    if niveau_tournoi_selectionne is None:
        print("⚠️ Aucun niveau sélectionné.")
        return  # 🔁 On sort sans rien faire

    print("🎯 TOURNOI LANCÉ :", tournoi_actif, "-", niveau_tournoi_selectionne)

    t_global = tournois_disponibles[tournoi_actif]
    t = t_global["niveaux"][niveau_tournoi_selectionne]

    # Si tournoi déjà terminé, ne pas relancer
    if t.get("etat") == "termine":
        print("❌ Ce tournoi est déjà terminé.")
        return

    # Sinon, initialisation normale
    nb_equipes = NB_EQUIPE_TOURNOI[niveau_tournoi_selectionne]
    equipes_possibles = [e for e in noms_equipes_possibles if e != nom_equipe]
    participantes = [nom_equipe] + random.sample(equipes_possibles, nb_equipes - 1)
    random.shuffle(participantes)

    premier_tour = [(participantes[i], participantes[i + 1]) for i in range(0, nb_equipes, 2)]

    t["equipes"] = participantes
    t["matchs"] = [premier_tour]
    t["tour_actuel"] = 0
    t["resultats"] = []
    t["vainqueur"] = ""
    t["classement"] = []

    # Mise à jour des états
    t["etat"] = "en_cours"
    t_global["etat"] = "en_cours"  # État global peut être utilisé pour l'ensemble du tournoi
    print("✅ Tournoi initialisé :", niveau_tournoi_selectionne)

        


def simuler_tournoi_coupe():
    global total_recettes
    global niveau_tournoi_selectionne
    global tournoi_a_deja_lance
    tournoi_a_deja_lance = True
    global total_depenses
    global etat
    global mon_equipe_a_gagne_le_tournoi
    mon_equipe_a_gagne_le_tournoi = False
    global gain



    t_global = tournois_disponibles[tournoi_actif]
    t = t_global["niveaux"][niveau_tournoi_selectionne]

    tour = t["tour_actuel"]

    if tour >= len(t["matchs"]):
        print("✅ Fin du tournoi atteinte — aucun match à simuler")
        return  # On sort proprement, plus rien à simuler

    matchs = t["matchs"][tour]
    resultats = []

    for equipe1, equipe2 in matchs:
        s1 = random.randint(70, 100)
        s2 = random.randint(70, 100)

            # Bonus de profondeur simple pour mon équipe si elle joue
        if equipe1 == nom_equipe or equipe2 == nom_equipe:
            if len(equipe) > 5:
                bonus_profondeur = (len(equipe) - 5) * 0  # +1 points par remplaçant
                if equipe1 == nom_equipe:
                    s1 += bonus_profondeur
                else:
                    s2 += bonus_profondeur
                    
        while s1 == s2:
            s1 += random.randint(1, 5)
            
        resultats.append((equipe1, equipe2, s1, s2))

    if len(t["resultats"]) <= tour:
        t["resultats"].append([])

    for e1, e2, s1, s2 in resultats:
        score = f"{s1} - {s2}"
        t["resultats"][tour].append(score)

    gagnants = [e1 if s1 > s2 else e2 for e1, e2, s1, s2 in resultats]

    if len(gagnants) == 1:
        t["etat"] = "termine"
        final = resultats[0]
        gagnant = final[0] if final[2] > final[3] else final[1]
        perdant = final[1] if gagnant == final[0] else final[0]

        t["vainqueur"] = gagnant
        classement_tournoi = [gagnant, perdant] + [e for e in t["equipes"] if e not in (gagnant, perdant)]
        t["classement"] = classement_tournoi
        tournois_disponibles[tournoi_actif]["niveaux"][niveau_tournoi_selectionne]["etat"] = "termine"

        # --- CREDIT TOURNOI (UNIQUE & CONSISTENT) ---
        niv = str(niveau_tournoi_selectionne)
        gentry = GAINS_TOURNOI_PAR_NIVEAU.get(niv, {})

        # support dict {"vainqueur":..., "finaliste":...} OU int simple
        if isinstance(gentry, dict):
            gain_vainqueur = int(gentry.get("vainqueur", 0))
            gain_finaliste = int(gentry.get("finaliste", 0))
        else:
            gain_vainqueur = int(gentry)
            gain_finaliste = 0

        # ✅ Ton équipe était-elle VRAIMENT en finale ?
        final_pair = (final[0], final[1])              # équipes finalistes
        team_in_final = same_team(final_pair[0], nom_equipe) or same_team(final_pair[1], nom_equipe)
        me_gagne = team_in_final and same_team(gagnant, nom_equipe)
        me_final = team_in_final and (not me_gagne) and same_team(perdant, nom_equipe)

        gain_tournoi = gain_vainqueur if me_gagne else (gain_finaliste if me_final else 0)

        # ⬇️ Marque explicitement la finale pour les autres écrans (utile à l’affichage)
        t["phase"] = "finale"
        t["A"] = final[0]
        t["B"] = final[1]

        # ✅ On n'ouvre la fenêtre "victoire_tournoi" ET on ne crédite un gain
        #    QUE si notre équipe est gagnante ou finaliste (sinon… rien)
        if (me_gagne or me_final):
            if gain_tournoi and not t.get("gain_credite"):
                t["gain_credite"] = True       # anti-doublon si la fonction repasse
                # Effets visuels/logs
                if me_gagne:
                    mon_equipe_a_gagne_le_tournoi = True
                    try:
                        generer_confettis_popup()
                    except Exception:
                        pass
                    print(f"🏆 Gagné ! +{gain_tournoi:,} €".replace(",", "."))
                elif me_final:
                    print(f"🥈 Finaliste. +{gain_tournoi:,} €".replace(",", "."))

                # --- PERSISTENCE TROPHÉE TOURNOI (non destructif, normalisé, sans doublon) ---
            try:
                # 1) Enregistrement synthétique (dernier état) dans TROPHIES["tournois"]
                _tour  = TROPHIES.setdefault("tournois", {})
                _niv_raw = str(niveau_tournoi_selectionne or "").lower()
                if "début" in _niv_raw or "debut" in _niv_raw:
                    _niv = "debutant"
                elif "inter" in _niv_raw:
                    _niv = "intermediaire"
                else:
                    _niv = "elite"
                _key = f"{tournoi_actif}_{_niv}"          # ex: "printemps_intermediaire"
                _val = "vainqueur" if me_gagne else ("finaliste" if me_final else "")
                if _val:
                    _tour[_key] = _val

                # 2) Historique cumulatif (affichage multi-saisons) dans TROPHIES["tournois_hist"]
                _hist = TROPHIES.setdefault("tournois_hist", [])
                _meta = TROPHIES.setdefault("_meta", {})
                # Saison réelle (ex: si on a déjà basculé en S+1, on recolle à S)
                _slabel = int(globals().get("saison_courante", globals().get("numero_saison", 1)))

                _entry  = {
                    "s": int(_slabel),
                    "tour": str(tournoi_actif),
                    "niv":  _niv,
                    "res": ("or" if me_gagne else ("argent" if me_final else "")),
                }
                if _entry["res"] and _entry not in _hist:
                    _hist.append(_entry)
                    if _entry not in _hist:
                        _hist.append(_entry)
                        if not _meta.get("printed_tournois_hist"):
                            print("[TROPHIES] tournois_hist ->", _hist)
                            _meta["printed_tournois_hist"] = True   # imprimera une seule fois
            except Exception:
                pass

            etat = "victoire_tournoi"
            globals().pop('medaille_tournoia_y', None)  # reset descente médaille (one-shot)

    else:
        prochain_tour = [(gagnants[i], gagnants[i+1]) for i in range(0, len(gagnants), 2)]
        t["matchs"].append(prochain_tour)

    t["tour_actuel"] += 1

    if len(t["matchs"]) == t["tour_actuel"]:
        tournois_disponibles[tournoi_actif]["etat"] = "termine"

    # 💸 Frais d’inscription à comptabiliser au 1er tour uniquement
    if tour == 0 and nom_equipe in t["equipes"]:
        if niveau_tournoi_selectionne == "Débutant":
            frais = FRAIS_INSCRIPTION_TOURNOI
        else:
            frais = FRAIS_INSCRIPTION_TOURNOI_PAR_NIVEAU[niveau_tournoi_selectionne]
        total_depenses += frais

        print(f"💸 Inscription tournoi {niveau_tournoi_selectionne} : -{frais:,}".replace(",", ".") + " €")

        # ➕ Consigner dans l'historique pour affichage Finance
        try:
            historique_matchs.append({
                "texte": f"Frais inscription tournoi ({tournoi_actif} - {niveau_tournoi_selectionne})",
                "domicile": False,
                "recette_billetterie": 0,
                "recette_boutique": 0,
                "bonus_tournoi": 0,
                "frais_inscription": int(frais)
            })
        except Exception:
            pass

    return resultats




# --- 🟧 5. Affichage simple dans l'état 'tournois' ---
