def _score_joueur_pour_vente(joueur):
    """
    Score 'envie de vendre' : plus c'est haut, plus le joueur a des chances
    d'être proposé parmi les 3 joueurs à vendre.

    LOGIQUE POUR LES RÈGLES DU JEU :
    - plus âgé  → plus vendable
    - plus gros salaire  → plus vendable
    - moins bonne pondération (niveau) → plus vendable
    """
    age = joueur.get("age", 25)
    perf = joueur.get("pondération", 75)

    salaire_str = str(joueur.get("salaire", "0")).replace(" €", "").replace(".", "").replace(" ", "")
    try:
        salaire = int(salaire_str)
    except ValueError:
        salaire = 0

    # vieux + cher + pas très performant → score élevé
    return age * 1.5 + salaire / 50000.0 - perf


def selectionner_joueurs_a_mettre_en_vente():
    """
    Remplit `joueurs_mercato_a_vendre` avec au maximum 3 joueurs de l'équipe actuelle.
    On exclut :
    - les joueurs déjà vendus
    - les joueurs tout juste achetés au Mercato (origine == 'mercato')
    """
    global joueurs_mercato_a_vendre

    equipe_loc = globals().get("equipe", set()) or set()
    joueurs_loc = globals().get("joueurs", [])

    candidats = []
    for idx in equipe_loc:
        if not (0 <= idx < len(joueurs_loc)):
            continue

        j = joueurs_loc[idx]
        if j.get("vendu"):
            continue
        if j.get("origine") == "mercato":
            continue

        score = _score_joueur_pour_vente(j)
        candidats.append((score, idx))

    # tri décroissant par score
    candidats.sort(reverse=True, key=lambda x: x[0])

    # On garde au maximum 3 joueurs
    joueurs_mercato_a_vendre = [idx for _, idx in candidats[:3]]

    

