# [MISSIONS][CURVES] helpers pour connecteurs S
def _cubic_bezier_point(p0, p1, p2, p3, t):
    u = 1.0 - t
    tt = t * t
    uu = u * u
    uuu = uu * u
    ttt = tt * t
    x = uuu * p0[0] + 3 * uu * t * p1[0] + 3 * u * tt * p2[0] + ttt * p3[0]
    y = uuu * p0[1] + 3 * uu * t * p1[1] + 3 * u * tt * p2[1] + ttt * p3[1]
    return (int(x), int(y))

def draw_s_connector(surface, p0, p3, *, amp=40, steps=28, invert=False, color=None, width=3):
    """Trace une courbe 'S' entre p0 -> p3 (centres de bulles). amp règle la bosse."""
    # Couleur par défaut
    if color is None:
        color = globals().get('GRIS', (170,170,170))
    x0, y0 = p0
    x3, y3 = p3
    dx = x3 - x0
    dy = y3 - y0

    # Deux points de contrôle pour former un 'S'
    # p1 décalé vers 1/3, p2 vers 2/3 ; invert alterne la bosse
    sgn = -1 if invert else 1
    p1 = (x0 + dx * 0.33, y0 + dy * 0.33 + sgn * amp)
    p2 = (x0 + dx * 0.66, y0 + dy * 0.66 - sgn * amp)

    # Échantillonne la Bézier et trace en segments courts (antialias visuel)
    prev = p0
    for i in range(1, steps + 1):
        t = i / steps
        cur = _cubic_bezier_point(p0, p1, p2, p3, t)
        # segments fins successifs → courbe douce
        try:
            import pygame
            pygame.draw.line(surface, color, prev, cur, width)
        except Exception:
            pass
        prev = cur


def dessiner_missions():
    import pygame

    # --- [SYNC/FALLBACK] roadmap ↔ panneau ---
    prog = globals().setdefault('MISSIONS_PROGRESS', {"completed": set(), "in_progress": set(), "selected": None})

    # tolérance : vieilles versions "done" -> "completed"
    if "done" in prog and "completed" not in prog:
        try:
            prog["completed"] = set(prog.get("done") or [])
        except Exception:
            prog["completed"] = set()

    sel = prog.get("selected")
    cur_from_panel = (globals().get('missions_state', {}) or {}).get('current')

    # si pas de sélection explicite côté roadmap, prendre la mission active du panneau
    if not sel and cur_from_panel:
        sel = str(cur_from_panel.get("id") if isinstance(cur_from_panel, dict) else cur_from_panel)
        prog["selected"] = sel

    # s'assurer que "in_progress" contient l'ID sélectionné (cohérence visuelle)
    if sel:
        ip = prog.get("in_progress")
        if not isinstance(ip, set):
            ip = set(ip or [])
        ip.add(sel)
        prog["in_progress"] = ip

    globals()['MISSIONS_PROGRESS'] = prog


    # --- Surfaces & couleurs de base
    F = globals().get('FENETRE')
    if not F:
        return
    W = int(globals().get('LARGEUR', 1280))
    H = int(globals().get('HAUTEUR', 720))
    NOIR  = globals().get('NOIR', (0,0,0))
    BLANC = globals().get('BLANC', (255,255,255))

    # --- Hover (souris) ---
    try:
        mx, my = pygame.mouse.get_pos()
    except Exception:
        mx = my = 0
    HOVER_R_DELTA = int(globals().get('MISSIONS_HOVER_DELTA', 6))  # +6px par défaut


    # --- Fond plein écran (image "missions")
    bg = (globals().get('img_missions')
          or globals().get('missions_bg')
          or globals().get('BACKGROUND_MISSIONS')
          or globals().get('image_missions'))
    try:
        if bg:
            iw, ih = bg.get_width(), bg.get_height()
            scale  = max(W / max(1, iw), H / max(1, ih))
            new_w, new_h = max(1, int(iw * scale)), max(1, int(ih * scale))
            scaled = pygame.transform.smoothscale(bg, (new_w, new_h))
            ox = max(0, (new_w - W)//2); oy = max(0, (new_h - H)//2)
            F.blit(scaled, (0, 0), pygame.Rect(ox, oy, W, H))
        else:
            F.fill((240,240,240))
    except Exception:
        F.fill((240,240,240))

    # --- Polices (titre / sous-titre / corps)
    FONT_TITRE = globals().get("POLICE_TITRE")    or pygame.font.SysFont("comicsansms", 32, bold=True)
    FONT_SS    = globals().get("POLICE_PETITE")   or pygame.font.SysFont("comicsansms", 18)
    FONT_BODY  = globals().get("POLICE_MOYENNE")  or pygame.font.SysFont("comicsansms", 20, bold=True)

    # --- Titre + sous-titre (avec ombre pour lisibilité)
    titre_txt  = "MISSIONS"
    sous_titre = "Objectifs en cours et à venir"

    # centre X : priorité à W si dispo, sinon largeur de F
    try:
        cx = W // 2
    except NameError:
        cx = F.get_width() // 2

    # Titre
    t_main   = FONT_TITRE.render(titre_txt, True, BLANC)
    t_shadow = FONT_TITRE.render(titre_txt, True, (0,0,0))
    F.blit(t_shadow, t_shadow.get_rect(midtop=(cx, 49)))  # ombre (y=46+3)
    F.blit(t_main,   t_main.get_rect(midtop=(cx, 46)))    # texte

    # Sous-titre
    st_main   = FONT_SS.render(sous_titre, True, (235,235,235))
    st_shadow = FONT_SS.render(sous_titre, True, (0,0,0))
    F.blit(st_shadow, st_shadow.get_rect(midtop=(cx, 90)))  # ombre (y=88+3)
    F.blit(st_main,   st_main.get_rect(midtop=(cx, 88)))    # texte


    # =======================
    #   ROADMAP DES MISSIONS
    # =======================
    # État de progression
    prog = globals().get('MISSIONS_PROGRESS', {"done": set(), "in_progress": set(), "selected": None})
    sel  = prog.get("selected")
    if sel and sel not in prog.get("in_progress", set()):
        prog["selected"] = None
        globals()['MISSIONS_PROGRESS'] = prog

    ORANGE = globals().get("ORANGE", (255,140,0))
    VERT   = (70,170,70)
    GRIS   = (170,170,170)

    missions = list(globals().get('MISSIONS_POOL', globals().get('MISSIONS_ROADMAP', [])))
    prog     = globals().get('MISSIONS_PROGRESS', {"done": set(), "in_progress": set(), "selected": None})
    done     = set(prog.get("done", set()))
    inpg     = set(prog.get("in_progress", set()))


    # Layout : bulles alternées (haut / bas) + connecteurs courbes
    x0, y0 = 120, 260
    y_up, y_down = y0 - 95, y0 + 95     # plus d'écart verticalement entre bulles
    step = 185                          # espace horizontale entre bulles
    r_node = 28
    nodes_rects = []

    # reset des pastilles "déblocage immédiat"
    globals()['missions_unlock_pill_rects'] = {}

    # Bulles (nœuds)
    globals()['missions_pill_rects'] = {}
    for i, m in enumerate(missions):
        x = x0 + i * step
        y = y_up if (i % 2 == 0) else y_down
        mid = m.get("id", i)

        # état
        if mid in done:
            state = "done"
        elif mid in inpg:
             state = "available"
        elif i < len(done):
             state = "done"  # sécurité
        else:
             state = "locked"

        # couleurs par état
        if state == "done":
            fill, bord = VERT, NOIR
        elif state == "available":
            fill, bord = (255,255,255), ORANGE
        elif state == "locked":
            fill, bord = (240,240,240), GRIS
        else:
            fill, bord = (200,220,255), ORANGE

        # hitbox "de base" (on ne la change pas pour éviter les effets de pompage)
        node_rect = pygame.Rect(x - r_node, y - r_node, 2*r_node, 2*r_node)
        hovered   = node_rect.collidepoint(mx, my)

        # rayon de dessin : +delta si survol
        rr = r_node + (HOVER_R_DELTA if hovered else 0)

        # bulle (avec léger renfort de bord si hover)
        pygame.draw.circle(F, fill, (x, y), rr)
        pygame.draw.circle(F, bord, (x, y), rr, 3 + (1 if hovered else 0))

        if hovered:
            pygame.draw.circle(F, bord, (x, y), rr + 3, 1)

        # numéro + label
        num = FONT_BODY.render(str(i+1), True, NOIR)
        F.blit(num, num.get_rect(center=(x, y)))
        label = str(m.get("label", f"Mission {i+1}"))
        lab   = FONT_BODY.render(label, True, BLANC)
        dy    = 14 if (i % 2 == 0) else 14      # distance entre la bulle et son label (texte)
        F.blit(lab, (x - lab.get_width()//2, y + rr + dy))  # ← rr pour garder l’écart sous bulle

        # [UNLOCK] Pastille "Déblocage immédiat" (SOUS le label) pour les nœuds verrouillés
        try:
            if state == "locked":
                # coût affiché = coût réel de la mission, sans fallback arbitraire
                amount = int((m or {}).get("unlock_cost_tokens", (m or {}).get("token_cost", 0)))
                # géo du label pour ancrer la pastille juste en dessous
                label_rect = lab.get_rect()
                label_rect.topleft = (x - lab.get_width()//2, y + r_node + dy)

                # ancre légèrement à DROITE du centre du label (car ‘_left’ dessine la pastille à gauche de l’ancre)
                ax = label_rect.centerx + int(globals().get('UNLOCK_PILL_ANCHOR_DX', 48))
                ay = label_rect.bottom + int(globals().get('UNLOCK_PILL_ANCHOR_DY', 8))
                anchor = pygame.Rect(ax, ay, 1, 1)

                pill = show_unlock_pill_left(F, anchor, amount)
                (globals().setdefault('missions_unlock_pill_rects', {}))[mid] = pill
        except Exception:
            pass

        # hitbox de la bulle
        nodes_rects.append((mid, pygame.Rect(x - r_node, y - r_node, 2*r_node, 2*r_node)))

    globals()['missions_nodes_rects'] = nodes_rects

    # --- CONNECTEURS ENTRE LES NOEUDS (S-courbes avec fallback ligne droite) ---
    _nodes = [(mid, r) for (mid, r) in (globals().get('missions_nodes_rects') or []) if r]
    if len(_nodes) >= 2:
        try:
            GRIS  = globals().get('GRIS', (170,170,170))
            width = 3
            amp   = int(globals().get('MISSIONS_ROADMAP_AMP', 52))  # amplitude plus marquée

            for i in range(len(_nodes) - 1):
                r1 = _nodes[i][1]
                r2 = _nodes[i+1][1]
                p0 = (r1.centerx, r1.centery)
                p3 = (r2.centerx, r2.centery)
                invert = bool(i % 2)  # alterne la courbure pour un vrai "S"
                if 'draw_s_connector' in globals():
                    draw_s_connector(FENETRE, p0, p3, amp=amp, steps=28, invert=invert, color=GRIS, width=width)
                else:
                    # fallback: segment droit si helper absent
                    pygame.draw.line(FENETRE, GRIS, p0, p3, width)
        except Exception:
            pass

    # --- TOOLTIP au survol d'une bulle (récompense + icône token) ---
    try:
        import pygame
        mx, my = pygame.mouse.get_pos()
    except Exception:
        mx = my = 0

    try:
        FONT_TT   = globals().get("POLICE_PETITE") or pygame.font.SysFont("comicsansms", 16)
        BLANC     = globals().get('BLANC', (255,255,255))
        NOIR      = globals().get('NOIR',  (0,0,0))
        missions  = list(globals().get('MISSIONS_POOL', globals().get('MISSIONS_ROADMAP', [])))
        nodes_map = dict(globals().get('missions_nodes_rects') or [])

        # détecter la bulle survolée
        over_id = None
        for mid, rect in (globals().get('missions_nodes_rects') or []):
            if rect and rect.collidepoint(mx, my):
                over_id = mid
                break

        if over_id:
            m = next((mm for mm in missions if str(mm.get('id')) == str(over_id)), {})
            reward = int(m.get('reward_tokens', m.get('token_cost') or globals().get('TOKENS_ACCEL_MISSION', 4)))

            # charge/cache l'icône token
            tok = globals().get('token_img')
            if tok is None:
                try:
                    tok = pygame.image.load("images/token.png").convert_alpha()
                    globals()['token_img'] = tok
                except Exception:
                    tok = None

            # texte "récompense :" (centré)
            titre = POLICE_CLASSEMENT_BOLD.render("Récompense :", True, BLANC)

            # ligne icône + valeur, centrée
            value_txt = POLICE_CLASSEMENT_BOLD.render(f"+{reward}", True, BLANC)
            ICON_W = ICON_H = 26    # taille icône Token
            spacing = 8

            if tok:
                icon = pygame.transform.smoothscale(tok, (ICON_W, ICON_H))
                line_w = value_txt.get_width() + spacing + icon.get_width()
                line_h = max(icon.get_height(), value_txt.get_height())
            else:
                icon = None
                line_w = value_txt.get_width()
                line_h = value_txt.get_height()

            # dimensions du tooltip (centrées)
            padx, pady = 12, 10
            w = max(titre.get_width(), line_w) + 2*padx
            h = titre.get_height() + 8 + line_h + 2*pady

            base = nodes_map.get(over_id)
            tx = (base.centerx if base else mx) + 14
            ty = (base.top     if base else my) - h - 12

            tip = pygame.Surface((w, h), pygame.SRCALPHA)
            tip.fill((20, 20, 30, 220))
            F.blit(tip, (tx, ty))
            pygame.draw.rect(F, (250, 250, 255), pygame.Rect(tx, ty, w, h), 1, border_radius=8)

            # titre centré
            titre_rect = titre.get_rect(midtop=(tx + w//2, ty + pady))
            F.blit(titre, titre_rect)

            # ligne icône+texte centrée sous le titre
            line_x = tx + (w - line_w)//2
            line_y = titre_rect.bottom + 8
            if icon:
                # le texte (valeur) aligné verticalement au centre de l'icône
                F.blit(value_txt, (line_x, line_y + (icon.get_height() - value_txt.get_height())//2))
                F.blit(icon, (line_x + value_txt.get_width() + spacing, line_y))
            else:
                F.blit(value_txt, (line_x, line_y))
    except Exception:
        pass


# Alias si d’autres endroits appellent l’ancien nom
