# --- Helpers: comparaison de noms d'équipes (robuste aux accents/espaces/casse) ---
def _norm_team(name):
    if name is None:
        return ""
    if not isinstance(name, str):
        name = str(name)
    # retire les accents, normalise les espaces, met en minuscule
    s = unicodedata.normalize("NFKD", name)
    s = s.encode("ascii", "ignore").decode("ascii")
    return s.strip().lower()


def _canon_name(s: str) -> str:
    s = (s or "").strip().lower()
    s = unicodedata.normalize("NFKD", s)
    s = "".join(ch for ch in s if not unicodedata.combining(ch))  # enlève les accents
    s = " ".join(s.split())  # compresse espaces multiples
    return s

def same_team(a, b) -> bool:
    return _canon_name(a) == _canon_name(b)


def dessiner_playoffs():
    global bouton_playoff_jouer, bouton_po_ok
    global po_bracket, po_phase, po_en_cours, po_champion
    global afficher_popup_po, afficher_popup_po_2eme
    global po_resultat

    # Fond + titre
    FENETRE.blit(playoffs_img, (0, 0))
    saison_txt = f"Saison {saison_actuelle}" if 'saison_actuelle' in globals() else ""
    titre = POLICE_TITRE.render(f"PLAYOFFS - {saison_txt}", True, NOIR)
    FENETRE.blit(titre, (LARGEUR // 2 - titre.get_width() // 2, 40))

    # Mise en page type "Tournoi Débutant"
    box_w, box_h = 225, 56
    gap_v = 25

    x_left  = 120
    x_right = LARGEUR - x_left - box_w
    y_top   = 250
    y_top2  = y_top + box_h + gap_v

    # Finale exactement au milieu vertical entre y_top et y_top2
    x_final = LARGEUR // 2 - box_w // 2
    y_final = y_top

    col_box = BLANC; col_brd = NOIR; col_btn = BLEU_FONCE; col_win = (50,160,50)

    def draw_box(x, y, w, h, texte, is_winner=False):
        r = pygame.Rect(x, y, w, h)
        pygame.draw.rect(FENETRE, col_box, r, border_radius=10)
        pygame.draw.rect(FENETRE, col_brd, r, 2, border_radius=10)
        surf = FONT.render(texte, True, (col_win if is_winner else NOIR))
        FENETRE.blit(surf, surf.get_rect(center=r.center))
        return r

    def nom_aff(n): return n if (n and isinstance(n, str)) else "—"

    def _titre_au_dessus(txt, center_x, top_rect, pad=10):
        s = POLICE_MOYENNE.render(txt, True, NOIR)
        FENETRE.blit(s, s.get_rect(midbottom=(center_x, top_rect.top - pad)))

    # --- Police pour les scores (petite si dispo)
    try:
        _SCORE_FONT = POLICE_PETITE
    except NameError:
        _SCORE_FONT = FONT

    def _blit_score_between(rect_a, rect_b, score_tuple):
        if not score_tuple: 
            return
        try:
            sA, sB = int(score_tuple[0]), int(score_tuple[1])
        except Exception:
            return
        surf_sc = _SCORE_FONT.render(f"{sA} - {sB}", True, NOIR)
        cx = (rect_a.centerx + rect_b.centerx) // 2
        cy = (rect_a.centery + rect_b.centery) // 2
        FENETRE.blit(surf_sc, surf_sc.get_rect(center=(cx, cy)))
    

    # Bracket prêt ?
    if not po_bracket or not all(k in po_bracket for k in ("demi1","demi2","finale")):
        po_lancer(classement)

    # --- Données
    d1 = po_bracket["demi1"]; d2 = po_bracket["demi2"]; fin = po_bracket["finale"]
    d1A, d1B = nom_aff(d1["A"]), nom_aff(d1["B"])
    d2A, d2B = nom_aff(d2["A"]), nom_aff(d2["B"])
    fA,  fB  = nom_aff(fin["A"]), nom_aff(fin["B"])
    d1_w, d2_w = d1.get("vainqueur"), d2.get("vainqueur")  

    # Source unique du vainqueur de la finale
    champ = (po_champion if 'po_champion' in globals() and po_champion
             else fin.get("vainqueur"))


    # --- Demi-finales
    r_d1A = draw_box(x_left,  y_top,  box_w, box_h, d1A, is_winner=(d1_w==d1A and d1.get("joue")))
    r_d1B = draw_box(x_left,  y_top2, box_w, box_h, d1B, is_winner=(d1_w==d1B and d1.get("joue")))
    r_d2A = draw_box(x_right, y_top,  box_w, box_h, d2A, is_winner=(d2_w==d2A and d2.get("joue")))
    r_d2B = draw_box(x_right, y_top2, box_w, box_h, d2B, is_winner=(d2_w==d2B and d2.get("joue")))

    # --- Scores des demies (si jouées)
    if d1.get("joue") and d1.get("score"):
        _blit_score_between(r_d1A, r_d1B, d1["score"])

    if d2.get("joue") and d2.get("score"):
        _blit_score_between(r_d2A, r_d2B, d2["score"])

    

    # --- Finale : une seule grande case avec trait au milieu
    r_fin = pygame.Rect(x_final, y_final, box_w, 2*box_h + gap_v)
    pygame.draw.rect(FENETRE, BLANC, r_fin, border_radius=10)
    pygame.draw.rect(FENETRE, NOIR,  r_fin, 2, border_radius=10)
    y_mid = r_fin.centery
    pygame.draw.line(FENETRE, NOIR, (r_fin.left+8, y_mid), (r_fin.right-8, y_mid), 2)

    colA = col_win if (same_team(champ, fA) and fin.get("joue")) else NOIR
    colB = col_win if (same_team(champ, fB) and fin.get("joue")) else NOIR

    _sA = FONT.render(fA, True, colA)
    rect_fA = FENETRE.blit(_sA, _sA.get_rect(center=(r_fin.centerx, r_fin.top + (y_mid - r_fin.top)//2)))

    _sB = FONT.render(fB, True, colB)
    rect_fB = FENETRE.blit(_sB, _sB.get_rect(center=(r_fin.centerx, y_mid + (r_fin.bottom - y_mid)//2)))

    # --- Score de la finale (si joué)
    if fin.get("joue") and fin.get("score"):
        _blit_score_between(rect_fA, rect_fB, fin["score"])


    # --- Titres centrés au-dessus
    _titre_au_dessus("Demi-finale 1", x_left  + box_w//2, r_d1A, pad=10)
    _titre_au_dessus("Demi-finale 2", x_right + box_w//2, r_d2A, pad=10)
    _titre_au_dessus("Finale",        x_final + box_w//2, r_fin,  pad=10)

    # --- Liaisons vers la finale (centrées verticalement)
    jg_x = r_d1A.right + 20
    jg_y = (r_d1A.centery + r_d1B.centery)//2
    pygame.draw.line(FENETRE, NOIR, (r_d1A.right, r_d1A.centery), (jg_x, r_d1A.centery), 2)
    pygame.draw.line(FENETRE, NOIR, (r_d1B.right, r_d1B.centery), (jg_x, r_d1B.centery), 2)
    pygame.draw.line(FENETRE, NOIR, (jg_x, r_d1A.centery), (jg_x, r_d1B.centery), 2)
    pygame.draw.line(FENETRE, NOIR, (jg_x, jg_y), (r_fin.left - 20, y_mid), 2)
    pygame.draw.line(FENETRE, NOIR, (r_fin.left - 20, y_mid), (r_fin.left, y_mid), 2)

    jd_x = r_d2A.left - 20
    jd_y = (r_d2A.centery + r_d2B.centery)//2
    pygame.draw.line(FENETRE, NOIR, (r_d2A.left, r_d2A.centery), (jd_x, r_d2A.centery), 2)
    pygame.draw.line(FENETRE, NOIR, (r_d2B.left, r_d2B.centery), (jd_x, r_d2B.centery), 2)
    pygame.draw.line(FENETRE, NOIR, (jd_x, r_d2A.centery), (jd_x, r_d2B.centery), 2)
    pygame.draw.line(FENETRE, NOIR, (jd_x, jd_y), (r_fin.right + 20, y_mid), 2)
    pygame.draw.line(FENETRE, NOIR, (r_fin.right, y_mid), (r_fin.right + 20, y_mid), 2)



    # Boutons
    bouton_playoff_jouer = pygame.Rect(LARGEUR - 220, HAUTEUR - 90, 180, 48)
    pygame.draw.rect(FENETRE, col_btn, bouton_playoff_jouer, border_radius=10)
    pygame.draw.rect(FENETRE, NOIR,    bouton_playoff_jouer, 2, border_radius=10)
    txt = ("Jouer la demi" if po_phase=="demies" else "Jouer la finale" if po_phase=="finale" else "Terminé")
    FENETRE.blit(FONT.render(txt, True, BLANC), FONT.render(txt, True, BLANC).get_rect(center=bouton_playoff_jouer.center))

    pygame.draw.rect(FENETRE, ROUGE, bouton_retour); pygame.draw.rect(FENETRE, NOIR, bouton_retour, 2)
    FENETRE.blit(FONT.render("Retour", True, BLANC), (bouton_retour.x + 10, bouton_retour.y + 5))


    if globals().get("afficher_popup_po"):
        dessiner_popup_victoire_po()

    if globals().get("afficher_popup_po_2eme"):
        dessiner_popup_po_2eme()

    if globals().get("afficher_popup_po_finalfour"):
        dessiner_popup_finalfour() 

     # --- Overlay de résultat (après TOUT le reste pour rester au-dessus) ---
    _res_overlay = globals().get("po_resultat")
    if isinstance(_res_overlay, dict) and po_phase != "termine":
        dessiner_resultat_playoff_overlay(_res_overlay)
    else:
        bouton_po_ok = None

    

def simuler_match_playoff(adversaire, domicile=False):
    """Simule un match de PO SANS toucher au classement/finance de la saison."""
    import random
    score1 = random.randint(70, 105)
    score2 = random.randint(70, 105)

    res = {
        "adversaire": adversaire,
        "score_equipe": score1,
        "score_adverse": score2,
        "score_nous": score1,
        "score_eux": score2,
        "resultat": "Victoire" if score1 > score2 else ("Défaite" if score2 > score1 else "Égalité"),
        "contexte": "playoff",
        "domicile": domicile,
        "mon_equipe": nom_equipe,
    }

    # Stats simples pour l’overlay PO (mêmes clés que l’écran de saison)
    stats = {
        "tirs_2_pts": [random.randint(55, 70), random.randint(55, 70)],
        "tirs_3_pts": [random.randint(30, 45), random.randint(30, 45)],
        "passes":     [random.randint(10, 18), random.randint(10, 18)],
        "fautes":     [random.randint(10, 20), random.randint(10, 20)],
    }
    res["stats"] = stats

    # MVPs attendus par l’overlay
    try:
        mvp_nom = random.choice([joueurs[i]["nom"] for i in equipe]) if equipe else nom_equipe
    except Exception:
        mvp_nom = nom_equipe
    res["mvp_equipe"] = {"nom": mvp_nom}
    res["mvp_match"]  = {"nom": mvp_nom}

    return res





def dessiner_prime_champion():
    import pygame
    global prime_terminee, _prime_layer
    # --- SFX state used during the counter animation ---
    global prime_sfx_last_ms, prime_sfx_done, prime_courant_prev
    global sfx_tick, sfx_chime, sfx_finish
    global prime_cible, prime_debut_ms, prime_terminee, prime_bg  # (si utilisés ici)

    if 'prime_sfx_last_ms' not in globals(): prime_sfx_last_ms = 0
    if 'prime_sfx_done'    not in globals(): prime_sfx_done    = False
    if 'prime_courant_prev' not in globals(): prime_courant_prev = 0


    # (A) rétablir le fond d'abord (efface toute frame précédente)
    if 'prime_bg' in globals() and prime_bg is not None:
        FENETRE.blit(prime_bg, (0, 0))

    # 1) progression
    now = pygame.time.get_ticks()
    elapsed_ms = max(0, now - prime_debut_ms)
    courant = int(min(prime_cible, elapsed_ms * (PRIME_EUROS_PAR_SECONDE / 1000.0)))
    prime_terminee = (courant >= prime_cible)
    texte_montant = f"{courant:,} €".replace(",", ".")


    # --- SFX paliers pendant l'incrément ---
    if 'prime_courant_prev' not in globals():
        prime_courant_prev = 0

    val_avant = int(prime_courant_prev)
    val_apres = int(courant)
    now = pygame.time.get_ticks()

    PALIER_TICK  = 10_000   # un tick tous les 10k€
    PALIER_CHIME = 100_000  # une clochette tous les 100k€
    MIN_DELAY_MS = 45       # anti-spam audio

    # 1) Tick à chaque palier de 10k
    if (val_avant // PALIER_TICK) < (val_apres // PALIER_TICK) and (now - prime_sfx_last_ms) > MIN_DELAY_MS:
        if sfx_tick:  # <-- au lieu du try/except
            sfx_tick.play()
        prime_sfx_last_ms = now

    # 2) Chime aux paliers majeurs (100k)
    if (val_avant // PALIER_CHIME) < (val_apres // PALIER_CHIME):
        if sfx_chime:  # <-- au lieu du try/except
            sfx_chime.play()

    # 3) Son de fin (une seule fois)
    if prime_terminee and not prime_sfx_done:
        if sfx_finish:  # <-- au lieu du try/except
            sfx_finish.play()
        prime_sfx_done = True


    # mémorise la valeur pour la frame suivante
    prime_courant_prev = val_apres



    # 2) font (taille fixe ou auto)
    try:
        taille = TAILLE_POLICE_PRIME
    except NameError:
        taille = max(72, min(int(LARGEUR * 0.16), int(HAUTEUR * 0.22)))
    font_big = pygame.font.SysFont("DejaVu Sans Mono", taille)  # monospace = pas de “sauts”

    # 3) couche transparente effacée à chaque frame
    if '_prime_layer' not in globals():
        layer_w, layer_h = int(LARGEUR * 0.8), int(HAUTEUR * 0.28)
        _prime_layer = pygame.Surface((layer_w, layer_h), pygame.SRCALPHA)
    layer = _prime_layer
    layer.fill((0, 0, 0, 0))  # clear

    # 4) rendu du texte (effet léger)
    c_gold, c_shadow, c_glow = (255,210,60), (20,20,20), (255,255,255)
    surf_main   = font_big.render(texte_montant, True, c_gold)
    surf_shadow = font_big.render(texte_montant, True, c_shadow)
    surf_glow   = font_big.render(texte_montant, True, c_glow)

    lx, ly = layer.get_width() // 2, layer.get_height() // 2
    layer.blit(surf_shadow, surf_shadow.get_rect(center=(lx + 3, ly + 3)))
    layer.blit(surf_glow,   surf_glow.get_rect(center=(lx - 1, ly - 1)))
    layer.blit(surf_main,   surf_main.get_rect(center=(lx, ly)))

    # 5) blit du layer au centre (par-dessus le fond rétabli)
    FENETRE.blit(layer, (LARGEUR // 2 - lx, HAUTEUR // 2 - layer.get_height() // 2))

    # Indication de sortie
    if prime_terminee:
        hint = FONT.render("Clique pour continuer…", True, (80, 80, 80))
        rect = hint.get_rect(center=(LARGEUR // 2, HAUTEUR // 2 + int(TAILLE_POLICE_PRIME * 0.9)))
        FENETRE.blit(hint, rect)



def dessiner_prime_tournoi():
    """Animation d’affichage du bonus Tournoi (identique à la prime PO mais dédiée tournois)."""
    import pygame
    global prime_terminee, prime_cible, prime_debut_ms, prime_bg
    global prime_sfx_last_ms, prime_sfx_done, prime_courant_prev

    # --- Fond gelé (screenshot) ou blanc + voile doux ---
    if 'FENETRE' not in globals():
        return
    if isinstance(globals().get('prime_bg'), pygame.Surface):
        FENETRE.blit(prime_bg, (0, 0))
    else:
        FENETRE.fill((255, 255, 255))
    voile = pygame.Surface((LARGEUR, HAUTEUR), pygame.SRCALPHA)
    voile.fill((255, 255, 255, 220))
    FENETRE.blit(voile, (0, 0))

    # --- Progression sûre (jamais d'UnboundLocalError) ---
    now     = pygame.time.get_ticks()
    vitesse = int(globals().get('TOURNOI_EUROS_PAR_SECONDE', globals().get('PRIME_EUROS_PAR_SECONDE', 50000)) or 50000)
    cible   = int(globals().get('prime_cible', 0) or 0)
    debut   = int(globals().get('prime_debut_ms', now) or now)

    if cible > 0 and vitesse > 0:
        elapsed  = max(0, now - debut)
        duree_ms = max(1, (cible * 1000) // max(1, vitesse))  # jamais 0
        ratio    = min(1.0, elapsed / float(duree_ms))
        courant  = int(round(cible * ratio))
    else:
        ratio   = 1.0
        courant = int(cible)

    prime_terminee = (cible <= 0) or (courant >= cible)

    # --- SFX paliers (facultatifs) ---
    if 'prime_courant_prev' not in globals(): prime_courant_prev = 0
    if 'prime_sfx_last_ms'  not in globals(): prime_sfx_last_ms  = 0
    if 'prime_sfx_done'     not in globals(): prime_sfx_done     = False

    val_avant = int(prime_courant_prev)
    val_apres = int(courant)
    PALIER_TICK, PALIER_CHIME, MIN_DELAY_MS = 10_000, 100_000, 45

    if (val_avant // PALIER_TICK) < (val_apres // PALIER_TICK) and (now - prime_sfx_last_ms) > MIN_DELAY_MS:
        try: sfx_tick.play()
        except Exception: pass
        prime_sfx_last_ms = now

    if (val_avant // PALIER_CHIME) < (val_apres // PALIER_CHIME):
        try: sfx_chime.play()
        except Exception: pass

    if prime_terminee and not prime_sfx_done:
        try: sfx_finish.play()
        except Exception: pass
        prime_sfx_done = True

    prime_courant_prev = val_apres

    # --- Rendu (mêmes couleurs que PO) ---
    try:
        taille = int(globals().get('TAILLE_POLICE_TOURNOI_PRIME', globals().get('TAILLE_POLICE_PRIME', 120)))
        police_val = pygame.font.SysFont("comicsansms", max(20, taille))
    except Exception:
        police_val = pygame.font.SysFont("comicsansms", 110)

    montant_txt = f"+ {val_apres:,} €".replace(",", " ")
    surf = police_val.render(montant_txt, True, (0, 140, 0))
    rect = surf.get_rect(center=(LARGEUR // 2, HAUTEUR // 2))
    pygame.draw.rect(FENETRE, NOIR, rect.inflate(30, 30), 2, border_radius=14)
    FENETRE.blit(surf, rect)

    label = FONT.render("Bonus Tournoi", True, NOIR)
    FENETRE.blit(label, label.get_rect(center=(LARGEUR // 2, rect.top - 35)))

    # Indication de sortie
    if prime_terminee:
        hint = FONT.render("Clique pour continuer…", True, (80, 80, 80))
        FENETRE.blit(hint, hint.get_rect(center=(LARGEUR // 2, rect.bottom + 40)))




