def stade_travaux_apres_match():
    """À appeler une fois à la fin de CHAQUE match disputé par le joueur."""
    if not globals().get('stade_travaux_en_cours'):
        return

    rem = int(globals().get('stade_travaux_matches_restants', 0))
    if rem > 0:
        rem -= 1
        globals()['stade_travaux_matches_restants'] = rem

    if rem <= 0:
        tgt = globals().get('stade_travaux_cible')
        if tgt:
            try:
                ng, ns = int(tgt[0]), int(tgt[1])
                globals()['niveau_global_jeu'] = ng
                globals()['niveau_stade']      = ns
            except Exception:
                pass

            # 🔄 Stocks : binder ceux du nouveau niveau
            try:
                _stock_boutique_bind()
            except Exception:
                pass

            # 🖼️ Image terrain correspondant au nouveau niveau
            try:
                _stade_actualiser_image_terrain()
            except Exception:
                pass

            # ✅ Fin des travaux : on nettoie les variables
            globals()['stade_travaux_en_cours'] = False
            for k in (
                'stade_travaux_cible',
                'stade_travaux_matches_restants',
                'stade_travaux_duree_totale',
                'stade_travaux_baseline_matchs_saison',
            ):
                if k in globals():
                    globals().pop(k, None)

            # 🔔 petit message de confirmation (3,5 s déjà géré ailleurs)
            try:
                cap = int(globals().get('capacite_stade_niveaux', {}).get(ng, {}).get(ns, 0))
                cap_str = f"{cap:,}".replace(",", " ")
                globals()['message_blocage'] = f"✅ Travaux terminés : niveau {ng}.{ns} opérationnel (capacité {cap_str})"
            except Exception:
                globals()['message_blocage'] = f"✅ Travaux terminés : niveau {ng}.{ns} opérationnel"
            globals()['temps_blocage'] = pygame.time.get_ticks()
            globals()['afficher_message_fin_travaux_stade'] = True



def _nb_matchs_saison_joues():
    """
    Compte les matchs de SAISON joués par l'équipe du joueur (domicile ou extérieur).
    On ne dépend pas d'un champ 'competition' : si la structure home/away existe, on compte.
    """
    h = globals().get('historique_matchs', []) or []
    me = (globals().get('nom_equipe')
          or globals().get('team_name')
          or globals().get('club_name'))

    c = 0
    for m in h:
        if not isinstance(m, dict):
            continue

        # Considéré "match de saison" si home/away (ou équivalents) existent
        if not any(k in m for k in ('domicile', 'home', 'exterieur', 'away', 'equipe_a', 'equipe_b')):
            continue

        home = m.get('domicile') or m.get('home') or m.get('equipe_a')
        away = m.get('exterieur') or m.get('away') or m.get('equipe_b')

        # Si on ne connaît pas le nom exact de l'équipe, on compte tout match structuré
        if me is None or home == me or away == me:
            c += 1

    # Fallback : si rien compté, on prend le nombre brut de matchs logués
    if c == 0:
        try:
            return len(h)
        except Exception:
            return 0
    return c

def __prochain_match_est_domicile():
    """
    Renvoie True si le prochain match (celui à venir) est à domicile.
    Reste aligné avec ta logique d’onglets : tu grises billetterie/boutique quand len(historique_matchs) % 2 == 1.
    """
    try:
        return (len(globals().get('historique_matchs', [])) % 2) == 0
    except Exception:
        return True  # fallback: on considère domicile

def __cap_travaux_domicile(montant):
    """
    Si travaux en cours ET prochain match à domicile → applique un cap à 50% (configurable).
    """
    try:
        if globals().get('stade_travaux_en_cours', False) and __prochain_match_est_domicile():
            cap = float(globals().get('RECETTE_TRAVAUX_CAP', 0.5))
            return int(montant * cap)
    except Exception:
        pass
    return int(montant)


def coach_contract_tick_season():
    """
    À appeler à chaque fin de saison.
    Décrémente le contrat coach en cours (si actif), et défige la sélection quand il arrive à 0.
    """
    if not globals().get('coach_contract_active'):
        return

    remain = int(globals().get('coach_contract_remaining') or 0)
    if remain > 0:
        remain -= 1
        globals()['coach_contract_remaining'] = remain

    if remain <= 0:
        globals()['coach_contract_active']   = False
        globals()['coach_selection_frozen']  = False
        # on garde le coach_card_selected pour l’affichage, comme Sponsors garde la carte
        # message optionnel :
        globals()['ui_flash_msg']   = "Contrat coach terminé"
        globals()['ui_flash_until'] = pygame.time.get_ticks() + 1500



def _maybe_award_eco_xp():
    """
    Attribue un peu d'XP éco au plus une fois par *période*.
    Définition MVP d'une période = 2 matchs du club.
    Barème : min(10, benef//50_000) si bénéfice > 0.
    """
    try:
        h = globals().get('historique_matchs', []) or []
        periode_idx = len(h) // 2  # 0,1,2,...

        last_done = int(globals().get('_xp_eco_last_period_idx', -1))
        if periode_idx <= last_done:
            return  # déjà traité pour cette période

        benef = int(globals().get('total_recettes', 0)) - int(globals().get('total_depenses', 0))
        if benef > 0:
            xp = min(10, benef // 50_000)
            if xp > 0:
                _apply_xp(xp, "eco_periode")

        globals()['_xp_eco_last_period_idx'] = periode_idx
    except Exception:
        pass




