def dessiner_popup_bienvenue():
    """
    Popup de bienvenue qui s'affiche sur l'écran des fiches joueurs
    après la création de l'équipe (nom + alias confirmés).
    """
    import pygame

    FENETRE = globals().get("FENETRE")
    if FENETRE is None:
        return

    LARGEUR = int(globals().get("LARGEUR", 1280))
    HAUTEUR = int(globals().get("HAUTEUR", 720))

    BLANC = globals().get("BLANC", (255, 255, 255))
    NOIR = globals().get("NOIR", (0, 0, 0))

    try:
        POLICE_TITRE = globals().get("POLICE_TITRE") or pygame.font.SysFont("comicsansms", 32, bold=True)
    except Exception:
        POLICE_TITRE = pygame.font.SysFont("comicsansms", 32, bold=True)

    try:
        POLICE_CORPS = globals().get("POLICE_PETITE") or pygame.font.SysFont("comicsansms", 20)
    except Exception:
        POLICE_CORPS = pygame.font.SysFont("comicsansms", 20)

    # Fond assombri derrière le popup
    try:
        overlay = pygame.Surface((LARGEUR, HAUTEUR), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 140))
        FENETRE.blit(overlay, (0, 0))
    except Exception:
        pass

    # Boîte principale du popup
    w, h = 700, 220
    rect = pygame.Rect(0, 0, w, h)
    rect.center = (LARGEUR // 2, HAUTEUR // 2)

    pygame.draw.rect(FENETRE, (245, 245, 255), rect, border_radius=18)
    pygame.draw.rect(FENETRE, (160, 160, 210), rect, 2, border_radius=18)

    # Croix de fermeture
    close_size = 24
    close_rect = pygame.Rect(rect.right - close_size - 12, rect.y + 12, close_size, close_size)
    pygame.draw.rect(FENETRE, (230, 230, 240), close_rect, border_radius=6)
    pygame.draw.rect(FENETRE, (180, 180, 210), close_rect, 2, border_radius=6)

    # 'X' dans la croix
    pygame.draw.line(FENETRE, (120, 120, 160),
                     (close_rect.x + 6, close_rect.y + 6),
                     (close_rect.right - 6, close_rect.bottom - 6), 2)
    pygame.draw.line(FENETRE, (120, 120, 160),
                     (close_rect.right - 6, close_rect.y + 6),
                     (close_rect.x + 6, close_rect.bottom - 6), 2)

    # Publier les rects dans globals pour le handler de clic
    globals()['popup_bienvenue_rect'] = rect
    globals()['popup_bienvenue_close_rect'] = close_rect

    # Texte
    titre = POLICE_TITRE.render("Bienvenue au club !", True, NOIR)
    FENETRE.blit(titre, (rect.x + 24, rect.y + 24))

    corps_lignes = [
        "Tu viens de prendre les commandes de l'équipe.",
        "Ton objectif : faire progresser le club sur plusieurs saisons",
        "en gérant résultats sportifs, finances et infrastructures.",
        "Bonne chance !"
    ]

    y_text = rect.y + 80
    for line in corps_lignes:
        surf = POLICE_CORPS.render(line, True, NOIR)
        FENETRE.blit(surf, (rect.x + 28, y_text))
        y_text += surf.get_height() + 4


def dessiner_popup_gestion_tuto():
    """
    Popup de tutoriel quand on arrive pour la première fois sur l'écran Gestion.
    Même style que dessiner_popup_bienvenue().
    """
    import pygame

    FENETRE = globals().get("FENETRE")
    if FENETRE is None:
        return

    LARGEUR = int(globals().get("LARGEUR", 1280))
    HAUTEUR = int(globals().get("HAUTEUR", 720))

    BLANC = globals().get("BLANC", (255, 255, 255))
    NOIR = globals().get("NOIR", (0, 0, 0))

    # Typo
    POLICE_TITRE = globals().get("POLICE_TITRE")
    POLICE_PETITE = globals().get("POLICE_PETITE")
    if POLICE_TITRE is None or POLICE_PETITE is None:
        POLICE_TITRE = pygame.font.SysFont("comicsansms", 28, bold=True)
        POLICE_PETITE = pygame.font.SysFont("comicsansms", 18)

    # Overlay léger
    overlay = pygame.Surface((LARGEUR, HAUTEUR), pygame.SRCALPHA)
    overlay.fill((0, 0, 0, 160))
    FENETRE.blit(overlay, (0, 0))

    # Carte centrale
    w, h = 700, 260
    rect = pygame.Rect(
        (LARGEUR - w) // 2,
        (HAUTEUR - h) // 2,
        w,
        h,
    )
    pygame.draw.rect(FENETRE, (245, 245, 255), rect, border_radius=20)
    pygame.draw.rect(FENETRE, (90, 90, 140), rect, 3, border_radius=20)

    # Titre
    titre = POLICE_TITRE.render("Voici le centre de Gestion", True, NOIR)
    FENETRE.blit(
        titre,
        (rect.x + (rect.width - titre.get_width()) // 2, rect.y + 20),
    )

    # Corps du texte (lignes courtes, comme demandé)
    lignes = [
        "D'ici tu gères le sportif, les finances,",
        "les sponsors et les infrastructures.",
        "Dans « Messages », tu trouveras des alertes",
        "pour piloter ton équipe au quotidien.",
    ]

    y = rect.y + 80
    for ligne in lignes:
        surf = POLICE_PETITE.render(ligne, True, (40, 40, 80))
        FENETRE.blit(
            surf,
            (rect.x + (rect.width - surf.get_width()) // 2, y),
        )
        y += surf.get_height() + 6

    # Petite croix de fermeture en haut-droite
    close_size = 26
    close_rect = pygame.Rect(
        rect.right - close_size - 12,
        rect.y + 12,
        close_size,
        close_size,
    )
    pygame.draw.rect(FENETRE, (220, 220, 235), close_rect, border_radius=8)
    pygame.draw.rect(FENETRE, (120, 120, 160), close_rect, 2, border_radius=8)

    cross_font = pygame.font.SysFont("comicsansms", 20, bold=True)
    cross_txt = cross_font.render("X", True, (80, 80, 120))
    FENETRE.blit(
        cross_txt,
        (
            close_rect.x + (close_rect.width - cross_txt.get_width()) // 2,
            close_rect.y + (close_rect.height - cross_txt.get_height()) // 2,
        ),
    )

    # Publier les rects pour le handler de clic
    globals()["popup_gestion_rect"] = rect
    globals()["popup_gestion_close_rect"] = close_rect



def appliquer_tuning(
    action_id,
    *,
    budget,
    tokens,
    xp_club,
    niveau_global_jeu,
    xp_par_niveau=XP_PAR_NIVEAU,
    appliquer_cout=True,
    appliquer_tokens=True,
    appliquer_xp=True,
    debug=False,
):
    """
    Applique les effets d'une action de tuning (coût €, coût/reward tokens, XP, LV).

    ⚠️ Fonction pure : elle NE modifie PAS les globals.
    Elle renvoie les nouvelles valeurs (budget, tokens, xp_club, niveau_global_jeu).

    Exemple d'appel :
        budget, TOKENS, XP_CLUB, niveau_global_jeu = appliquer_tuning(
            "upgrade_stade_1_2",
            budget=budget,
            tokens=TOKENS,
            xp_club=XP_CLUB,
            niveau_global_jeu=niveau_global_jeu,
            debug=True,
        )
    """
    action = TUNING_ACTIONS.get(action_id)

    if action is None:
        if debug:
            print(f"[TUNING][WARN] Action inconnue : {action_id}")
        # On ne change rien
        return budget, tokens, xp_club, niveau_global_jeu

    if debug:
        label = action.get("label", action_id)
        print(f"[TUNING] Appliquer action '{action_id}' → {label}")

        temps_type = action.get("temps_type")
        temps_duree = action.get("temps_duree")
        difficulte = action.get("difficulte")
        palier_lv_min = action.get("palier_lv_min")

        if temps_type is not None:
            print(f"  - Temps : {temps_duree} {temps_type}(s)")

        if difficulte is not None:
            print(f"  - Difficulté : {difficulte}")
        if palier_lv_min is not None:
            print(f"  - Palier LV min conseillé : {palier_lv_min}")

    # 1) Coûts (euros + tokens dépensés)
    if appliquer_cout:
        cout_euros = action.get("cout_euros", 0) or 0
        cout_tokens = action.get("cout_tokens", 0) or 0

        budget_apres = budget - cout_euros
        tokens_apres = tokens - cout_tokens

        # Sécurités (éviter les valeurs négatives absurdes)
        if budget_apres < 0:
            budget_apres = budget_apres  # tu peux gérer les dettes ailleurs
        if tokens_apres < 0:
            tokens_apres = 0

        budget = budget_apres
        tokens = tokens_apres

        if debug:
            print(f"  - Coût € : -{cout_euros} → budget = {budget}")
            print(f"  - Coût tokens : -{cout_tokens} → tokens = {tokens}")

    # 2) Récompense tokens
    if appliquer_tokens:
        reward_tokens = action.get("reward_tokens", 0) or 0
        if reward_tokens:
            tokens += reward_tokens
            if debug:
                print(f"  - Récompense tokens : +{reward_tokens} → tokens = {tokens}")

    # 3) XP + recalcul niveau
    if appliquer_xp:
        gain_xp = action.get("gain_xp", 0) or 0
        xp_club += gain_xp

        if xp_par_niveau and xp_par_niveau > 0:
            nouveau_niveau = xp_club // xp_par_niveau
            # On s'assure de ne pas baisser le niveau
            if nouveau_niveau > niveau_global_jeu:
                niveau_global_jeu = int(nouveau_niveau)

        if debug:
            print(f"  - Gain XP : +{gain_xp} → XP_CLUB = {xp_club}")
            print(f"  - Niveau global jeu = {niveau_global_jeu}")

    return budget, tokens, xp_club, niveau_global_jeu





