        def dessiner_trophees_ecran():
            """
            Affiche une vitrine simple :
            - Coupe PO si champion
            - Médaille argent PO si finaliste
            - Compteurs de médailles de tournois (or/argent) avec petites icônes
            """
            global SCROLL_X_TROPHEES, SCROLL_X_MIN, SCROLL_X_MAX, SCROLL_STEP
            SCROLL_X_MIN = 0

            SAISON_MULTI_SPACING = 110  # espacement horizontal entre coupes (multi-saisons)

            # --- Fond de la salle (v1 jusqu'à S5, v2 à partir de S6) ---
            FENETRE.blit(_trophy_bg_surface(), (0, 0))

            # Taille affichée d'un trophée après scale v1/v2 (pour centrer/espacer correctement)
            def _trophy_scaled_size(img, kind="medal"):
                layout = _TROPHY_LAYOUTS[_trophy_layout_mode()]
                sc = layout["medal_scale"] if kind == "medal" else layout["cup_scale"]
                return (int(img.get_width() * sc), int(img.get_height() * sc))


            # Titres
            titre = POLICE_TITRE.render("Salle des trophées", True, BLANC)
            FENETRE.blit(titre, (LARGEUR//2 - titre.get_width()//2, 20))
            saison_dict = TROPHIES.setdefault("saison", {})
            # Libelle S-1 stocké une seule fois si absent
            _cur = int(globals().get('saison_courante', globals().get('numero_saison', 1)))
            saison_dict.setdefault("saison_po_label", max(1, _cur - 1))
            # Libellé de saison : priorise la saison stockée au moment du trophée
            _s_label = saison_dict.get("saison_po_label")
            if _s_label is None:
                # Par défaut, afficher la saison précédente (trophée gagné fin de S, vu en S+1)
                _cur = int(globals().get("numero_saison", 1))
                _s_label = max(1, _cur - 1)
            saison_txt = f"Saison {_s_label}"

            # ✅ Sync de sécurité : si champion, garantir l'entrée multi-saisons (clé correcte)
            try:
                if saison_dict.get("champion_po"):
                    _lst = TROPHIES.setdefault("saisons_championnes", [])
                    _lab = int(_s_label)
                    if _lab not in _lst:
                        _lst.append(_lab)
            except Exception:
                pass
           
            # on se base sur po_bracket["finale"]["vainqueur"] pour forcer l'état local.
            try:
                updated = False
                # 1) Flux TEMP : si la finale est en attente, on fige le trophée (+ label, exclusivité)
                if globals().get('po_final_pending'):
                    vainq = globals().get('po_champion_pending')
                    if vainq == nom_equipe:
                        saison_dict["champion_po"] = True
                        saison_dict["finaliste_po"] = False
                    elif vainq:  # l'autre a gagné => nous finalistes (si on y était)
                        saison_dict["finaliste_po"] = True
                        saison_dict["champion_po"] = False

                    # Étiquette de saison au moment du trophée (raisonnable: S courante)
                    saison_dict.setdefault(
                        "saison_po_label",
                        int(globals().get("saison_actuelle", globals().get("numero_saison", 1)))
                    )

                    # Mémo multi-saisons (ajout non destructif, en int)
                    _lst = TROPHIES.setdefault("saisons_championnes", [])
                    try:
                        _lab = int(saison_dict.get("saison_po_label"))
                        if saison_dict.get("champion_po") and _lab not in _lst:
                            _lst.append(_lab)
                    except Exception:
                        pass

                    try:
                        globals()["po_final_pending"] = False  # consommé (global)
                    except Exception:
                        pass

                    updated = True

                        
                # 2) Fallback "réel" : si rien n'a été fixé, lire le bracket final
                if (not updated) and (not saison_dict.get("champion_po")) and (not saison_dict.get("finaliste_po")):
                    fin = (po_bracket or {}).get("finale", {})  # dict attendu
                    A = fin.get("A"); B = fin.get("B")
                    vainq = fin.get("vainqueur")

                    if vainq:
                        if vainq == nom_equipe:
                            saison_dict["champion_po"] = True
                            saison_dict["finaliste_po"] = False
                            _s = int(globals().get('saison_courante', globals().get('numero_saison', 1)))
                            saison_dict["saison_po_label"] = _s
                            updated = True

                        # ✅ on ne met "finaliste" QUE si on était bien en finale
                        elif nom_equipe in (A, B):
                            saison_dict["finaliste_po"] = True
                            saison_dict["champion_po"] = False
                            _s = int(globals().get('saison_courante', globals().get('numero_saison', 1)))
                            saison_dict["saison_po_label"] = _s
                            updated = True

                        _lst = TROPHIES.setdefault("saisons_championnes", [])
                        if saison_dict["saison_po_label"] not in _lst:
                            _lst.append(saison_dict["saison_po_label"])
            except Exception:
                # silencieux : aucune incidence si des variables n'existent pas encore
                pass

            # --- Normalisation : un champion n'est jamais "finaliste" ---
            try:
                if saison_dict.get("champion_po"):
                    saison_dict["finaliste_po"] = False
            except Exception:
                pass
    
            # ---- Offsets de mise en page (ajuste ces valeurs) ----
            SAISON_CX, SAISON_CY = LARGEUR // 2, 330    # centre de la coupe/médaille Saison/PO - CX/CY = x/y de la Saison 
            TITLE_GAP = 40                              # écart vertical du titre ↕ au-dessus du visuel pour trophées PO

            # (Option) micro-finetuning à la main :
            SAISON_DX, SAISON_DY = -3, -10              # décalage fin de la coupe/médaille Saison (± px) - micro-décalage
            TITLE_DY = 0                                # micro-décalage fin du titre Saison (± px)
  

            # Offsets de mise en page pour l’affichage Tournois (tu peux les mettre avec les autres offsets)
            TOURNOIS_CX          = int(globals().get('TOURNOIS_CX', LARGEUR // 2))  # 2 = centre X de la rangée Tournois
            TOURNOIS_Y           = int(globals().get('TOURNOIS_Y', 150))             # ligne des médailles de Tournois
            TOURNOIS_DY          = int(globals().get('TOURNOIS_DY', 15))             # décalage fin du bloc Tournois (± px)
            TOURNOIS_SPACING     = int(globals().get('TOURNOIS_SPACING', 4))         # intra-saison
            TOURNOIS_SEASON_GAP  = int(globals().get('TOURNOIS_SEASON_GAP', 70))     # inter-saisons
            TOURNOIS_LABEL_GAP   = int(globals().get('TOURNOIS_LABEL_GAP', 3))       # écrat entre médailles et libellé "Saison N"

            

            # --- Ajustements de mise en page v2 (ne changent rien en v1) ---
            _layout = _TROPHY_LAYOUTS[_trophy_layout_mode()]
            SAISON_CY += _layout.get("po_block_dy", 0)              # bloc PO (coupes)
            MEDAL_CUP_GAP = _layout.get("medal_cup_extra_gap", 0)   # Écart supplémentaire entre Tournois et PO
            SAISON_CY += MEDAL_CUP_GAP
            
            total_w_cups = 0
            total_w_medals = 0


            # Section Saison (PO) — gère multi-saisons (plusieurs coupes) ou fallback actuel
            _src_coupe = coupe_icon_img if ('coupe_icon_img' in globals() and coupe_icon_img) else coupe_img
            try:
                _multi = sorted({int(x) for x in (TROPHIES.get("saisons_championnes", []) or [])})
            except Exception:
                _multi = []

            if not _multi:
                try:
                    _lab = TROPHIES.get("saison", {}).get("saison_po_label")
                    if _lab is None:
                        # Afficher la saison qui vient de se terminer = S-1
                        _lab = max(1, int(globals().get("saison_courante", globals().get("numero_saison", 1))) - 1)
                    _multi = [int(_lab)]
                except Exception:
                    _multi = []


            if _multi and _src_coupe is not None:
                # Rangée de coupes centrée (prend en compte le scale v2)
                icon_w = _trophy_scaled_size(_src_coupe, "cup")[0]
                icon_h = _trophy_scaled_size(_src_coupe, "cup")[1]
                spacing = SAISON_MULTI_SPACING
                total_w = len(_multi) * icon_w + (len(_multi) - 1) * spacing
                total_w_cups = total_w  # <- mémorise la largeur de la rangée de coupes (scalées)

                start_x = (SAISON_CX + SAISON_DX) - total_w // 2
                if _is_v2() or (total_w > (LARGEUR - 80)):
                    start_x -= SCROLL_X_TROPHEES

                y_center = SAISON_CY + SAISON_DY
                x = start_x
                for _s in _multi:
                    # top-left pour rester centré verticalement malgré le scale
                    tx = x
                    ty = int(y_center - icon_h // 2)
                    _trophy_blit(FENETRE, _src_coupe, tx, ty, kind="cup")

                    # label sous la coupe (utilise la hauteur scalée)
                    lab = POLICE_PETITE.render(f"Saison {int(_s)}", True, BLANC)
                    FENETRE.blit(lab, (tx + icon_w//2 - lab.get_width()//2, ty + icon_h + 6))

                    x += icon_w + spacing

                    # bornes provisoires côté coupes (utile si pas de médailles)
                    contenu_w = total_w_cups
                    visible_w = LARGEUR
                    SCROLL_X_MAX = max(SCROLL_X_MAX, max(0, contenu_w - visible_w + 80))
                    _clamp_scroll()
 
           # Section Tournois — affichage PAR SAISON (blocs Saison N séparés)
            _hist  = TROPHIES.get("tournois_hist", []) or []
            # Regroupe les icônes par saison (s -> [Surface, Surface, ...])
            par_saison = {}
            for e in _hist:
                try:
                    s   = int(e.get("s", 0))
                    if s <= 0:
                        continue  # on ignore les saisons invalides
                    niv = str(e.get("niv","")).lower()
                    res = str(e.get("res","")).lower()
                    if niv.startswith("debut") or "début" in niv:   # Débutant / Tournoi A
                        img = (or_tournoia_small if res == "or" else argent_tournoia_small) if 'or_tournoia_small' in globals() else None
                    elif niv.startswith("inter"):
                        img = (or_tournoii_small if res == "or" else argent_tournoii_small) if 'or_tournoii_small' in globals() else None
                    else:
                        # niveau Elite (si jamais tu l’ajoutes, on peut réutiliser Intermédiaire comme placeholder)
                        img = (or_tournoii_small if res == "or" else argent_tournoii_small) if 'or_tournoii_small' in globals() else None
                    if img:
                        par_saison.setdefault(s, []).append(img)
                except Exception:
                    pass

            if par_saison:
                cx = TOURNOIS_CX
                y_icons = TOURNOIS_Y + TOURNOIS_DY
                y_icons += _layout.get("tournoi_block_dy", 0)   # décalage vertical du bloc "Tournois" uniquement en v2
                spacing_intra = TOURNOIS_SPACING
                spacing_inter = TOURNOIS_SEASON_GAP

                # Titre
                sous_titre2 = POLICE_MOYENNE_BOLD.render("Tournois", True, BLANC)
                FENETRE.blit(sous_titre2, (cx - sous_titre2.get_width()//2, y_icons - 35))

                saisons_ordre = sorted(par_saison.keys())

                def bloc_width(imgs):
                    if not imgs: return 0
                    w = 0
                    for i, im in enumerate(imgs):
                        if _is_v2():
                            w += _trophy_scaled_size(im, "medal")[0]
                        else:
                            w += im.get_width()
                        if i < len(imgs) - 1:
                            w += spacing_intra
                    return w

                total_w = 0
                for idx, s in enumerate(saisons_ordre):
                    total_w += bloc_width(par_saison[s])
                    if idx < len(saisons_ordre) - 1:
                        total_w += spacing_inter

                # Mémorise la largeur de la rangée des médailles
                total_w_medals = total_w  # ← largeur de la rangée médailles calculée juste avant

                # Point de départ : centré, puis on applique le scroll en v2
                start_x = cx - total_w // 2
                if _is_v2():
                    start_x -= SCROLL_X_TROPHEES  # ← scroll horizontal v2

                    # Bornes de scroll sur la base du contenu le plus large (coupes vs médailles)
                    contenu_w = max(total_w_cups, total_w_medals)
                    visible_w = LARGEUR
                    SCROLL_X_MAX = max(0, contenu_w - visible_w + 80)

                    # TEST temporaire : marge minimale (à retirer après tests)
                    SCROLL_X_MAX = max(SCROLL_X_MAX, 300)

                    _clamp_scroll()

                try:
                    _ = total_w_cups
                except NameError:
                    total_w_cups = total_w_medals

                def _has_trophy_overflow():
                    # petite marge pour les labels
                    return max(total_w_cups, total_w_medals) > (LARGEUR - 80)

                # Point de départ centré
                start_x = cx - total_w // 2

                # ⚠️ Remplace ton ancien `if _is_v2():` par la condition élargie ci-dessous
                if _is_v2() or _has_trophy_overflow():
                    start_x -= SCROLL_X_TROPHEES  # scroll horizontal

                    # bornes + clamp (réutilise tes variables globales)
                    contenu_w = max(total_w_cups, total_w_medals)
                    visible_w = LARGEUR
                    SCROLL_X_MAX = max(0, contenu_w - visible_w + 80)

                    # (option test) marge mini — tu peux retirer après tests
                    if globals().get('DEBUG_TROPHEES_SCROLL'):
                        SCROLL_X_MAX = max(SCROLL_X_MAX, 300)


                    _clamp_scroll()

                # --- Dessin du contenu (toutes les saisons) ---
                x = start_x
                for si, s in enumerate(saisons_ordre):
                    imgs = par_saison[s]
                    if not imgs:
                        continue

                    bw = bloc_width(imgs)  # largeur du bloc (images + espacements intra)
                    xx = x
                    for i, im in enumerate(imgs):
                        sw, sh = (_trophy_scaled_size(im, "medal") if _is_v2()
                                  else (im.get_width(), im.get_height()))
                        _trophy_blit(FENETRE, im, xx, y_icons, kind="medal")
                        xx += sw
                        if i < len(imgs) - 1:
                            xx += spacing_intra

                    # Légende "Saison s" centrée sous le bloc
                    cap = POLICE_PETITE.render(f"Saison {s}", True, BLANC)
                    cap_x = x + (bw // 2) - (cap.get_width() // 2)
                    first_h = (_trophy_scaled_size(imgs[0], "medal")[1] if (_is_v2() and imgs) 
                               else (imgs[0].get_height() if imgs else 90))
                    cap_y = y_icons + first_h + TOURNOIS_LABEL_GAP
                    FENETRE.blit(cap, (cap_x, cap_y))

