                                pr = globals().get('finance_archive_popup_rect')
                                if pr is None:
                                    w, h = 760, 480
                                    L = int(globals().get("LARGEUR", 1280))
                                    H = int(globals().get("HAUTEUR", 720))
                                    x = (L - w) // 2
                                    y = (H - h) // 2
                                    pr = pygame.Rect(x, y, w, h)
                                    globals()['finance_archive_popup_rect'] = pr

                                if path and os.path.exists(path):
                                    raw = pygame.image.load(path).convert()
                                    header_h = 40
                                    inner_w = pr.w - 32
                                    inner_h = pr.h - header_h - 32

                                    rw, rh = raw.get_width(), raw.get_height()
                                    k = min(inner_w / max(1, rw), inner_h / max(1, rh))
                                    new_w, new_h = int(rw * k), int(rh * k)

                                    scaled = pygame.transform.smoothscale(raw, (new_w, new_h))
                                    globals()['finance_archive_popup_surface'] = scaled
                                else:
                                    globals()['finance_archive_popup_surface'] = None
                                        
